    def create_settings_tab(self):
        """Create the Settings tab with vertical sidebar navigation"""
        from PyQt6.QtWidgets import QScrollArea
        from modules.settings_sidebar import SettingsSidebar

        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(0)

        # Create sidebar navigation (replaces horizontal QTabWidget)
        settings_tabs = SettingsSidebar()
        self.settings_tabs = settings_tabs  # Store for reference
        set_help_topic(tab, HelpTopics.SETTINGS_GENERAL)

        # Scroll area wrapper for each tab (for long content)
        scroll_area_wrapper = lambda widget: self._wrap_in_scroll(widget)

        # ===== TAB 1: General Settings =====
        general_tab = self._create_general_settings_tab()
        settings_tabs.addTab(scroll_area_wrapper(general_tab), "⚙️ General")

        # ===== TAB 2: User Identity =====
        identity_tab = self._create_user_identity_tab()
        settings_tabs.addTab(scroll_area_wrapper(identity_tab), "👤 User Identity")

        # ===== TAB 3: AI Settings (LLM, Ollama) =====
        ai_tab = self._create_ai_settings_tab()
        ai_scroll = scroll_area_wrapper(ai_tab)
        settings_tabs.addTab(ai_scroll, "🤖 AI Settings")
        self.ai_settings_scroll = ai_scroll  # Store reference for scrolling to API keys

        # ===== TAB: Voice (commands & dictation, lives in Sidekick) =====
        voice_tab = self._create_voice_settings_tab()
        settings_tabs.addTab(scroll_area_wrapper(voice_tab), "🎤 Voice")

        # ===== TAB 3: Language Pair Settings =====
        lang_tab = self._create_language_pair_tab()
        settings_tabs.addTab(scroll_area_wrapper(lang_tab), "🌐 Language Pair")

        # ===== TAB 4: MT Settings =====
        mt_tab = self._create_mt_settings_tab()
        settings_tabs.addTab(scroll_area_wrapper(mt_tab), "🌐 MT Settings")

        # ===== TAB 5: QuickTrans Settings =====
        # Prior to v1.10.10 this was a stub pointing users to
        # Sidekick → SuperLookup → SuperLookup Settings → QuickTrans
        # (a sub-sub-tab Sidekick mounted via the is_sidekick=True
        # branch on SuperlookupTab). With Sidekick retired the real
        # QuickTrans settings widget now lives directly here, where
        # users would have looked for it in the first place.
        mt_quick_tab = self._create_mt_quick_lookup_settings_tab()
        settings_tabs.addTab(scroll_area_wrapper(mt_quick_tab), "⚡ QuickTrans")
        self.mt_quick_lookup_tab_index = settings_tabs.count() - 1  # Store index for opening

        # ===== TAB 6: View Settings =====
        view_tab = self._create_view_settings_tab()
        settings_tabs.addTab(scroll_area_wrapper(view_tab), "🔍 View Settings")

        # ===== TAB 7: System Prompts (Layer 1) =====
        system_prompts_tab = self._create_system_prompts_tab()
        settings_tabs.addTab(scroll_area_wrapper(system_prompts_tab), "📝 System Prompts")

        # ===== TAB 8: Debug Settings =====
        debug_tab = self._create_debug_settings_tab()
        settings_tabs.addTab(scroll_area_wrapper(debug_tab), "🐛 Debug")

        # The "📦 Features" tab was retired in v1.9.474. The Workbench used
        # to ship feature modules (voice, web, pdf, mt, hunspell, …) as
        # optional pip extras and exposed an install-status panel here. All
        # of those packages are now part of the core dependency set, so the
        # tab no longer had any toggles to offer – everything is always
        # installed and ready. The pyproject [project.optional-dependencies]
        # section is also gone; ``pip install supervertaler`` gives you the
        # full surface area in one step.

        # ===== TAB 9: Domain Detection Keywords =====
        domain_keywords_tab = self._create_domain_keywords_tab()
        settings_tabs.addTab(scroll_area_wrapper(domain_keywords_tab), "🎯 Domain Detection")

        # ===== TAB 11: Segmentation Rules =====
        seg_tab = self.create_segmentation_rules_tab()
        settings_tabs.addTab(scroll_area_wrapper(seg_tab), "📏 Segmentation Rules")

        # ===== TAB 12: Keyboard Shortcuts =====
        from modules.keyboard_shortcuts_widget import KeyboardShortcutsWidget
        shortcuts_tab = KeyboardShortcutsWidget(self)
        settings_tabs.addTab(shortcuts_tab, "⌨️ Keyboard Shortcuts")
        # Index stored so the Voice tab's "Change in Settings → Keyboard
        # Shortcuts" link can jump straight here.
        self.keyboard_shortcuts_tab_index = settings_tabs.count() - 1

        # ===== TAB 13: Log (moved from main tabs) =====
        log_tab = self.create_log_tab()
        settings_tabs.addTab(log_tab, "📋 Log")

        layout.addWidget(settings_tabs)

        # Apply saved UI font scale on startup
        saved_scale = self._get_global_ui_font_scale()
        if saved_scale != 100:
            # Defer application to ensure widgets are fully created
            from PyQt6.QtCore import QTimer
            QTimer.singleShot(100, lambda: self._apply_global_ui_font_scale(saved_scale))

        # Apply saved Compact UI chrome preference on startup.
        # Defaults to compact (v1.9.386+); use 0ms timer so it lands in the same event
        # loop iteration the widgets were constructed in – no visible flash of
        # non-compact chrome before the restyle.
        if self._get_ui_chrome_compact():
            from PyQt6.QtCore import QTimer
            QTimer.singleShot(0, lambda: self._apply_ui_chrome_compactness(True, persist=False))

        # Apply dark sidebar style if current theme is dark
        self._update_settings_sidebar_theme()

        return tab
    
    # Fixed content width for every settings tab. Content is left-anchored
    # against the sidebar; anything past this width sits as breathing room
    # on the right. 1000 px is roughly the content area of the Trados
    # Studio Options dialog and keeps label–control rows comfortable
    # without feeling oversized on wide monitors.
    SETTINGS_CONTENT_MAX_WIDTH = 1000

    def _wrap_in_scroll(self, widget):
        """Wrap a settings-tab widget in a scroll area with consistent layout.

        Three things in one place so every settings tab gets them for free:

        1. **Wheel guard** – prevents hovered sliders / spinboxes / combo
           boxes from silently absorbing mouse-wheel events meant for the
           scroll area. See ``_WheelGuard``.
        2. **Left-anchor + max-width cap** – wraps ``widget`` in a horizontal
           layout with the content on the left and a stretch on the right,
           capped at ``SETTINGS_CONTENT_MAX_WIDTH`` px. Stops settings rows
           from sprawling across ultra-wide monitors while avoiding the
           "centred in a sea of grey" look that bare centring produces.
        3. **Scroll area** – the obvious one.
        """
        from PyQt6.QtWidgets import QSlider, QAbstractSpinBox, QComboBox

        # Left-anchor + width cap. Skip if the caller already wrapped its
        # own content (legacy: AI Settings used to do this inline). We
        # detect that by checking whether `widget` itself already has a
        # QHBoxLayout with a stretch – a heuristic that's good enough for
        # the small number of legacy callers.
        host = widget
        if not getattr(widget, '_settings_left_anchored', False):
            host = QWidget()
            outer = QHBoxLayout(host)
            outer.setContentsMargins(0, 0, 0, 0)
            outer.setSpacing(0)
            # Pin both min and max to the same width so every tab claims
            # exactly the same column regardless of how wide its longest
            # internal row would naturally make it. Without the min, a tab
            # with short rows would sit narrower than its neighbours, and
            # clicking between tabs would feel jumpy.
            widget.setMinimumWidth(self.SETTINGS_CONTENT_MAX_WIDTH)
            widget.setMaximumWidth(self.SETTINGS_CONTENT_MAX_WIDTH)
            outer.addWidget(widget, 0)
            outer.addStretch(1)

        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        scroll.setWidget(host)
        scroll.setStyleSheet("QScrollArea { border: none; }")

        # Wheel guard: one instance per scroll area, attached so it's not GC'd.
        if not hasattr(self, '_settings_wheel_guards'):
            self._settings_wheel_guards = []
        guard = _WheelGuard(scroll)
        self._settings_wheel_guards.append(guard)
        for cls in (QSlider, QAbstractSpinBox, QComboBox):
            for w in widget.findChildren(cls):
                w.installEventFilter(guard)
                # Demote WheelFocus → StrongFocus so wheel doesn't take focus.
                w.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
        return scroll

    def _update_settings_sidebar_theme(self):
        """Update the settings sidebar styling based on the current theme."""
        if not hasattr(self, 'settings_tabs'):
            return
        from modules.settings_sidebar import SettingsSidebar
        if not isinstance(self.settings_tabs, SettingsSidebar):
            return
        is_dark = (hasattr(self, 'theme_manager') and self.theme_manager
                   and 'dark' in self.theme_manager.current_theme.name.lower())
        if is_dark:
            self.settings_tabs.apply_dark_style()
        else:
            self.settings_tabs._apply_style()

    def _update_tools_sidebar_theme(self):
        """Update the tools sidebar styling based on the current theme."""
        if not hasattr(self, 'modules_tabs'):
            return
        from modules.settings_sidebar import SettingsSidebar
        if not isinstance(self.modules_tabs, SettingsSidebar):
            return
        is_dark = (hasattr(self, 'theme_manager') and self.theme_manager
                   and 'dark' in self.theme_manager.current_theme.name.lower())
        if is_dark:
            self.modules_tabs.apply_dark_style()
        else:
            self.modules_tabs._apply_style()

