    def _populate_voice_commands_table(self):
        """Refresh the Voice command table in Sidekick (if open).

        Called whenever the underlying voice_command_manager has changed
        (commands added, edited, removed, or reset).
        """
        if not hasattr(self, 'voice_command_manager'):
            return
        # Refresh the in-Workbench Voice top tab's command table if
        # it's been built (it's lazy-constructed on first activation).
        # Pre-v1.10.4 this also refreshed Sidekick's voice tab; with
        # Sidekick retired only the top tab needs poking.
        voice_widget = getattr(self, '_voice_top_widget', None)
        if voice_widget is not None and hasattr(voice_widget, '_populate_table'):
            try:
                voice_widget._populate_table()
            except Exception:
                pass

    def _reset_voice_commands(self):
        """Reset voice commands to defaults"""
        reply = QMessageBox.question(
            self, "Reset Commands",
            "Reset all voice commands to defaults?\n\nThis will remove any custom commands you've added.",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
        )
        
        if reply == QMessageBox.StandardButton.Yes:
            self.voice_command_manager.commands = self.voice_command_manager.DEFAULT_COMMANDS.copy()
            self.voice_command_manager.save_commands()
            self._populate_voice_commands_table()
            QMessageBox.information(self, "Reset Complete", "Voice commands have been reset to defaults.")

    def _check_ahk_installed(self) -> str:
        """Check if AutoHotkey is installed"""
        ahk_exe = self.voice_command_manager._find_ahk_executable() if hasattr(self, 'voice_command_manager') else None
        if ahk_exe:
            return "✅ AutoHotkey detected"
        else:
            return "⚠️ AutoHotkey not found - install from autohotkey.com for system commands"

    def _open_voice_scripts_folder(self):
        """Open the voice scripts folder"""
        import subprocess
        scripts_folder = self.user_data_path / "workbench" / "voice_scripts"
        scripts_folder.mkdir(parents=True, exist_ok=True)
        subprocess.Popen(['explorer', str(scripts_folder)])

    def _toggle_alwayson_listening(self):
        """Toggle always-on voice listening mode"""
        if self.voice_listener and self.voice_listener.is_listening:
            # Stop listening
            self.voice_listener.stop()
            self.voice_listener = None
            self._update_alwayson_ui("stopped")
            self.log("🔇 Always-on listening stopped")
            self.status_bar.showMessage("🔇 Always-on listening stopped", 3000)
        else:
            # Start listening
            try:
                dictation_settings = self.load_dictation_settings()
                model_name = dictation_settings.get('model', 'base')
                
                # Recognition engine setting. Legacy 'local' maps to
                # 'faster_whisper' for users upgrading from pre-Vosk versions.
                engine = dictation_settings.get('recognition_engine', 'vosk')
                if engine == 'local':
                    engine = 'faster_whisper'

                # If using API, check if we have an OpenAI key. If not,
                # fall back to Vosk (the new safe default) rather than
                # forcing the user into a dialog about installing extras.
                api_key = None
                if engine == 'api':
                    api_keys = self.load_api_keys()
                    api_key = api_keys.get('openai') or api_keys.get('openai_api_key')
                    if not api_key:
                        QMessageBox.warning(
                            self, "OpenAI API Key Required",
                            "To use OpenAI Whisper API, please set your OpenAI API key in:\n\n"
                            "Settings → AI Settings → OpenAI API Key\n\n"
                            "Falling back to Vosk (offline, free, commands-only)."
                        )
                        engine = 'vosk'
                
                # Get language setting
                lang_setting = dictation_settings.get('language', 'Auto (use project target language)')
                if lang_setting.startswith('Auto'):
                    target_lang = self.current_project.target_lang if self.current_project else 'en'
                    lang_map = {
                        'nl': 'nl', 'nl_NL': 'nl', 'nl_BE': 'nl',
                        'en': 'en', 'en_US': 'en', 'en_GB': 'en',
                        'de': 'de', 'de_DE': 'de',
                        'fr': 'fr', 'fr_FR': 'fr',
                        'es': 'es', 'es_ES': 'es',
                    }
                    lang_code = lang_map.get(target_lang, 'auto')
                else:
                    lang_code = lang_setting.lower()[:2]
                
                # Create listener. user_data_path is needed by the Vosk
                # engine to locate / download the Vosk model on demand.
                # initial_prompt + replacements bias the Whisper
                # decoder toward known brand / technical vocabulary so
                # "Supervertaler" stops being heard as "Supervertile"
                # etc. Built fresh from current settings + (optionally)
                # the active project's termbase – see
                # build_voice_initial_prompt() and
                # load_voice_vocabulary_settings(). Vosk ignores both
                # (it runs in grammar mode with a fixed phrase list).
                vocab_settings = self.load_voice_vocabulary_settings()
                self.voice_listener = ContinuousVoiceListener(
                    command_manager=self.voice_command_manager,
                    model_name=model_name,
                    language=lang_code,
                    engine=engine,
                    api_key=api_key,
                    user_data_path=str(self.user_data_path) if hasattr(self, 'user_data_path') else None,
                    mic_device=dictation_settings.get('mic_device'),
                    initial_prompt=self.build_voice_initial_prompt(),
                    replacements=vocab_settings.get('replacements', []),
                )
                
                # Set sensitivity from persisted settings (the Voice tab
                # writes this key directly via _set_dictation_keys).
                sensitivity = dictation_settings.get('alwayson_sensitivity', 'medium')
                if sensitivity in ('low', 'medium', 'high'):
                    self.voice_listener.set_sensitivity(sensitivity)
                
                # Connect signals
                self.voice_listener.speech_detected.connect(self._on_alwayson_speech)
                self.voice_listener.command_detected.connect(self._on_alwayson_command)
                self.voice_listener.text_for_dictation.connect(self._on_alwayson_dictation)
                self.voice_listener.status_update.connect(self._on_alwayson_status)
                self.voice_listener.error_occurred.connect(self._on_alwayson_error)
                self.voice_listener.vad_status_changed.connect(self._on_alwayson_vad_status)
                self.voice_listener.listening_started.connect(lambda: self._update_alwayson_ui("listening"))
                self.voice_listener.listening_stopped.connect(lambda: self._update_alwayson_ui("stopped"))
                
                # Log which engine we're using
                if engine == 'api':
                    self.log("🎧 Always-on listening started (OpenAI API – fast & accurate)")
                elif engine == 'vosk':
                    self.log("🎧 Always-on listening started (Vosk – offline, commands-only)")
                else:
                    self.log(f"🎧 Always-on listening started (faster-whisper '{model_name}')")
                
                # Start
                self.voice_listener.start()
                self.log("🎧 Always-on listening started")
                
            except Exception as e:
                import traceback
                self.log(f"❌ Failed to start always-on listening: {e}")
                self.log(traceback.format_exc())
                QMessageBox.critical(self, "Always-On Error", f"Failed to start always-on listening:\n\n{e}")

    def _update_alwayson_ui(self, status: str):
        """Update the always-on UI elements"""
        # Update settings panel UI (if visible)
        if hasattr(self, 'alwayson_status_label'):
            if status == "listening" or status == "waiting":
                self.alwayson_status_label.setText("🟢 Listening for speech...")
                self.alwayson_status_label.setStyleSheet("font-size: 9pt; padding: 5px; color: #2E7D32;")
                self.alwayson_toggle_btn.setText("⏹️ Stop Always-On Listening")
                self.alwayson_toggle_btn.setStyleSheet("padding: 8px 15px; background-color: #FFCDD2;")
            elif status == "recording":
                self.alwayson_status_label.setText("🔴 Recording...")
                self.alwayson_status_label.setStyleSheet("font-size: 9pt; padding: 5px; color: #C62828;")
            elif status == "processing":
                self.alwayson_status_label.setText("⏳ Processing...")
                self.alwayson_status_label.setStyleSheet("font-size: 9pt; padding: 5px; color: #F57C00;")
            else:  # stopped or other
                self.alwayson_status_label.setText("⚪ Not active")
                self.alwayson_status_label.setStyleSheet("font-size: 9pt; padding: 5px;")
                self.alwayson_toggle_btn.setText("▶️ Start Always-On Listening")
                self.alwayson_toggle_btn.setStyleSheet("padding: 8px 15px;")
        
        # Update status bar indicator (always visible when active)
        if hasattr(self, 'alwayson_indicator_label'):
            if status == "listening" or status == "waiting":
                self.alwayson_indicator_label.setText("🎤 ALWAYS-ON")
                self.alwayson_indicator_label.setStyleSheet("font-size: 11px; font-weight: bold; color: #2E7D32; background-color: #C8E6C9; padding: 2px 6px; border-radius: 3px;")
                self.alwayson_indicator_label.setToolTip("Always-on voice listening ACTIVE\nClick to stop")
                self.alwayson_indicator_label.show()
            elif status == "recording":
                self.alwayson_indicator_label.setText("🔴 REC")
                self.alwayson_indicator_label.setStyleSheet("font-size: 11px; font-weight: bold; color: white; background-color: #C62828; padding: 2px 6px; border-radius: 3px;")
                self.alwayson_indicator_label.setToolTip("Recording speech...")
                self.alwayson_indicator_label.show()
            elif status == "processing":
                self.alwayson_indicator_label.setText("⏳ ...")
                self.alwayson_indicator_label.setStyleSheet("font-size: 11px; font-weight: bold; color: #F57C00; background-color: #FFF3E0; padding: 2px 6px; border-radius: 3px;")
                self.alwayson_indicator_label.setToolTip("Processing speech...")
                self.alwayson_indicator_label.show()
            else:  # stopped or other
                self.alwayson_indicator_label.hide()
        
        # Update grid toolbar button (if exists)
        if hasattr(self, 'grid_alwayson_btn'):
            if status == "listening" or status == "waiting":
                self.grid_alwayson_btn.setText("🎧 Always-On: ON")
                self.grid_alwayson_btn.setChecked(True)
                self.grid_alwayson_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #2E7D32;
                        color: white;
                        font-weight: bold;
                        padding: 3px 5px;
                        border-radius: 3px;
                    }
                    QPushButton:checked {
                        background-color: #2E7D32;
                    }
                """)
            elif status == "recording":
                self.grid_alwayson_btn.setText("🔴 REC")
                self.grid_alwayson_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #C62828;
                        color: white;
                        font-weight: bold;
                        padding: 3px 5px;
                        border-radius: 3px;
                    }
                    QPushButton:checked {
                        background-color: #C62828;
                    }
                """)
            elif status == "processing":
                self.grid_alwayson_btn.setText("⏳ ...")
                self.grid_alwayson_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #F57C00;
                        color: white;
                        font-weight: bold;
                        padding: 3px 5px;
                        border-radius: 3px;
                    }
                    QPushButton:checked {
                        background-color: #F57C00;
                    }
                """)
            else:  # stopped or other
                self.grid_alwayson_btn.setText("🎧 Always-On: OFF")
                self.grid_alwayson_btn.setChecked(False)
                self.grid_alwayson_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #757575;
                        color: white;
                        font-weight: bold;
                        padding: 3px 5px;
                        border-radius: 3px;
                    }
                    QPushButton:checked {
                        background-color: #2E7D32;
                    }
                """)

        # Update the in-Workbench Voice top tab's status indicator if
        # it has been built (lazy on first activation). Pre-v1.10.4
        # this also poked Sidekick's voice widget; Sidekick is gone.
        voice_widget = getattr(self, '_voice_top_widget', None)
        if voice_widget is not None and hasattr(voice_widget, 'set_alwayson_status'):
            try:
                voice_widget.set_alwayson_status(status)
            except Exception:
                pass

        # System tray icon – visible only while Always-On is active.
        # Gives the user a persistent "the mic is hot" signal even when
        # Workbench is hidden.
        self._update_alwayson_tray_icon(status)

    @staticmethod
    def _draw_mic_icon(color):
        """Draw a small microphone glyph as a QIcon, in the given QColor.

        Used by the Always-On tray indicator. Two visual states share the
        same shape but differ in colour: grey when Always-On is off, red
        when it's actively listening. Drawing programmatically avoids
        bundling an extra asset and keeps colour-swaps trivial.
        """
        from PyQt6.QtGui import QIcon, QPixmap, QPainter, QColor, QPen, QBrush
        size = 32
        pix = QPixmap(size, size)
        pix.fill(QColor(0, 0, 0, 0))
        p = QPainter(pix)
        try:
            p.setRenderHint(QPainter.RenderHint.Antialiasing)
            qcol = QColor(color) if not isinstance(color, QColor) else color
            stroke = max(1.5, size * 0.06)

            # Mic body – vertical capsule centred horizontally
            body_w = size * 0.42
            body_h = size * 0.50
            body_x = (size - body_w) / 2
            body_y = size * 0.10
            p.setBrush(QBrush(qcol))
            p.setPen(Qt.PenStyle.NoPen)
            p.drawRoundedRect(
                int(body_x), int(body_y), int(body_w), int(body_h),
                int(body_w / 2), int(body_w / 2),
            )

            # U-shaped pickup arc cradling the body
            p.setBrush(Qt.BrushStyle.NoBrush)
            p.setPen(QPen(qcol, stroke, Qt.PenStyle.SolidLine,
                          Qt.PenCapStyle.RoundCap))
            arc_x = size * 0.16
            arc_y = size * 0.30
            arc_w = size * 0.68
            arc_h = size * 0.50
            # Qt uses 1/16ths of a degree; 0° is at 3 o'clock, going CCW.
            p.drawArc(int(arc_x), int(arc_y), int(arc_w), int(arc_h),
                      200 * 16, 140 * 16)

            # Stand (vertical) + base (horizontal)
            cx = size / 2
            p.drawLine(int(cx), int(size * 0.80), int(cx), int(size * 0.90))
            p.drawLine(int(cx - size * 0.18), int(size * 0.90),
                       int(cx + size * 0.18), int(size * 0.90))
        finally:
            p.end()
        return QIcon(pix)

    def _ensure_alwayson_tray_icon(self):
        """Lazily create the QSystemTrayIcon used as a global Always-On
        toggle and visual state indicator.

        A small microphone glyph drawn programmatically – grey when
        Always-On is off, red when actively listening. Convention follows
        OBS / Zoom / Discord (grey = ready/off, red = live).

        The icon is created once and stays visible for the lifetime of
        the Workbench window. Showing/hiding a tray slot causes Windows
        to reflow the tray (the "icons bounce" effect), so the slot
        stays allocated and only the pixmap, tooltip, and menu wording
        change as state changes.

        Single-click toggles Always-On. Right-click shows a small menu
        with the same toggle plus an "Open Voice in Sidekick"
        shortcut.
        """
        if hasattr(self, '_alwayson_tray_icon'):
            return
        from PyQt6.QtWidgets import QSystemTrayIcon, QMenu
        from PyQt6.QtGui import QColor

        if not QSystemTrayIcon.isSystemTrayAvailable():
            self._alwayson_tray_icon = None
            return

        # Material grey 600 (off) and red 800 (live).
        self._alwayson_tray_icon_normal = self._draw_mic_icon(QColor(0x75, 0x75, 0x75))
        self._alwayson_tray_icon_red = self._draw_mic_icon(QColor(0xC6, 0x28, 0x28))

        tray = QSystemTrayIcon(self._alwayson_tray_icon_normal, self)
        tray.setToolTip("Voice – Always-On is OFF. Click to start.")

        menu = QMenu(self)
        toggle_action = menu.addAction("▶ Start Always-On")
        toggle_action.triggered.connect(self._toggle_alwayson_listening)
        menu.addSeparator()
        open_action = menu.addAction("🎤 Open Voice")
        open_action.triggered.connect(self._open_voice_in_workbench)
        tray.setContextMenu(menu)
        self._alwayson_tray_toggle_action = toggle_action

        tray.activated.connect(self._on_alwayson_tray_activated)
        self._alwayson_tray_icon = tray
        tray.show()

    def _on_alwayson_tray_activated(self, reason):
        """Tray-icon click handler – single-click toggles Always-On."""
        from PyQt6.QtWidgets import QSystemTrayIcon
        if reason == QSystemTrayIcon.ActivationReason.Trigger:
            self._toggle_alwayson_listening()

    def _update_alwayson_tray_icon(self, status: str):
        """Switch the tray icon between inactive/active visuals based on
        the current listener status. The icon stays visible at all times
        – only the pixmap, tooltip, and menu wording change."""
        self._ensure_alwayson_tray_icon()
        tray = getattr(self, '_alwayson_tray_icon', None)
        if tray is None:
            return

        active = status in ("listening", "waiting", "recording", "processing")

        # Skip every tray API call when the active/inactive state hasn't changed.
        # setIcon() and setToolTip() both trigger a Windows notification-area
        # repaint that briefly hides the icon. The VAD cycle emits three status
        # changes per spoken command (recording → processing → listening), all of
        # which map to the same "active" state, so we can safely ignore them.
        if getattr(self, '_alwayson_tray_active', None) == active:
            return
        self._alwayson_tray_active = active

        tray.setIcon(
            self._alwayson_tray_icon_red if active
            else self._alwayson_tray_icon_normal
        )
        tray.setToolTip(
            "Voice – Always-On listening. Click to stop." if active
            else "Voice – Always-On is OFF. Click to start."
        )
        action = getattr(self, '_alwayson_tray_toggle_action', None)
        if action is not None:
            action.setText("⏹ Stop Always-On" if active else "▶ Start Always-On")

    def _on_alwayson_speech(self, text: str):
        """Handle raw speech from always-on listener"""
        self.log(f"🎤 Heard: {text}")

    def _on_alwayson_command(self, phrase: str, result: str):
        """Handle command execution from always-on listener"""
        self.log(f"🎤 Command: {phrase} → {result}")
        self.status_bar.showMessage(f"🎤 {result}", 3000)

    def _on_alwayson_dictation(self, text: str):
        """Handle dictation text from always-on listener (no command matched).

        Routes through the shared cross-app helper so Always-On, F9
        push-to-talk, and the Voice global hotkey all behave the same
        way regardless of which app has focus.

        Skipped entirely when the user has set Always-On to commands-only
        mode (Voice tab → "Listen for commands only"). In that mode
        unmatched speech is logged but not typed – dictation is reserved
        for the explicit push-to-talk path (hold the dictation hotkey).
        """
        try:
            settings = self.load_dictation_settings()
            if settings.get('alwayson_commands_only', False):
                self.log(f"💬 Heard (commands-only mode, not dictated): {text}")
                return
        except Exception:
            pass
        self._insert_dictated_text(text)

    def _on_alwayson_status(self, message: str):
        """Handle status updates from always-on listener"""
        self.log(message)
        if hasattr(self, 'alwayson_status_label'):
            # Keep status label updated but don't override state-based status
            pass

    def _on_alwayson_error(self, error: str):
        """Handle errors from always-on listener"""
        self.log(f"❌ Always-on error: {error}")
        QMessageBox.warning(self, "Always-On Error", f"Voice listener error:\n\n{error}")

    def _on_alwayson_vad_status(self, status: str):
        """Handle VAD status changes (waiting/recording/processing)"""
        self._update_alwayson_ui(status)

    def _toggle_alwayson_from_statusbar(self):
        """Toggle always-on listening when clicking the status bar indicator"""
        self._toggle_alwayson_listening()

    def _toggle_alwayson_from_grid_btn(self, checked: bool, btn: QPushButton):
        """Toggle always-on listening from the grid toolbar button"""
        self._toggle_alwayson_listening()
        # Button state will be updated by _update_alwayson_ui

    def _create_system_prompts_tab(self):
        """Create System Prompts (Layer 1) Settings tab content"""
        from PyQt6.QtWidgets import QGroupBox, QPushButton, QTextEdit, QComboBox

        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(20, 20, 20, 20)
        layout.setSpacing(15)

        # Header info
        header_group = QGroupBox("📝 System Prompts (Layer 1)")
        header_layout = QVBoxLayout()

        info_label = QLabel(
            "<b>System Prompts are the foundation of Supervertaler's 2-Layer Prompt Architecture.</b><br><br>"
            "These prompts are <b>always applied</b> and contain critical infrastructure instructions:<br>"
            "• CAT tool tag preservation (memoQ, Trados, CafeTran)<br>"
            "• Formatting rules and output standards<br>"
            "• Language-specific conventions (numbers, dates, typography)<br>"
            "• Professional translation context<br><br>"
            "<i>Layer 2 (Custom Prompts) are managed in the Prompts tab and can be freely attached/detached.</i>"
        )
        info_label.setTextFormat(Qt.TextFormat.RichText)
        info_label.setWordWrap(True)
        info_label.setStyleSheet("font-size: 9pt; padding: 12px; border-radius: 3px;")
        header_layout.addWidget(info_label)

        header_group.setLayout(header_layout)
        layout.addWidget(header_group)

        # Mode selector
        mode_group = QGroupBox("🎯 Select System Prompt Mode")
        mode_layout = QVBoxLayout()

        mode_info = QLabel(
            "Supervertaler uses different system prompts for different translation modes:"
        )
        mode_info.setStyleSheet("font-size: 9pt; color: #666; padding: 8px;")
        mode_info.setWordWrap(True)
        mode_layout.addWidget(mode_info)

        mode_selector_layout = QHBoxLayout()
        mode_selector_layout.addWidget(QLabel("Mode:"))
        mode_combo = QComboBox()
        mode_combo.addItems([
            "Single Segment Translation",
            "Batch DOCX Translation",
            "Batch Bilingual Translation"
        ])
        mode_combo.setToolTip("Select which system prompt to view/edit")
        mode_selector_layout.addWidget(mode_combo)
        mode_selector_layout.addStretch()
        mode_layout.addLayout(mode_selector_layout)

        mode_group.setLayout(mode_layout)
        layout.addWidget(mode_group)

        # Editor
        editor_group = QGroupBox("✏️ Edit System Prompt")
        editor_layout = QVBoxLayout()

        editor_info = QLabel(
            "Edit the system prompt below. Use {{SOURCE_LANGUAGE}}, {{TARGET_LANGUAGE}}, and {{SOURCE_TEXT}} as placeholders."
        )
        editor_info.setStyleSheet("font-size: 8pt; padding: 8px; border-radius: 2px;")
        editor_info.setWordWrap(True)
        editor_layout.addWidget(editor_info)

        system_prompt_editor = QTextEdit()
        system_prompt_editor.setStyleSheet("font-family: 'Consolas', 'Courier New', monospace; font-size: 9pt;")
        system_prompt_editor.setMinimumHeight(500)  # Increased from 400 to 500
        system_prompt_editor.setLineWrapMode(QTextEdit.LineWrapMode.WidgetWidth)  # Enable word wrap
        system_prompt_editor.setAcceptRichText(False)  # Plain text only
        editor_layout.addWidget(system_prompt_editor, 1)  # Added stretch factor of 1 to allow expansion

        editor_group.setLayout(editor_layout)
        layout.addWidget(editor_group, 1)  # Added stretch factor of 1 to allow expansion

        # Buttons
        buttons_layout = QHBoxLayout()

        reset_btn = QPushButton("🔄 Reset to Default")
        reset_btn.setToolTip("Restore the default system prompt for this mode")
        reset_btn.clicked.connect(lambda: self._reset_system_prompt(mode_combo, system_prompt_editor))
        buttons_layout.addWidget(reset_btn)

        buttons_layout.addStretch()

        save_btn = QPushButton("💾 Save System Prompt")
        save_btn.setStyleSheet("font-weight: bold; padding: 8px;")
        save_btn.clicked.connect(lambda: self._save_system_prompt_from_ui(mode_combo, system_prompt_editor))
        buttons_layout.addWidget(save_btn)

        layout.addLayout(buttons_layout)

        # Load initial prompt
        self._load_system_prompt_into_editor(mode_combo, system_prompt_editor)

        # Connect mode change to load new prompt
        mode_combo.currentIndexChanged.connect(lambda: self._load_system_prompt_into_editor(mode_combo, system_prompt_editor))

        return tab

    def _load_system_prompt_into_editor(self, mode_combo, editor):
        """Load the selected system prompt into the editor"""
        mode_map = {
            "Single Segment Translation": "single",
            "Batch DOCX Translation": "batch_docx",
            "Batch Bilingual Translation": "batch_bilingual"
        }

        selected_mode = mode_combo.currentText()
        mode_key = mode_map.get(selected_mode, "single")

        # Load from prompt_manager_qt if available
        if hasattr(self, 'prompt_manager_qt'):
            prompt_text = self.prompt_manager_qt.get_system_template(mode_key)
        else:
            # Fallback: load from JSON file
            system_prompts_file = self.user_data_path / "prompt_library" / "system_prompts_layer1.json"
            if system_prompts_file.exists():
                import json
                with open(system_prompts_file, 'r', encoding='utf-8') as f:
                    system_prompts = json.load(f)
                prompt_text = system_prompts.get(mode_key, "# SYSTEM PROMPT\n\nNo prompt defined.")
            else:
                prompt_text = "# SYSTEM PROMPT\n\nNo prompt defined."

        editor.setPlainText(prompt_text)

    def _save_system_prompt_from_ui(self, mode_combo, editor):
        """Save the edited system prompt"""
        mode_map = {
            "Single Segment Translation": "single",
            "Batch DOCX Translation": "batch_docx",
            "Batch Bilingual Translation": "batch_bilingual"
        }

        selected_mode = mode_combo.currentText()
        mode_key = mode_map.get(selected_mode, "single")
        prompt_text = editor.toPlainText()

        # Save to prompt_manager_qt if available
        if hasattr(self, 'prompt_manager_qt'):
            self.prompt_manager_qt.system_templates[mode_key] = prompt_text

        # Always save to JSON file
        import json
        system_prompts_file = self.user_data_path / "prompt_library" / "system_prompts_layer1.json"
        system_prompts_file.parent.mkdir(parents=True, exist_ok=True)

        # Load existing prompts
        if system_prompts_file.exists():
            with open(system_prompts_file, 'r', encoding='utf-8') as f:
                system_prompts = json.load(f)
        else:
            system_prompts = {}

        # Update and save
        system_prompts[mode_key] = prompt_text
        with open(system_prompts_file, 'w', encoding='utf-8') as f:
            json.dump(system_prompts, f, indent=2, ensure_ascii=False)

        self.log(f"✓ Saved system prompt: {selected_mode}")
        QMessageBox.information(
            self,
            "System Prompt Saved",
            f"System prompt for '{selected_mode}' has been saved successfully."
        )

    def _reset_system_prompt(self, mode_combo, editor):
        """Reset system prompt to default"""
        mode_map = {
            "Single Segment Translation": "single",
            "Batch DOCX Translation": "batch_docx",
            "Batch Bilingual Translation": "batch_bilingual"
        }

        selected_mode = mode_combo.currentText()
        mode_key = mode_map.get(selected_mode, "single")

        # Confirm reset
        reply = QMessageBox.question(
            self,
            "Reset System Prompt",
            f"Are you sure you want to reset the system prompt for '{selected_mode}' to its default value?\n\n"
            "This will discard any custom changes you've made.",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No
        )

        if reply == QMessageBox.StandardButton.Yes:
            # Get default from prompt_manager_qt
            if hasattr(self, 'prompt_manager_qt'):
                default_prompt = self.prompt_manager_qt._get_default_system_template(mode_key)
            else:
                default_prompt = "# SYSTEM PROMPT\n\nNo default prompt available."
            editor.setPlainText(default_prompt)
            self.log(f"✓ Reset system prompt to default: {selected_mode}")

    def _create_user_identity_tab(self):
        """Create User Identity settings tab – translator name used in file exports."""
        from PyQt6.QtWidgets import QGroupBox, QPushButton

        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(20, 20, 20, 20)
        layout.setSpacing(15)

        settings = self.load_general_settings()

        # Header
        header = QLabel(
            "👤 <b>User Identity</b><br>"
            "<span style='color:#666;'>Configure the translator name that appears in exported files. "
            "This name is written to SDLXLIFF comments, Trados return packages, TMX files, and other output.</span>"
        )
        header.setTextFormat(Qt.TextFormat.RichText)
        header.setWordWrap(True)
        header.setStyleSheet("font-size: 9pt; padding: 10px; background-color: #E3F2FD; border-radius: 4px;")
        layout.addWidget(header)

        # Translator name group
        name_group = QGroupBox("Translator Name")
        name_layout = QVBoxLayout()

        name_info = QLabel(
            "Enter your name or alias as you want it to appear in exported files.\n"
            "If left empty, your system username will be used as a fallback."
        )
        name_info.setWordWrap(True)
        name_info.setStyleSheet("font-size: 9pt; color: #555;")
        name_layout.addWidget(name_info)

        name_layout.addSpacing(5)

        name_edit = QLineEdit()
        name_edit.setPlaceholderText("(uses system username if empty)")
        name_edit.setText(settings.get('translator_name', ''))
        name_edit.setMaxLength(100)
        name_layout.addWidget(name_edit)

        # Show current fallback
        import os as _os
        fallback = _os.environ.get('USERNAME', _os.environ.get('USER', ''))
        if fallback:
            fallback_label = QLabel(f"Current system username: <b>{fallback}</b>")
            fallback_label.setTextFormat(Qt.TextFormat.RichText)
            fallback_label.setStyleSheet("font-size: 8pt; color: #888; margin-top: 3px;")
            name_layout.addWidget(fallback_label)

        name_group.setLayout(name_layout)
        layout.addWidget(name_group)

        # Save button
        save_btn = QPushButton("💾 Save User Identity")
        save_btn.setStyleSheet("font-weight: bold; padding: 8px;")
        save_btn.clicked.connect(lambda: self._save_user_identity_from_ui(name_edit))
        layout.addWidget(save_btn)

        layout.addStretch()
        return tab

    def _save_user_identity_from_ui(self, name_edit):
        """Save user identity settings."""
        general_settings = self.load_general_settings()
        general_settings['translator_name'] = name_edit.text().strip()
        self.save_general_settings(general_settings)

        saved_name = name_edit.text().strip()
        display = saved_name if saved_name else "(system username)"
        self.log(f"✓ User identity saved: translator name = {display}")
        QMessageBox.information(self, "Settings Saved", f"User identity saved.\nTranslator name: {display}")

    def _create_voice_settings_tab(self):
        """Create the Voice info/redirect tab.

        Voice (commands & dictation) lives in Sidekick. This
        Workbench Settings tab is just a signpost: a brief explanation, a
        quick-reference card for the hotkeys, and a button that opens
        Sidekick directly to the Voice tab.
        """
        from PyQt6.QtWidgets import QGroupBox, QPushButton

        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(20, 20, 20, 20)
        layout.setSpacing(15)

        header = QLabel("🎤 <b>Voice</b> – commands and dictation")
        header.setTextFormat(Qt.TextFormat.RichText)
        header.setStyleSheet("font-size: 14pt; padding: 8px;")
        layout.addWidget(header)

        info = QLabel(
            "Voice is Supervertaler's command and dictation system. "
            "Its full settings panel lives in <b>Supervertaler Sidekick</b>, the "
            "floating companion window you can summon from anywhere on your "
            "computer.<br><br>"
            "<b>Why is it there and not here?</b><br>"
            "Sidekick stays accessible even when Workbench is hidden – and "
            "Voice's Always-On listening + global hotkeys are designed to "
            "work across every app on your computer (Word, Trados, memoQ, "
            "browsers, etc.), not just inside Workbench."
        )
        info.setTextFormat(Qt.TextFormat.RichText)
        info.setWordWrap(True)
        info.setStyleSheet(
            "font-size: 9pt; color: #444; padding: 12px;"
            " background-color: #E3F2FD; border-radius: 4px;"
        )
        layout.addWidget(info)

        open_btn = QPushButton("🎤  Open Voice")
        open_btn.setStyleSheet(
            "background-color: #4CAF50; color: white; font-weight: bold;"
            " padding: 12px; font-size: 11pt; border: none;"
        )
        open_btn.clicked.connect(self._open_voice_in_workbench)
        layout.addWidget(open_btn)

        quick_ref_group = QGroupBox("📖 Quick Reference")
        quick_ref_layout = QVBoxLayout()
        quick_ref = QLabel(
            "<b>Dictation hotkey</b> (default <b>Ctrl+Shift+Space</b>) – "
            "hold to dictate, release to transcribe. Works in the "
            "Workbench grid and in any other app on your computer.<br>"
            "<b>Always-On</b> – toggleable in Sidekick → Voice tab; "
            "listens continuously, hands-free.<br>"
            "<b>Voice commands</b> – say a phrase to execute keystrokes, "
            "AutoHotkey scripts, or built-in actions. Editable in Sidekick.<br><br>"
            "Rebind the dictation hotkey to any key you like "
            "(numpad+, a function key, anything) in "
            "<b>Settings → Keyboard Shortcuts → Special → Voice dictation</b>."
        )
        quick_ref.setTextFormat(Qt.TextFormat.RichText)
        quick_ref.setWordWrap(True)
        quick_ref.setStyleSheet("font-size: 9pt; color: #555; padding: 8px;")
        quick_ref_layout.addWidget(quick_ref)
        quick_ref_group.setLayout(quick_ref_layout)
        layout.addWidget(quick_ref_group)

        layout.addStretch()
        return tab

    def _open_voice_in_workbench(self):
        """Open Workbench's Voice top tab from a Settings link / tray menu.

        Method was renamed from _open_voice_in_sidekick in v1.10.10
        when Sidekick was retired. The two existing call sites
        (Voice settings link and Always-On tray menu) were updated
        to match.
        """
        try:
            if hasattr(self, '_ensure_voice_top_tab'):
                self._ensure_voice_top_tab()
            self._bring_workbench_forward()
            if hasattr(self, 'voice_tab_index') and hasattr(self, 'main_tabs'):
                self.main_tabs.setCurrentIndex(self.voice_tab_index)
        except Exception as e:
            QMessageBox.warning(self, "Could not open Voice", str(e))

    def _bring_workbench_forward(self):
        """Bring Workbench to the foreground.

        On Windows the bare show/raise/activateWindow trio isn't
        enough to win the foreground race against another app the
        user has been working in (Trados is a known-aggressive
        host). We escalate through the full documented
        foreground-grab chain: synthetic Alt-key press to satisfy
        SetForegroundWindow's "Alt pressed" exception, then
        AttachThreadInput dance, then BringWindowToTop +
        SetForegroundWindow + SwitchToThisWindow. See v1.10.9
        changelog for the full history of this fix.
        """
        if self.isMinimized():
            self.showNormal()
        self.show()
        self.raise_()
        self.activateWindow()

        import sys
        if sys.platform == 'win32':
            # v1.10.9: belt + braces + suspenders. Three earlier
            # versions (v1.10.6 deferred the button click, v1.10.7
            # reordered ensure vs. bring, v1.10.8 split work across
            # event-loop turns) still left the first Ctrl+Alt+C from
            # a heavy host like Trados painting Workbench *behind*
            # Trados despite the SetForegroundWindow call returning
            # success. That's classic Windows foreground-stealing
            # prevention: the OS accepts the call but quietly refuses
            # to actually bring our window forward, leaving it
            # flashing in the taskbar with no visible activation.
            #
            # The canonical fix is the "Alt key" trick. Windows
            # documents an exception in the foreground-allowed rules
            # (SetForegroundWindow MSDN page): if the Alt key is
            # currently pressed at the moment SetForegroundWindow is
            # called, the OS grants the request unconditionally.
            # By synthesising a brief Alt down + Alt up *immediately
            # before* the call, we satisfy that rule even when our
            # process has no other claim to foreground rights. The
            # Alt key is released within microseconds so the user
            # never sees side effects (no menu activation etc.).
            #
            # Plus three additional hammers, applied in order:
            #   - BringWindowToTop() forces Z-order to the top of
            #     the same-thread-group stack.
            #   - SetForegroundWindow() requests the actual
            #     foreground change. With Alt held + thread input
            #     attached, the OS now accepts it.
            #   - SwitchToThisWindow() is a deprecated-but-functional
            #     API that bypasses some foreground rules entirely;
            #     used as a last-resort hammer for stubborn cases
            #     (Trados being one).
            try:
                import ctypes
                user32 = ctypes.windll.user32
                kernel32 = ctypes.windll.kernel32
                hwnd = int(self.winId())

                # Step 1: Synthetic Alt + F24 chord to satisfy
                # SetForegroundWindow's "Alt key pressed" exception
                # without triggering Qt's QMenuBar menu-activation.
                #
                # v1.10.9 used a bare Alt down/up here. That works
                # for the foreground grab, but Windows + Qt also
                # interpret a *naked* Alt tap (Alt down → Alt up
                # with nothing in between) as "user wants to
                # activate the menu bar". Even though the synthetic
                # tap was meant for the originating foreground app,
                # the AttachThreadInput dance below shares input
                # queues, so the Alt event leaks into Workbench's
                # input stream just as we become foreground. Qt's
                # QMenuBar then activates File-menu navigation and
                # the user's arrow keys steer the menu instead of
                # the Clipboard list / SuperLookup results
                # (v1.10.14 tried to fix this post-hoc by calling
                # menuBar().setActiveAction(None) and setFocus()
                # on the target widget, but that ran *before* Qt
                # processed the queued Alt event, so it cleared
                # state that hadn't been set yet).
                #
                # v1.10.15 inserts a synthetic F24 between the Alt
                # down and Alt up. VK_F24 (0x87) is a defined VK
                # code that no app binds to – it exists in the
                # Windows VK enum mostly for keyboards with extended
                # function-key rows that nobody ships any more. Qt's
                # QMenuBar treats Alt+anything as a chord, not a
                # naked Alt tap, and skips menu activation. The
                # synthetic F24 itself reaches no listener (nothing
                # binds it). The Alt key still satisfies
                # SetForegroundWindow's exception because it's
                # pressed at the moment SetForegroundWindow is
                # called.
                VK_MENU = 0x12
                VK_F24 = 0x87
                KEYEVENTF_KEYUP = 0x0002
                user32.keybd_event(VK_MENU, 0, 0, 0)               # Alt down
                user32.keybd_event(VK_F24, 0, 0, 0)                # F24 down (chord)
                user32.keybd_event(VK_F24, 0, KEYEVENTF_KEYUP, 0)  # F24 up
                user32.keybd_event(VK_MENU, 0, KEYEVENTF_KEYUP, 0) # Alt up

                # Step 2: AttachThreadInput dance.
                fg = user32.GetForegroundWindow()
                fg_thread = user32.GetWindowThreadProcessId(fg, None)
                our_thread = kernel32.GetCurrentThreadId()
                attached = False
                if fg and fg_thread and fg_thread != our_thread:
                    attached = bool(
                        user32.AttachThreadInput(fg_thread, our_thread, True)
                    )

                # Step 3: Force Z-order to top, then request
                # foreground, then the deprecated-but-effective
                # SwitchToThisWindow hammer.
                try:
                    user32.BringWindowToTop(hwnd)
                    user32.SetForegroundWindow(hwnd)
                    # SwitchToThisWindow(hwnd, fAltTab=True) – second
                    # arg makes the call behave like an Alt+Tab
                    # switch which is more reliable than the bare
                    # foreground-request path.
                    user32.SwitchToThisWindow(hwnd, True)
                finally:
                    if attached:
                        user32.AttachThreadInput(fg_thread, our_thread, False)
            except Exception as e:
                print(f"[Workbench] foreground escalation failed: {e}")

        # v1.10.14: the synthetic Alt-tap above gets the foreground
        # grant we need, but it's also what Windows interprets as
        # "user pressed Alt to activate the menu bar". Even though
        # we sent the Alt to the *originating* foreground (Trados),
        # AttachThreadInput shares input queues for the duration, so
        # the Alt event leaks into Workbench's input stream just as
        # we become foreground. Qt's QMenuBar then activates File-
        # menu navigation mode and the user's arrow keys steer the
        # menu instead of the Clipboard list / SuperLookup results.
        # Dismiss the leaked menu state explicitly so we land in the
        # expected "neutral" focus state.
        self._dismiss_menu_activation()

    def _dismiss_menu_activation(self):
        """Clear any leaked menu-bar activation after a foreground
        grab. Called from _bring_workbench_forward(); safe to call
        when no menu is active (no-op in that case). The continuation
        callbacks (`_continue_clipboard`, `_continue_superlookup`)
        also explicitly setFocus() on their target widget, which
        belt-and-braces clears the menu-activation indirectly – but
        calling setActiveAction(None) here makes the cleanup
        deterministic instead of relying on focus-change side
        effects."""
        try:
            mb = self.menuBar() if hasattr(self, 'menuBar') else None
            if mb is not None:
                mb.setActiveAction(None)
        except Exception:
            pass

    def open_workbench_to_superlookup(self, text: str = ""):
        """Bring Workbench forward, switch to the SuperLookup top tab,
        and optionally seed the search field with ``text``.

        Wired to Ctrl+Alt+L in v1.10.1 (Phase 2 of issue #199). Replaces
        the legacy ``Sidekick.show_superlookup(text)`` route for the
        global hotkey path; Sidekick's own copy still works for users
        who summon Sidekick via Ctrl+Alt+K.
        """
        try:
            # v1.10.7: bring Workbench forward *before* the lazy-tab
            # ensure.
            # v1.10.8: that wasn't enough on a cold first run. Even
            # with bring-forward called first, the SetForegroundWindow
            # call only *queues* WM_ACTIVATE / WM_PAINT for our
            # window – Workbench doesn't visibly become active until
            # Qt's event loop processes those messages. If we then
            # synchronously call _ensure_superlookup_top_tab() and
            # block the GUI thread for 1–2s building the widget, the
            # queued activation events sit waiting; meanwhile Windows
            # may decide to re-evaluate foreground or simply never
            # repaint Workbench as the active window because Qt hasn't
            # acknowledged the WM_ACTIVATE. The user keeps seeing
            # their source app the whole time.
            #
            # Fix: split the work across two event-loop turns.
            #   Turn 1 (now):   _bring_workbench_forward()
            #   Turn 2 (next):  ensure + setCurrentIndex + seed/click
            # QTimer.singleShot(0, …) schedules the continuation for
            # the next iteration of Qt's main loop, between which the
            # activation/paint events get processed and Workbench
            # actually appears on top before we start blocking the
            # GUI thread on widget construction.
            self._bring_workbench_forward()
            from PyQt6.QtCore import QTimer

            def _continue_superlookup():
                try:
                    if hasattr(self, '_ensure_superlookup_top_tab'):
                        self._ensure_superlookup_top_tab()
                    if hasattr(self, 'superlookup_tab_index') and hasattr(self, 'main_tabs'):
                        self.main_tabs.setCurrentIndex(self.superlookup_tab_index)
                    widget = getattr(self, '_superlookup_top_widget', None)
                    if widget is not None:
                        # v1.10.14: explicit focus on the search field
                        # (or the tab root if the search field isn't
                        # available) so keyboard navigation lands here
                        # instead of leaking into the menu bar after
                        # the foreground-grab Alt-tap.
                        try:
                            if hasattr(widget, 'source_text') and widget.source_text is not None:
                                widget.source_text.setFocus()
                            else:
                                widget.setFocus()
                        except Exception:
                            pass
                    if widget is not None and text:
                        try:
                            if hasattr(widget, 'source_text'):
                                widget.source_text.setEditText(text)
                            if hasattr(widget, 'search_btn'):
                                # Still defer the click by another
                                # 150ms past the ensure so the search
                                # doesn't peg the GUI thread before
                                # the tab finishes painting.
                                QTimer.singleShot(150, widget.search_btn.click)
                        except Exception as inner:
                            self.log(f"⚠ Could not seed SuperLookup search: {inner}")
                except Exception as inner:
                    self.log(f"⚠ Could not finish SuperLookup open: {inner}")

            QTimer.singleShot(0, _continue_superlookup)
        except Exception as e:
            self.log(f"⚠ Could not open SuperLookup top tab: {e}")
            import traceback
            traceback.print_exc()

    def open_workbench_to_clipboard(self, source_window=None):
        """Bring Workbench forward and switch to the Clipboard top tab.

        Wired to Ctrl+Alt+C in v1.10.1 (Phase 2 of issue #199). If
        ``source_window`` is supplied (captured by the hotkey handler
        BEFORE bringing Workbench forward), it's passed to the
        Clipboard widget so snippet / conversion activations
        paste-and-return to that window rather than just sitting on
        the clipboard. Manual navigation to the Clipboard tab passes
        no source; activations then just set the clipboard.
        """
        try:
            # v1.10.7 reordered to bring-then-ensure.
            # v1.10.8 additionally splits the work across two Qt event-
            # loop turns so the WM_ACTIVATE / WM_PAINT events queued by
            # _bring_workbench_forward() actually get processed before
            # the heavy lazy-tab ensure blocks the GUI thread. See
            # open_workbench_to_superlookup for the full diagnosis.
            self._bring_workbench_forward()
            from PyQt6.QtCore import QTimer

            def _continue_clipboard():
                try:
                    if hasattr(self, '_ensure_clipboard_top_tab'):
                        self._ensure_clipboard_top_tab()
                    if hasattr(self, 'clipboard_tab_index') and hasattr(self, 'main_tabs'):
                        self.main_tabs.setCurrentIndex(self.clipboard_tab_index)
                    widget = getattr(self, '_clipboard_top_widget', None)
                    if widget is not None and hasattr(widget, 'set_source_window'):
                        widget.set_source_window(source_window)
                    # v1.10.14: explicit focus on the clipboard text
                    # list so arrow keys navigate the history straight
                    # away. Without this, the foreground-grab Alt-tap
                    # leaks into Qt's QMenuBar and arrow keys steer
                    # the File menu instead of the list. Prefer the
                    # text list (most-used column); the widget's own
                    # _focus_list helper falls back to selecting row 0
                    # if nothing is currently selected.
                    if widget is not None:
                        try:
                            text_list = getattr(widget, '_text_list', None)
                            if text_list is not None and hasattr(widget, '_focus_list'):
                                widget._focus_list(text_list)
                            else:
                                widget.setFocus()
                        except Exception:
                            pass
                except Exception as inner:
                    self.log(f"⚠ Could not finish Clipboard open: {inner}")

            QTimer.singleShot(0, _continue_clipboard)
        except Exception as e:
            self.log(f"⚠ Could not open Clipboard top tab: {e}")
            import traceback
            traceback.print_exc()

    def open_settings_to_keyboard_shortcuts(self):
        """Jump to Settings → Keyboard Shortcuts.

        Called from the Voice tab's "Change in Settings → Keyboard
        Shortcuts" link. Switches the main window to the Settings page
        and selects the Keyboard Shortcuts sub-tab.
        """
        try:
            main_tabs = getattr(self, 'main_tabs', None)
            settings_tabs = getattr(self, 'settings_tabs', None)
            settings_idx = getattr(self, 'settings_tab_index', None)
            kb_idx = getattr(self, 'keyboard_shortcuts_tab_index', None)
            if main_tabs is not None and settings_idx is not None:
                main_tabs.setCurrentIndex(settings_idx)
            if settings_tabs is not None and kb_idx is not None:
                settings_tabs.setCurrentIndex(kb_idx)
            self._bring_workbench_forward()
        except Exception as e:
            QMessageBox.information(
                self, "Open Keyboard Shortcuts",
                f"Couldn't auto-navigate (\"{e}\"). Open the main "
                "Workbench window → Settings → Keyboard Shortcuts and "
                "find <b>Voice dictation / push-to-talk</b> under "
                "<b>Special</b>."
            )

    def reload_global_hotkeys(self):
        """Re-register the global hotkey set with current ShortcutManager values.

        Called after the user changes a ``global_*`` shortcut in
        Settings → Keyboard Shortcuts. Without this call, the OS-level
        hotkey listener keeps firing on the *old* key until the next
        application restart, because pynput / WinAPI registrations don't
        track ShortcutManager state. Idempotent – ``register_global_hotkey``
        stops any previously running manager before binding fresh keys.
        """
        lookup_tab = getattr(self, 'lookup_tab', None)
        if lookup_tab is None or not hasattr(lookup_tab, 'register_global_hotkey'):
            return
        try:
            lookup_tab.register_global_hotkey()
        except Exception as e:
            self.log(f"⚠ Could not reload global hotkeys: {e}")

    def _create_debug_settings_tab(self):
        """Create Debug Settings tab content"""
        from PyQt6.QtWidgets import QGroupBox, QPushButton, QTextEdit
        
        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(20, 20, 20, 20)
        layout.setSpacing(15)
        
        debug_settings = self.load_general_settings()
        
        # Debug Mode section
        debug_group = QGroupBox("🐛 Debug Mode")
        debug_layout = QVBoxLayout()
        
        info_label = QLabel(
            "<b>Debug Mode</b> enables verbose logging to help diagnose performance issues.\n\n"
            "When enabled, detailed logs will show:\n"
            "• Every text change event in the grid\n"
            "• Database update operations (BEFORE/AFTER)\n"
            "• Cell selection events\n"
            "• Signal connections\n\n"
            "⚠️ <b>Warning:</b> Debug mode generates a LOT of log output and may slow down the application.\n"
            "Only enable when troubleshooting specific issues."
        )
        info_label.setWordWrap(True)
        info_label.setStyleSheet("font-size: 9pt; padding: 10px; border-radius: 4px;")
        debug_layout.addWidget(info_label)
        
        debug_layout.addSpacing(10)
        
        # Enable debug mode checkbox
        debug_mode_cb = CheckmarkCheckBox("Enable verbose debug logging")
        debug_mode_cb.setChecked(debug_settings.get('debug_mode_enabled', False))
        debug_mode_cb.setToolTip(
            "When enabled, shows detailed debug messages in the log.\n"
            "This helps diagnose performance issues but generates a lot of output."
        )
        debug_layout.addWidget(debug_mode_cb)
        
        # Auto-export debug logs checkbox
        debug_export_cb = CheckmarkCheckBox("Auto-export debug logs to file")
        debug_export_cb.setChecked(debug_settings.get('debug_auto_export', False))
        debug_export_cb.setToolTip(
            "When enabled, automatically saves debug logs to:\n"
            "supervertaler_debug_log_<timestamp>.txt in the program root.\n"
            "Logs are exported every 5 minutes or when you close the application."
        )
        debug_export_cb.setEnabled(debug_mode_cb.isChecked())  # Only enabled if debug mode is on
        debug_layout.addWidget(debug_export_cb)
        
        # Link the checkboxes
        debug_mode_cb.toggled.connect(lambda checked: debug_export_cb.setEnabled(checked))
        
        debug_layout.addSpacing(10)
        
        # Export log button
        export_btn = QPushButton("📁 Export Debug Log Now")
        export_btn.setToolTip("Export the current debug log buffer to a timestamped file")
        export_btn.clicked.connect(self.export_debug_log_now)
        debug_layout.addWidget(export_btn)
        
        # Clear log buffer button
        clear_btn = QPushButton("🗑️ Clear Debug Log Buffer")
        clear_btn.setToolTip("Clear the in-memory debug log buffer")
        clear_btn.clicked.connect(self.clear_debug_log_buffer)
        debug_layout.addWidget(clear_btn)
        
        debug_group.setLayout(debug_layout)
        layout.addWidget(debug_group)
        
        # Performance Settings section
        perf_group = QGroupBox("⚡ Performance Settings")
        perf_layout = QVBoxLayout()
        
        perf_info = QLabel(
            "<b>Performance Tuning</b> - These settings control UI responsiveness.\n\n"
            "Higher delays = more responsive typing but slower lookups.\n"
            "Lower delays = faster lookups but potential UI freezes during typing."
        )
        perf_info.setWordWrap(True)
        perf_info.setStyleSheet("font-size: 9pt; padding: 10px; border-radius: 4px;")
        perf_layout.addWidget(perf_info)
        
        perf_layout.addSpacing(10)
        
        # Target text debounce delay
        debounce_layout = QHBoxLayout()
        debounce_layout.addWidget(QLabel("Target text save delay:"))
        debounce_spin = QSpinBox()
        debounce_spin.setRange(100, 5000)
        debounce_spin.setValue(debug_settings.get('target_debounce_delay', 1000))
        debounce_spin.setSingleStep(100)
        debounce_spin.setSuffix(" ms")
        debounce_spin.setToolTip(
            "Delay before saving target text changes to database.\n"
            "1000ms (default) = good balance between responsiveness and data safety.\n"
            "Higher values = less database overhead but longer delay before saving."
        )
        debounce_layout.addWidget(debounce_spin)
        debounce_layout.addStretch()
        perf_layout.addLayout(debounce_layout)
        
        perf_group.setLayout(perf_layout)
        layout.addWidget(perf_group)
        
        # Save button
        save_btn = QPushButton("💾 Save Debug Settings")
        save_btn.setStyleSheet("font-weight: bold; padding: 8px;")
        save_btn.clicked.connect(lambda: self._save_debug_settings_from_ui(
            debug_mode_cb, debug_export_cb, debounce_spin
        ))
        layout.addWidget(save_btn)
        
        layout.addStretch()
        
        return tab

    def _save_debug_settings_from_ui(self, debug_mode_cb, debug_export_cb, debounce_spin):
        """Save debug settings from UI"""
        self.debug_mode_enabled = debug_mode_cb.isChecked()
        self.debug_auto_export = debug_export_cb.isChecked()
        
        general_settings = self.load_general_settings()
        general_settings['debug_mode_enabled'] = self.debug_mode_enabled
        general_settings['debug_auto_export'] = self.debug_auto_export
        general_settings['target_debounce_delay'] = debounce_spin.value()
        self.save_general_settings(general_settings)
        
        self.log(f"✓ Debug settings saved: Debug Mode={'ON' if self.debug_mode_enabled else 'OFF'}, Auto-export={'ON' if self.debug_auto_export else 'OFF'}")
        QMessageBox.information(self, "Settings Saved", "Debug settings have been saved successfully.")
    
    def export_debug_log_now(self):
        """Export debug log buffer to file immediately"""
        from datetime import datetime
        
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        filename = f"supervertaler_debug_log_{timestamp}.txt"
        
        try:
            with open(filename, 'w', encoding='utf-8') as f:
                f.write(f"Supervertaler Workbench Debug Log\n")
                f.write(f"Generated: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                f.write("="*80 + "\n\n")
                
                if self.debug_log_buffer:
                    f.write("\n".join(self.debug_log_buffer))
                else:
                    f.write("(No debug logs in buffer)")
            
            self.log(f"✓ Debug log exported to: {filename}")
            QMessageBox.information(
                self,
                "Log Exported",
                f"Debug log exported successfully to:\n{filename}\n\n"
                f"Log entries: {len(self.debug_log_buffer)}"
            )
        except Exception as e:
            self.log(f"❌ Error exporting debug log: {e}")
            QMessageBox.warning(self, "Export Failed", f"Failed to export debug log:\n{e}")
    
    def clear_debug_log_buffer(self):
        """Clear the debug log buffer"""
        buffer_size = len(self.debug_log_buffer)
        self.debug_log_buffer.clear()
        self.log(f"✓ Debug log buffer cleared ({buffer_size} entries removed)")
        QMessageBox.information(self, "Buffer Cleared", f"Debug log buffer cleared.\n{buffer_size} entries removed.")

    def _create_domain_keywords_tab(self):
        """Create Domain Detection Keywords tab content"""
        from PyQt6.QtWidgets import QGroupBox, QPushButton, QTextEdit, QTabWidget

        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(20, 20, 20, 20)
        layout.setSpacing(15)

        # Introduction
        intro_label = QLabel(
            "<h3>🎯 Automated Domain Detection</h3>"
            "<p>Supervertaler automatically identifies document types (Legal, Medical, Technical, Patent) "
            "to generate domain-appropriate translation prompts.</p>"
            "<p><b>Keywords below</b> are used for detection. The system counts matches and selects the domain "
            "with the highest score (minimum 2 matches required).</p>"
            "<p>💡 <b>Tip:</b> Add domain-specific terminology to improve detection accuracy for your projects.</p>"
        )
        intro_label.setWordWrap(True)
        intro_label.setStyleSheet("font-size: 10pt; padding: 10px; border-radius: 4px;")
        layout.addWidget(intro_label)

        # Load current keywords from prompt_manager_qt.py default lists
        keywords = self._load_domain_keywords()

        # Create tab widget for each domain
        domain_tabs = QTabWidget()
        domain_tabs.tabBar().setFocusPolicy(Qt.FocusPolicy.NoFocus)
        domain_tabs.tabBar().setDrawBase(False)
        domain_tabs.tabBar().setExpanding(False)
        domain_tabs.setStyleSheet("QTabBar::tab { outline: 0; } QTabBar::tab:focus { outline: none; } QTabBar::tab:selected { border-bottom: 1px solid #2196F3; background-color: rgba(33, 150, 243, 0.08); }")

        # Legal domain
        legal_tab = QWidget()
        legal_layout = QVBoxLayout(legal_tab)
        legal_info = QLabel("<b>Legal/Notarial Documents:</b> Notarial deeds, contracts, court documents, Belgian law")
        legal_info.setWordWrap(True)
        legal_layout.addWidget(legal_info)
        self.legal_keywords_edit = QTextEdit()
        self.legal_keywords_edit.setPlainText("\n".join(keywords['legal']))
        self.legal_keywords_edit.setPlaceholderText("Enter keywords, one per line...")
        legal_layout.addWidget(self.legal_keywords_edit)
        domain_tabs.addTab(legal_tab, "⚖️ Legal")

        # Medical domain
        medical_tab = QWidget()
        medical_layout = QVBoxLayout(medical_tab)
        medical_info = QLabel("<b>Medical Documents:</b> Clinical reports, procedures, pharmaceutical documents")
        medical_info.setWordWrap(True)
        medical_layout.addWidget(medical_info)
        self.medical_keywords_edit = QTextEdit()
        self.medical_keywords_edit.setPlainText("\n".join(keywords['medical']))
        self.medical_keywords_edit.setPlaceholderText("Enter keywords, one per line...")
        medical_layout.addWidget(self.medical_keywords_edit)
        domain_tabs.addTab(medical_tab, "🏥 Medical")

        # Patent domain
        patent_tab = QWidget()
        patent_layout = QVBoxLayout(patent_tab)
        patent_info = QLabel("<b>Patent Documents:</b> Patent applications, claims, prior art references")
        patent_info.setWordWrap(True)
        patent_layout.addWidget(patent_info)
        self.patent_keywords_edit = QTextEdit()
        self.patent_keywords_edit.setPlainText("\n".join(keywords['patent']))
        self.patent_keywords_edit.setPlaceholderText("Enter keywords, one per line...")
        patent_layout.addWidget(self.patent_keywords_edit)
        domain_tabs.addTab(patent_tab, "🔬 Patent")

        # Technical domain
        technical_tab = QWidget()
        technical_layout = QVBoxLayout(technical_tab)
        technical_info = QLabel("<b>Technical Documents:</b> Manuals, specifications, installation guides")
        technical_info.setWordWrap(True)
        technical_layout.addWidget(technical_info)
        self.technical_keywords_edit = QTextEdit()
        self.technical_keywords_edit.setPlainText("\n".join(keywords['technical']))
        self.technical_keywords_edit.setPlaceholderText("Enter keywords, one per line...")
        technical_layout.addWidget(self.technical_keywords_edit)
        domain_tabs.addTab(technical_tab, "🔧 Technical")

        layout.addWidget(domain_tabs)

        # Save and Reset buttons
        buttons_layout = QHBoxLayout()

        reset_btn = QPushButton("🔄 Reset to Defaults")
        reset_btn.setToolTip("Reset all keyword lists to default values")
        reset_btn.clicked.connect(self._reset_domain_keywords_to_defaults)
        buttons_layout.addWidget(reset_btn)

        buttons_layout.addStretch()

        save_btn = QPushButton("💾 Save Domain Keywords")
        save_btn.setToolTip("Save custom domain detection keywords")
        save_btn.clicked.connect(self._save_domain_keywords)
        save_btn.setStyleSheet("font-weight: bold; padding: 8px 16px;")
        buttons_layout.addWidget(save_btn)

        layout.addLayout(buttons_layout)

        return tab

