    # =========================================================================
    
    # Class variables for Match Panel font (TM Source/Target boxes)
    match_panel_font_size = 10    # Default font size
    match_panel_font_family = ''  # Empty = system default; set from settings on startup
    match_panel_font_bold = False  # Default not bold

    def match_panel_zoom_in(self):
        """Increase font size in Match Panel TM boxes"""
        SupervertalerQt.match_panel_font_size = min(18, SupervertalerQt.match_panel_font_size + 1)
        self._apply_match_panel_font_size()
        self.save_current_font_sizes()
        self.log(f"Match Panel font size: {SupervertalerQt.match_panel_font_size}pt")

    def match_panel_zoom_out(self):
        """Decrease font size in Match Panel TM boxes"""
        SupervertalerQt.match_panel_font_size = max(7, SupervertalerQt.match_panel_font_size - 1)
        self._apply_match_panel_font_size()
        self.save_current_font_sizes()
        self.log(f"Match Panel font size: {SupervertalerQt.match_panel_font_size}pt")

    def match_panel_zoom_reset(self):
        """Reset font size in Match Panel TM boxes to default"""
        SupervertalerQt.match_panel_font_size = 10
        self._apply_match_panel_font_size()
        self.save_current_font_sizes()
        self.log("Match Panel font size reset to 10pt")
    
    def _apply_match_panel_font_size(self):
        """Apply current font settings to Match Panel TM Source/Target text edits.

        Both the QTextEdit stylesheet AND the document default font must be updated:
        - The stylesheet controls plain-text rendering.
        - The document default font controls rich-text content inserted via QTextCursor
          (e.g. diff-highlighted segments), which ignores the stylesheet font-size.
        """
        if not hasattr(self, 'compare_panel_text_edits'):
            return

        font_size = SupervertalerQt.match_panel_font_size
        font_family = SupervertalerQt.match_panel_font_family
        font_bold = SupervertalerQt.match_panel_font_bold

        # Build a QFont for the document default font
        from PyQt6.QtGui import QFont
        doc_font = QFont()
        if font_family:
            doc_font.setFamily(font_family)
        doc_font.setPointSize(font_size)
        doc_font.setBold(font_bold)

        for item in self.compare_panel_text_edits:
            text_edit = item[0]  # First element is the QTextEdit
            if not (text_edit and hasattr(text_edit, 'setStyleSheet')):
                continue

            # 1. Update stylesheet (for plain-text rendering)
            import re
            current_style = text_edit.styleSheet()
            new_style = re.sub(r'font-size:\s*\d+px;?', f'font-size: {font_size}px;', current_style)
            if 'font-size' not in new_style:
                new_style += f" font-size: {font_size}px;"
            text_edit.setStyleSheet(new_style)

            # 2. Update document default font (for rich-text / cursor-inserted content)
            text_edit.document().setDefaultFont(doc_font)
    
    def save_current_font_sizes(self):
        """Save current font sizes to preferences"""
        try:
            from modules.translation_results_panel import CompactMatchItem, TranslationResultsPanel
            general_settings = self.load_general_settings()
            general_settings['grid_font_family'] = self.default_font_family
            general_settings['grid_font_size'] = self.default_font_size
            if hasattr(CompactMatchItem, 'font_size_pt'):
                general_settings['results_match_font_size'] = CompactMatchItem.font_size_pt
            if hasattr(TranslationResultsPanel, 'compare_box_font_size'):
                general_settings['results_compare_font_size'] = TranslationResultsPanel.compare_box_font_size
            if hasattr(CompactMatchItem, 'show_tags'):
                general_settings['results_show_tags'] = CompactMatchItem.show_tags
            if hasattr(EditableGridTextEditor, 'tag_highlight_color'):
                general_settings['tag_highlight_color'] = EditableGridTextEditor.tag_highlight_color
            # Save Match Panel font settings
            general_settings['match_panel_font_size'] = SupervertalerQt.match_panel_font_size
            general_settings['match_panel_font_family'] = SupervertalerQt.match_panel_font_family
            general_settings['match_panel_font_bold'] = SupervertalerQt.match_panel_font_bold
            # Preserve other settings
            if 'restore_last_project' not in general_settings:
                general_settings['restore_last_project'] = False
            self.save_general_settings(general_settings)
        except Exception as e:
            # Silently fail - don't interrupt user workflow
            pass
    
    def load_general_settings(self) -> Dict[str, Any]:
        """Load general application settings"""
        # Initialize auto-propagation from loaded settings
        settings = self._load_general_settings_from_file()
        if 'auto_propagate_exact_matches' in settings:
            self.auto_propagate_exact_matches = settings['auto_propagate_exact_matches']
        if 'auto_insert_100_percent_matches' in settings:
            self.auto_insert_100_percent_matches = settings['auto_insert_100_percent_matches']
        if 'auto_confirm_100_percent_matches' in settings:
            self.auto_confirm_100_percent_matches = settings['auto_confirm_100_percent_matches']
        if 'auto_confirm_overwrite_existing' in settings:
            self.auto_confirm_overwrite_existing = settings['auto_confirm_overwrite_existing']
        # Load TM/termbase matching setting
        if 'enable_tm_termbase_matching' in settings:
            self.enable_tm_matching = settings['enable_tm_termbase_matching']
            self.enable_termbase_matching = settings['enable_tm_termbase_matching']
        # Load termbase grid highlighting setting
        if 'enable_termbase_grid_highlighting' in settings:
            self.enable_termbase_grid_highlighting = settings['enable_termbase_grid_highlighting']
        # Load auto-markdown setting
        self.auto_generate_markdown = settings.get('auto_generate_markdown', False)
        # Load TM save mode
        self.tm_save_mode = settings.get('tm_save_mode', 'latest')
        # Load debug mode settings
        self.debug_mode_enabled = settings.get('debug_mode_enabled', False)
        self.debug_auto_export = settings.get('debug_auto_export', False)
        # Load LLM matching setting (default: FALSE - too slow!)
        self.enable_llm_matching = settings.get('enable_llm_matching', False)
        # Load precision scroll divisor setting
        self.precision_scroll_divisor = settings.get('precision_scroll_divisor', 3)
        # Load auto-center active segment setting (default True, like memoQ/Trados)
        self.auto_center_active_segment = settings.get('auto_center_active_segment', True)
        # Load termbase display settings
        self.termbase_hide_shorter_matches = settings.get('termbase_hide_shorter_matches', False)
        # Load invisible character color
        self.invisible_char_color = settings.get('invisible_char_color', '#999999')
        # Load smart word selection setting
        self.enable_smart_word_selection = settings.get('enable_smart_word_selection', True)
        
        # Load alternating row color settings
        self.enable_alternating_row_colors = settings.get('enable_alternating_row_colors', True)
        self.even_row_color = settings.get('even_row_color', '#FFFFFF')
        self.odd_row_color = settings.get('odd_row_color', '#F0F0F0')

        # Load hide outer wrapping tags setting
        self.hide_outer_wrapping_tags = settings.get('hide_outer_wrapping_tags', False)

        # Load termbase highlight style settings
        self.termbase_highlight_style = settings.get('termbase_highlight_style', 'semibold')
        self.termbase_dotted_color = settings.get('termbase_dotted_color', '#808080')
        
        # Load tab position setting
        self.tabs_above_grid = settings.get('tabs_above_grid', False)
        
        # Load panel visibility settings
        self.show_translation_results_pane = settings.get('show_translation_results_pane', False)
        self.show_compare_panel = settings.get('show_compare_panel', True)

        # Load cache kill switch setting (default: False = caches ENABLED for performance)
        self.disable_all_caches = settings.get('disable_all_caches', False)

        # Load LLM provider settings for AI Assistant
        llm_settings = self.load_llm_settings()
        self.current_provider = llm_settings.get('provider', 'openai')
        provider_key = f"{self.current_provider}_model"
        self.current_model = llm_settings.get(provider_key)

        return settings
    
    # ═══════════════════════════════════════════════════════════════════════
    # Unified Settings Infrastructure
    # All settings are stored in settings/settings.json with top-level sections:
    #   "api_keys", "general", "ui", "features"
    # ═══════════════════════════════════════════════════════════════════════

    def _get_settings_dir(self) -> Path:
        """Get the settings subdirectory path"""
        return self.user_data_path / "workbench" / "settings"

    def _get_unified_settings_path(self) -> Path:
        """Get the unified settings.json file path"""
        return self._get_settings_dir() / "settings.json"

    def _load_unified_settings(self) -> Dict[str, Any]:
        """Load the entire unified settings file"""
        settings_file = self._get_unified_settings_path()
        if not settings_file.exists():
            return {"api_keys": {}, "general": {}, "ui": {}, "features": {}}
        try:
            with open(settings_file, 'r', encoding='utf-8') as f:
                data = json.load(f)
            # Ensure all sections exist
            for section in ("api_keys", "general", "ui", "features"):
                if section not in data:
                    data[section] = {}
            return data
        except Exception:
            return {"api_keys": {}, "general": {}, "ui": {}, "features": {}}

    def _save_unified_settings(self, data: Dict[str, Any]):
        """Save the entire unified settings file"""
        settings_dir = self._get_settings_dir()
        settings_dir.mkdir(parents=True, exist_ok=True)
        settings_file = settings_dir / "settings.json"
        try:
            with open(settings_file, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=2, ensure_ascii=False)
        except Exception as e:
            self.log(f"⚠ Could not save settings: {str(e)}")

    def _load_settings_section(self, section: str) -> Dict[str, Any]:
        """Load a specific section from unified settings"""
        return self._load_unified_settings().get(section, {})

    def _save_settings_section(self, section: str, section_data: Dict[str, Any]):
        """Save a specific section to unified settings (preserves other sections)"""
        all_settings = self._load_unified_settings()
        all_settings[section] = section_data
        self._save_unified_settings(all_settings)

    def _migrate_settings_to_unified(self):
        """One-time migration from old settings files to unified settings/settings.json"""
        settings_dir = self._get_settings_dir()
        unified_file = settings_dir / "settings.json"

        # Skip if already migrated
        if unified_file.exists():
            return

        print("[Settings] Migrating to unified settings/settings.json ...")
        settings_dir.mkdir(parents=True, exist_ok=True)
        unified = {"api_keys": {}, "general": {}, "ui": {}, "features": {}}

        # 1. Migrate general_settings.json
        old_general = self.user_data_path / "general_settings.json"
        if old_general.exists():
            try:
                with open(old_general, 'r', encoding='utf-8') as f:
                    unified["general"] = json.load(f)
                old_general.rename(old_general.with_suffix('.json.migrated'))
            except Exception as e:
                print(f"[Settings] Warning: could not migrate general_settings.json: {e}")

        # 2. Migrate ui_preferences.json
        old_prefs = self.user_data_path / "ui_preferences.json"
        if old_prefs.exists():
            try:
                with open(old_prefs, 'r', encoding='utf-8') as f:
                    prefs = json.load(f)
                # Remove the nested general_settings (it's a stale duplicate of general_settings.json)
                prefs.pop('general_settings', None)
                unified["ui"] = prefs
                old_prefs.rename(old_prefs.with_suffix('.json.migrated'))
            except Exception as e:
                print(f"[Settings] Warning: could not migrate ui_preferences.json: {e}")

        # 3. Migrate feature_settings.json
        old_features = self.user_data_path / "feature_settings.json"
        if old_features.exists():
            try:
                with open(old_features, 'r', encoding='utf-8') as f:
                    unified["features"] = json.load(f)
                old_features.rename(old_features.with_suffix('.json.migrated'))
            except Exception as e:
                print(f"[Settings] Warning: could not migrate feature_settings.json: {e}")

        # 4. Migrate api_keys.txt
        api_keys_file = None
        for candidate in [self.user_data_path / "api_keys.txt",
                          Path(__file__).parent / "user_data_private" / "api_keys.txt"]:
            if candidate.exists():
                api_keys_file = candidate
                break

        if api_keys_file:
            try:
                api_keys = {}
                with open(api_keys_file, 'r', encoding='utf-8') as f:
                    for line in f:
                        line = line.strip()
                        if line and '=' in line and not line.startswith('#'):
                            key, value = line.split('=', 1)
                            api_keys[key.strip().lower()] = value.strip()
                # Migrate legacy 'google' key to canonical 'gemini' key
                if api_keys.get('google') and not api_keys.get('gemini'):
                    api_keys['gemini'] = api_keys['google']
                unified["api_keys"] = api_keys
                api_keys_file.rename(api_keys_file.with_suffix('.txt.migrated'))
            except Exception as e:
                print(f"[Settings] Warning: could not migrate api_keys.txt: {e}")

        # 5. Relocate satellite JSON files to settings/ subfolder
        import shutil
        for filename in ['find_replace_history.json', 'superlookup_history.json',
                         'recent_projects.json',
                         'themes.json', 'shortcuts.json', 'voice_commands.json']:
            old_path = self.user_data_path / filename
            new_path = settings_dir / filename
            if old_path.exists() and not new_path.exists():
                try:
                    shutil.move(str(old_path), str(new_path))
                except Exception as e:
                    print(f"[Settings] Warning: could not move {filename}: {e}")

        # 6. Write unified settings
        try:
            with open(unified_file, 'w', encoding='utf-8') as f:
                json.dump(unified, f, indent=2, ensure_ascii=False)
            print(f"[Settings] Migration complete: {unified_file}")
        except Exception as e:
            print(f"[Settings] Error writing unified settings: {e}")

    def _migrate_to_workbench_layout(self):
        """One-time migration: move Workbench files into a workbench/ subfolder.

        Old layout:
            ~/Supervertaler/settings/         → workbench/settings/
            ~/Supervertaler/dictionaries/     → workbench/dictionaries/
            ~/Supervertaler/voice_scripts/    → workbench/voice_scripts/
            ~/Supervertaler/ai_assistant/     → workbench/ai_assistant/
            ~/Supervertaler/web_cache/        → workbench/web_cache/
            ~/Supervertaler/projects/         → workbench/projects/

        Shared resources (prompt_library/, resources/) stay at the root.
        """
        import shutil

        flag_file = self.user_data_path / "workbench" / ".migrated"
        if flag_file.exists():
            return

        old_settings = self.user_data_path / "settings" / "settings.json"
        if not old_settings.exists():
            # Nothing to migrate – fresh install or already migrated.
            # Just ensure the workbench dir exists and write the flag.
            try:
                (self.user_data_path / "workbench" / "settings").mkdir(parents=True, exist_ok=True)
                flag_file.write_text(datetime.utcnow().isoformat(), encoding='utf-8')
            except Exception:
                pass
            return

        print("[Layout] Migrating to workbench/ subfolder layout ...")
        wb = self.user_data_path / "workbench"

        try:
            # Move settings/ → workbench/settings/
            old_settings_dir = self.user_data_path / "settings"
            new_settings_dir = wb / "settings"
            if old_settings_dir.exists() and not new_settings_dir.exists():
                new_settings_dir.mkdir(parents=True, exist_ok=True)
                for f in old_settings_dir.iterdir():
                    if f.is_file():
                        dest = new_settings_dir / f.name
                        if not dest.exists():
                            shutil.move(str(f), str(dest))
                # Remove old dir if empty
                try:
                    old_settings_dir.rmdir()
                except OSError:
                    pass

            # Move top-level directories → workbench/
            for dirname in ['dictionaries', 'voice_scripts', 'ai_assistant',
                            'web_cache', 'projects']:
                old_dir = self.user_data_path / dirname
                new_dir = wb / dirname
                if old_dir.exists() and not new_dir.exists():
                    try:
                        shutil.move(str(old_dir), str(new_dir))
                    except Exception as e:
                        print(f"[Layout] Warning: could not move {dirname}: {e}")

            flag_file.write_text(datetime.utcnow().isoformat(), encoding='utf-8')
            print("[Layout] Migration to workbench/ layout complete.")
        except Exception as e:
            print(f"[Layout] Warning: migration incomplete: {e}")

    def _load_general_settings_from_file(self) -> Dict[str, Any]:
        """Load general settings from unified settings.json (general section)"""

        defaults = {
            'restore_last_project': False,
            'auto_propagate_exact_matches': True,
            'auto_center_active_segment': True,  # Default to True (like memoQ/Trados)
            'enable_sound_effects': False,
            'sound_effects_map': {
                'glossary_term_added': 'asterisk',
                'glossary_created': 'asterisk',
                'match_inserted': 'ok',
                'glossary_term_duplicate': 'exclamation',
                'glossary_term_error': 'hand'
            },
            'grid_font_size': 11,
            'results_match_font_size': 9,
            'results_compare_font_size': 9
        }

        settings = self._load_settings_section("general")
        if not settings:
            return defaults

        # Merge with defaults to ensure all keys exist
        result = defaults.copy()
        result.update(settings)

        # Migrate termview_* → termlens_* settings keys (v1.9.347+)
        _tv_migrations = {
            'termview_under_grid_visible': 'termlens_under_grid_visible',
            'termview_font_family': 'termlens_font_family',
            'termview_font_size': 'termlens_font_size',
            'termview_font_bold': 'termlens_font_bold',
        }
        for old_key, new_key in _tv_migrations.items():
            if old_key in result and new_key not in result:
                result[new_key] = result.pop(old_key)

        return result

    def save_general_settings(self, settings: Dict[str, Any]):
        """Save general settings to unified settings.json (general section)"""
        try:
            self._save_settings_section("general", settings)
        except Exception as e:
            self.log(f"⚠ Could not save general settings: {str(e)}")

    def load_dictation_settings(self) -> Dict[str, Any]:
        """Load Voice settings"""
        defaults = {
            'model': 'base',
            'max_duration': 10,
            'language': 'Auto (use project target language)'
        }

        try:
            prefs = self._load_settings_section("ui")
            dictation = prefs.get('dictation_settings', {})
            result = defaults.copy()
            result.update(dictation)
            return result
        except:
            return defaults

    def save_dictation_settings(self, model: str, duration: int, language: str):
        """Save Voice settings"""
        # Load existing preferences to check if model changed
        all_settings = self._load_unified_settings()
        prefs = all_settings.setdefault("ui", {})
        old_model = prefs.get('dictation_settings', {}).get('model')

        # Update dictation settings
        prefs['dictation_settings'] = {
            'model': model,
            'max_duration': duration,
            'language': language
        }

        # Model download info
        model_sizes = {
            'tiny': '75 MB',
            'base': '142 MB',
            'small': '466 MB',
            'medium': '1.5 GB',
            'large': '2.9 GB'
        }

        # Save back
        try:
            self._save_unified_settings(all_settings)
            self.log(f"✓ Voice settings saved: Model={model}, Duration={duration}s")

            # Build message
            message = (
                f"Voice settings saved successfully!\n\n"
                f"Model: {model}\n"
                f"Max Duration: {duration} seconds\n"
                f"Language: {language}"
            )

            # Add download info if model changed
            if old_model != model:
                import os
                cache_path = os.path.expanduser('~/.cache/whisper')
                if os.name == 'nt':  # Windows
                    cache_path = os.path.join(os.environ.get('USERPROFILE', ''), '.cache', 'whisper')

                download_size = model_sizes.get(model, 'unknown size')
                message += (
                    f"\n\n📥 Model Download Info:\n"
                    f"If you haven't used the '{model}' model before, it will be\n"
                    f"downloaded automatically on first use ({download_size}).\n\n"
                    f"Storage location:\n{cache_path}"
                )

            QMessageBox.information(self, "Settings Saved", message)
        except Exception as e:
            self.log(f"⚠ Could not save Voice settings: {str(e)}")
            QMessageBox.warning(self, "Save Error", f"Could not save settings:\n{str(e)}")

    def _load_language_pair_from_disk(self):
        """Read just the source/target language pair from settings.json.

        This must run BEFORE the Language Pair tab UI is built, otherwise
        the combo boxes are populated from the stale hard-coded defaults
        (English / Dutch). Called early in __init__ where spellcheck and
        log may not be set up yet, so we avoid touching them here.
        """
        defaults = ('English', 'Dutch')
        try:
            prefs = self._load_settings_section("ui")
            lang_settings = prefs.get('language_settings', {}) or {}
            src = lang_settings.get('source_language') or defaults[0]
            tgt = lang_settings.get('target_language') or defaults[1]
            self.source_language = src
            self.target_language = tgt
            print(f"[LangSettings] Loaded from settings.json: {src} → {tgt}")
        except Exception as e:
            print(f"[LangSettings] Load failed, keeping defaults: {e!r}")

    # =========================================================
    # Voice dictation vocabulary biasing (v1.10.26 issue: Whisper
    # misheard "Supervertaler" as "Supervertile" / etc. – see
    # modules/voice_vocabulary.py for the full design).
    # =========================================================

    def load_voice_vocabulary_settings(self) -> Dict[str, Any]:
        """Load the user's voice-dictation vocabulary settings.

        Settings shape (stored under the ``voice_vocabulary`` key in
        the unified settings JSON):

            {
                "custom_terms": ["MyClient", "TechWord", ...],
                "replacements": [
                    {"heard": "supervertile", "meant": "Supervertaler"},
                    ...
                ],
                "use_termbase": true
            }

        The built-in defaults (modules.voice_vocabulary.DEFAULT_VOCABULARY
        and DEFAULT_REPLACEMENTS) are *always* applied on top of the
        user's settings, so brand names like "Supervertaler" are biased
        even on a fresh install with no customisation.
        """
        defaults = {
            'custom_terms': [],
            'replacements': [],
            'use_termbase': True,
        }
        try:
            section = self._load_settings_section("voice_vocabulary")
            result = defaults.copy()
            result.update(section or {})
            # Sanity-check shapes – tolerate strings that got saved as
            # JSON lists, etc. Bad entries are silently dropped.
            if not isinstance(result.get('custom_terms'), list):
                result['custom_terms'] = []
            if not isinstance(result.get('replacements'), list):
                result['replacements'] = []
            result['use_termbase'] = bool(result.get('use_termbase', True))
            return result
        except Exception as e:
            print(f"[VoiceVocab] load failed, using defaults: {e!r}")
            return defaults

    def save_voice_vocabulary_settings(self, custom_terms, replacements, use_termbase):
        """Persist the voice-dictation vocabulary settings. Replaces
        the entire ``voice_vocabulary`` section; partial updates aren't
        supported by design (the UI always writes all three fields).
        """
        try:
            self._save_settings_section("voice_vocabulary", {
                'custom_terms': [
                    str(t).strip() for t in (custom_terms or [])
                    if str(t).strip()
                ],
                'replacements': [
                    {
                        'heard': str(r.get('heard', '')).strip(),
                        'meant': str(r.get('meant', '')).strip(),
                    }
                    for r in (replacements or [])
                    if isinstance(r, dict)
                    and str(r.get('heard', '')).strip()
                    and str(r.get('meant', '')).strip()
                ],
                'use_termbase': bool(use_termbase),
            })
        except Exception as e:
            print(f"[VoiceVocab] save failed: {e!r}")

    def build_voice_initial_prompt(self) -> str:
        """Construct the Whisper ``initial_prompt`` from defaults +
        the user's custom terms + (optionally) the active project's
        termbase source-language entries.

        Called every time a new dictation surface is constructed
        (always-on listener, push-to-talk thread), so changes to
        the user's settings take effect on the next utterance
        without restarting Workbench.
        """
        settings = self.load_voice_vocabulary_settings()
        custom = settings.get('custom_terms', [])
        termbase_terms = []
        if settings.get('use_termbase', True):
            try:
                termbase_terms = self._collect_voice_dictation_termbase_terms()
            except Exception as e:
                print(f"[VoiceVocab] termbase pull failed: {e!r}")
        try:
            from modules.voice_vocabulary import build_initial_prompt
            return build_initial_prompt(
                custom_terms=custom,
                termbase_terms=termbase_terms,
            )
        except Exception as e:
            print(f"[VoiceVocab] prompt build failed: {e!r}")
            return ""

    def open_termbases_tab(self):
        """Navigate the main tab bar to the 🏷️ Termbases top tab.

        Looked up by tab text rather than a stored index so it
        survives any future re-ordering of top tabs. No-op if the
        Termbases tab isn't present (e.g. some future build that
        moves termbase management elsewhere). Returns True if we
        navigated, False if the tab wasn't found.

        Added in v1.10.31 for the voice-bias checkbox in the Voice
        tab – ticking "Also bias from your termbases" navigates here
        automatically so the user can pick which termbases to
        actually enable (the per-termbase 🎤 Voice column is opt-in
        as of v1.10.29).
        """
        if not hasattr(self, 'main_tabs'):
            return False
        for i in range(self.main_tabs.count()):
            if "Termbases" in self.main_tabs.tabText(i):
                self.main_tabs.setCurrentIndex(i)
                return True
        return False

    def _migrate_voice_dictation_default_off(self):
        """One-shot reset: clear every termbase's
        ``voice_dictation_enabled`` flag so the v1.10.29 opt-in
        default takes effect for users who upgraded from v1.10.28
        (where the flag was added with DEFAULT 1, populating every
        existing termbase as voice-enabled).

        Runs at most once per database, gated by a sentinel in the
        unified settings JSON. The user's manual selections after
        v1.10.29 are not touched – the sentinel is set the first
        time this method runs, and on every subsequent launch the
        method returns immediately.

        Skipped silently on any error; the worst that happens is
        the user sees their old v1.10.28 defaults persist and has
        to untick the 🎤 Voice column manually, which is the same
        UX they'd get without this migration.
        """
        try:
            prefs = self._load_settings_section("ui")
            if prefs.get("voice_dictation_opt_in_reset_applied"):
                return  # already migrated
            cursor = self.db_manager.cursor
            cursor.execute(
                "UPDATE termbases SET voice_dictation_enabled = 0"
            )
            self.db_manager.connection.commit()
            prefs["voice_dictation_opt_in_reset_applied"] = True
            self._save_settings_section("ui", prefs)
            self.log(
                "✓ Voice-dictation termbase flags reset to opt-in (v1.10.29 migration)"
            )
        except Exception as e:
            print(f"[VoiceVocab] opt-in reset migration error: {e!r}")

    def _collect_voice_dictation_termbase_terms(self) -> list:
        """Return the **target-language** ``target_term`` values of
        every term in every termbase whose **voice-dictation flag**
        is on. The list is used by ``build_voice_initial_prompt()``
        as additional vocabulary biasing for Whisper.

        Why target, not source: translators dictate the *target* side
        (the language they're producing). An EN→NL translator
        dictating Dutch needs Whisper to know Dutch terminology, not
        the English originals.

        Why no project filter: this used to require an open Workbench
        project (it called ``get_active_termbase_ids(project_id)``),
        which meant the feature silently did nothing when the user
        had Workbench open as a companion utility alongside their
        translation in Trados – the typical case. v1.10.28 swapped
        the per-project read/write activation for a separate
        per-termbase voice-dictation flag (column ``🎤 Voice`` in
        Termbase Manager) which is independent of project context.

        Best-effort: any database / API error is caught and turned
        into an empty list so it can never break dictation.
        """
        if not hasattr(self, 'termbase_mgr') or not self.termbase_mgr:
            return []
        try:
            voice_ids = self.termbase_mgr.get_voice_enabled_termbase_ids() or []
        except Exception:
            return []
        out = []
        seen = set()
        for tb_id in voice_ids:
            try:
                terms = self.termbase_mgr.get_terms(tb_id) or []
            except Exception:
                continue
            for entry in terms:
                # Target-language column (what the translator dictates).
                tgt = (entry.get('target_term') or '').strip()
                if not tgt:
                    continue
                key = tgt.lower()
                if key in seen:
                    continue
                seen.add(key)
                out.append(tgt)
                # Cap to keep the prompt from ballooning past Whisper's
                # token budget. build_initial_prompt() trims further
                # if needed, but it's cheaper to cap here.
                if len(out) >= 200:
                    return out
        return out

    def load_language_settings(self):
        """Initialize spellcheck based on the already-loaded target language.

        The source/target pair itself is loaded earlier by
        _load_language_pair_from_disk() so the UI sees the right values.
        This method now handles only the spellcheck side-effects that
        depend on self.spellcheck_manager and self.log existing.
        """
        try:
            prefs = self._load_settings_section("ui")
            spellcheck_settings = prefs.get('spellcheck_settings', {}) or {}
            self.spellcheck_enabled = spellcheck_settings.get('enabled', False)
            TagHighlighter.set_spellcheck_enabled(self.spellcheck_enabled)

            if self.spellcheck_manager and self.spellcheck_enabled:
                if self.spellcheck_manager.set_language(self.target_language):
                    self.log(f"✓ Spellcheck initialized for {self.target_language}")
                else:
                    self.log(f"⚠ Spellcheck dictionary not available for {self.target_language}")
        except Exception as e:
            print(f"[LangSettings] Spellcheck init failed: {e!r}")

    def save_language_settings(self, source_lang: str, target_lang: str):
        """Save language settings to preferences"""
        try:
            all_settings = self._load_unified_settings()
            all_settings.setdefault("ui", {})['language_settings'] = {
                'source_language': source_lang,
                'target_language': target_lang
            }
            self._save_unified_settings(all_settings)
        except Exception as e:
            self.log(f"⚠ Could not save language settings: {str(e)}")
    
    def _save_language_settings_from_ui(self, source_combo, target_combo):
        """Save language settings from UI"""
        self.source_language = source_combo.currentText()
        self.target_language = target_combo.currentText()
        self.save_language_settings(self.source_language, self.target_language)
        
        self.log(f"✓ Language settings saved: {self.source_language} → {self.target_language}")
        QMessageBox.information(self, "Settings Saved", 
                              f"Language settings have been saved:\n\n"
                              f"Source: {self.source_language}\n"
                              f"Target: {self.target_language}")
    
    def load_font_sizes_from_preferences(self):
        """Load and apply font sizes from preferences on startup"""
        try:
            general_settings = self.load_general_settings()
            
            # Load grid font family
            font_family = general_settings.get('grid_font_family', 'Calibri')
            if font_family:
                self.default_font_family = font_family
            
            # Load grid font size
            grid_size = general_settings.get('grid_font_size', 11)
            if 7 <= grid_size <= 72:
                self.default_font_size = grid_size
            
            # Apply font to grid if it exists
            if hasattr(self, 'table') and self.table is not None:
                self.apply_font_to_grid()
            
            # Load results pane font sizes
            match_size = general_settings.get('results_match_font_size', 9)
            compare_size = general_settings.get('results_compare_font_size', 9)
            show_tags = general_settings.get('results_show_tags', False)
            
            # Apply to all results panels
            if hasattr(self, 'results_panels'):
                if 7 <= match_size <= 16:
                    from modules.translation_results_panel import CompactMatchItem
                    CompactMatchItem.set_font_size(match_size)
                    for panel in self.results_panels:
                        if hasattr(panel, 'set_font_size'):
                            panel.set_font_size(match_size)
                
                if 7 <= compare_size <= 14:
                    from modules.translation_results_panel import TranslationResultsPanel
                    TranslationResultsPanel.compare_box_font_size = compare_size
                    for panel in self.results_panels:
                        if hasattr(panel, 'set_compare_box_font_size'):
                            panel.set_compare_box_font_size(compare_size)
                
                # Apply show_tags setting
                from modules.translation_results_panel import CompactMatchItem
                CompactMatchItem.show_tags = show_tags
                for panel in self.results_panels:
                    if hasattr(panel, 'set_show_tags'):
                        panel.set_show_tags(show_tags)
                
                # Load and apply tag color
                tag_color = general_settings.get('tag_highlight_color', '#7f0001')
                EditableGridTextEditor.tag_highlight_color = tag_color
                ReadOnlyGridTextEditor.tag_highlight_color = tag_color
                CompactMatchItem.tag_highlight_color = tag_color
                for panel in self.results_panels:
                    if hasattr(panel, 'set_tag_color'):
                        panel.set_tag_color(tag_color)
                
                # Load and apply badge text color
                badge_text_color = general_settings.get('badge_text_color', '#333333')
                CompactMatchItem.badge_text_color = badge_text_color
                
                # Load and apply focus border settings
                focus_border_color = general_settings.get('focus_border_color', '#f1b79a')
                focus_border_thickness = general_settings.get('focus_border_thickness', 2)
                EditableGridTextEditor.focus_border_color = focus_border_color
                EditableGridTextEditor.focus_border_thickness = focus_border_thickness
                
            # Load and apply Match Panel font settings
            match_panel_size = general_settings.get('match_panel_font_size', 10)
            if 7 <= match_panel_size <= 18:
                SupervertalerQt.match_panel_font_size = match_panel_size
            SupervertalerQt.match_panel_font_family = general_settings.get('match_panel_font_family', '')
            SupervertalerQt.match_panel_font_bold = general_settings.get('match_panel_font_bold', False)
            self._apply_match_panel_font_size()
                
            if hasattr(self, 'results_panels'):
                # Load and apply match limits
                match_limits = general_settings.get('match_limits', {
                    'LLM': 3,
                    'MT': 3,
                    'TM': 5,
                    'Termbases': 10
                })
                for panel in self.results_panels:
                    panel.match_limits = match_limits
                    
        except Exception as e:
            self.log(f"⚠ Could not load font sizes: {e}")
    
    def _init_usage_statistics(self):
        """Show opt-in dialog (once) and send anonymous usage ping if opted in."""
        try:
            from modules.usage_statistics import (
                has_been_asked, show_opt_in_dialog, set_opted_in, send_ping
            )
            settings_path = self._get_unified_settings_path()

            # Show opt-in dialog once (first launch or after update that adds this)
            if not has_been_asked(settings_path):
                opted_in = show_opt_in_dialog(self)
                set_opted_in(settings_path, opted_in)
                if opted_in:
                    self.log("📊 Usage statistics enabled – thank you!")
                else:
                    self.log("📊 Usage statistics declined – no data will be sent.")

            # Send anonymous ping in background (only if opted in)
            send_ping(settings_path, __version__)

        except Exception:
            # Never let stats code block startup
            pass

    def restore_last_project_if_enabled(self):
        """Restore the last opened project on startup if the setting is enabled"""
        try:
            # Check if setting is enabled
            general_settings = self.load_general_settings()
            if not general_settings.get('restore_last_project', False):
                return
            
            # Get recent projects
            recent_projects = self.load_recent_projects()
            if not recent_projects:
                return
            
            # Get the most recent project (first in the list)
            # Recent projects are sorted by most recent first
            last_project = recent_projects[0]
            project_path = last_project.get('path') if isinstance(last_project, dict) else last_project
            
            # Verify file exists
            if not project_path or not os.path.exists(project_path):
                self.log(f"⚠ Last project file not found: {project_path}")
                return
            
            # Load the project
            self.log(f"🔄 Restoring last project: {Path(project_path).name}")
            self.load_project(project_path)
            
        except Exception as e:
            # Silently fail - don't block startup if restoration fails
            self.log(f"⚠ Could not restore last project: {e}")
    
    
    def get_status_icon(self, status: str) -> str:
        """Get status icon for display"""
        return get_status(status).icon
    
    def _handle_target_text_debounced_by_id(self, segment_id, new_text):
        """
        Handle expensive target text change operations after user stops typing.
        Called 500ms after last keystroke to avoid UI lag.
        Uses segment ID to find the correct segment (not row index).
        """
        try:
            # Find segment by ID
            segment = next((seg for seg in self.current_project.segments if seg.id == segment_id), None)
            if not segment:
                return
            
            # Find current row for this segment
            row = next((i for i, seg in enumerate(self.current_project.segments) if seg.id == segment_id), None)
            if row is None:
                return
            
            # Note: Status is now set to "not_started" immediately on edit (in on_target_text_changed)
            # User must manually confirm/approve to change status to translated/confirmed
            
            # Update window title
            self.update_window_title()
            
            # Auto-resize only this row (fast, single-row operation)
            self._auto_resize_single_row(row)
            
            # Save to TM ONLY if segment is confirmed (user explicitly approved)
            # Do NOT save for 'draft' status - that's just machine/batch translated
            if segment.status == 'confirmed' and new_text.strip():
                try:
                    self.save_segment_to_activated_tms(segment.source, new_text)
                except Exception as e:
                    self.log(f"Warning: Could not save to TM: {e}")
            
            # Update status bar progress stats (debounced - only after user stops typing)
            self.update_progress_stats()
            
            # 🚀 IDLE PREFETCH: User stopped typing, prefetch next segments for instant Ctrl+Enter
            self._trigger_idle_prefetch(row)
            
        except Exception as e:
            self.log(f"Error in debounced target handler: {e}")
    
    def update_status_icon(self, row: int, status: str):
        """Update status icon for a specific row"""
        if not self.current_project or row >= len(self.current_project.segments):
            return
        segment = self.current_project.segments[row]
        old_status = segment.status
        old_target = segment.target
        segment.status = status
        
        # Record undo state for status change
        self.record_undo_state(segment.id, old_target, segment.target, old_status, status)
        
        self._refresh_segment_status(segment)
        
        # Save to TM ONLY if status changed to confirmed (user explicitly approved)
        # Do NOT save for 'draft' or 'approved' status - user must confirm first
        find_replace_active = getattr(self, 'find_replace_active', False)
        if not find_replace_active and status == 'confirmed' and segment.target.strip():
            try:
                self.save_segment_to_activated_tms(segment.source, segment.target)
            except Exception as e:
                self.log(f"Warning: Could not save to TM: {e}")
    
    def on_cell_changed(self, item: QTableWidgetItem):
        """Handle cell content changes - now mainly for placeholder items"""
        # Target cell changes are handled by the EditableGridTextEditor's textChanged signal
        # This method is kept for compatibility but should rarely be called now
        # Placeholder items (columns 2 and 3) are non-interactive, so this shouldn't trigger
        pass
    
    def on_cell_selected(self, current_row, current_col, previous_row, previous_col):
        """Handle cell selection change"""
        if self.debug_mode_enabled:
            self.log(f"🎯 on_cell_selected called: row {current_row}, col {current_col}")

        # 🚫 GUARD: Don't re-run lookups if we're staying on the same row
        # This prevents lookups when user edits text (focus changes within same row)
        if hasattr(self, '_last_selected_row') and self._last_selected_row == current_row:
            if self.debug_mode_enabled:
                self.log(f"⏭️ Skipping lookup - already on row {current_row}")
            return
        self._last_selected_row = current_row

        # ⚡ FAST PATH: Defer heavy lookups for ALL navigation (arrow keys, Ctrl+Enter, AND mouse clicks)
        # This makes segment navigation feel INSTANT - cursor moves first, lookups happen after
        # Reset any navigation flags
        self._arrow_key_navigation = False
        self._ctrl_enter_navigation = False

        # In filtered mode, use a longer debounce so rapid navigation stays snappy
        # but settling on a segment still triggers TM/MT/LLM lookups
        is_filtering = getattr(self, 'filtering_active', False)
        debounce_ms = 250 if is_filtering else 10

        # Schedule deferred lookup with short delay - debounce prevents hammering during rapid navigation
        if hasattr(self, '_deferred_lookup_timer') and self._deferred_lookup_timer:
            self._deferred_lookup_timer.stop()
        from PyQt6.QtCore import QTimer
        self._deferred_lookup_timer = QTimer()
        self._deferred_lookup_timer.setSingleShot(True)
        self._deferred_lookup_timer.timeout.connect(
            lambda r=current_row, c=current_col, pr=previous_row, pc=previous_col:
            self._on_cell_selected_full(r, c, pr, pc)
        )
        self._deferred_lookup_timer.start(debounce_ms)

        # Do minimal UI update immediately (orange highlight, scroll)
        self._on_cell_selected_minimal(current_row, previous_row)

        # In filtered mode, also update glossary highlights from cache (cheap)
        if is_filtering:
            self._on_cell_selected_glossary_only(current_row)
    
    def _center_row_in_viewport(self, row: int):
        """Center the given row vertically in the visible table viewport.
        
        Uses Qt's built-in scrollTo() with PositionAtCenter hint.
        """
        if row < 0 or row >= self.table.rowCount():
            return
        
        # Get the model index for any cell in this row (use column 0)
        index = self.table.model().index(row, 0)
        if index.isValid():
            # Use Qt's built-in centering - PositionAtCenter puts the item in the center of the viewport
            self.table.scrollTo(index, QAbstractItemView.ScrollHint.PositionAtCenter)
    
    def _on_cell_selected_minimal(self, current_row, previous_row):
        """Minimal UI update for fast arrow key navigation - just highlight and scroll"""
        try:
            # Clear previous highlighting
            if previous_row >= 0 and previous_row < self.table.rowCount():
                prev_id_item = self.table.item(previous_row, 0)
                if prev_id_item:
                    prev_id_item.setBackground(QBrush())
                    theme = self.theme_manager.current_theme
                    segment_num_color = "black" if theme.name in ["Light (Default)", "Soft Gray", "Warm Cream", "Sepia", "High Contrast"] else theme.text
                    prev_id_item.setForeground(QBrush(QColor(segment_num_color)))

            # Highlight current segment number in orange
            if current_row >= 0 and current_row < self.table.rowCount():
                current_id_item = self.table.item(current_row, 0)
                if current_id_item:
                    current_id_item.setBackground(QColor("#FFA500"))
                    current_id_item.setForeground(QColor("white"))
                
                # Auto-center if enabled
                if getattr(self, 'auto_center_active_segment', False) and not getattr(self, 'filtering_active', False):
                    self._center_row_in_viewport(current_row)
        except Exception as e:
            if self.debug_mode_enabled:
                self.log(f"Error in minimal cell selection: {e}")

    def _on_cell_selected_glossary_only(self, current_row):
        """Update glossary highlights and TermLens from cache when in filtered mode.
        Skips TM/MT/LLM lookups - only handles cheap, cache-based termbase operations."""
        try:
            if not self.current_project or current_row < 0:
                return

            id_item = self.table.item(current_row, 0)
            if not id_item:
                return
            try:
                segment_id = int(id_item.text())
            except (ValueError, AttributeError):
                return

            segment = next((seg for seg in self.current_project.segments if seg.id == segment_id), None)
            if not segment:
                return

            # --- Termbase grid highlighting (from cache) ---
            if self.enable_termbase_grid_highlighting:
                tb_dict = {}
                with self.termbase_cache_lock:
                    tb_dict = self.termbase_cache.get(segment_id, {})

                if not tb_dict:
                    # Fall back to translation_matches_cache
                    with self.translation_matches_cache_lock:
                        cached_matches = self.translation_matches_cache.get(segment_id)
                    if cached_matches:
                        cached_tb = cached_matches.get("Termbases", [])
                        if cached_tb:
                            for match in cached_tb:
                                term_id = match.metadata.get('term_id') if match.metadata else None
                                key = term_id if term_id is not None else match.source
                                tb_dict[key] = {
                                    'source': match.source,
                                    'translation': match.target,
                                    'ranking': match.metadata.get('ranking', 0) if match.metadata else 0,
                                    'is_project_termbase': match.metadata.get('is_project_termbase', False) if match.metadata else False,
                                    'forbidden': match.metadata.get('forbidden', False) if match.metadata else False,
                                    'termbase_name': match.metadata.get('termbase_name', '') if match.metadata else '',
                                    'notes': match.metadata.get('notes', '') if match.metadata else '',
                                    'term_id': term_id,
                                    'termbase_id': match.metadata.get('termbase_id') if match.metadata else None,
                                }
                            if tb_dict:
                                with self.termbase_cache_lock:
                                    self.termbase_cache[segment_id] = tb_dict

                if tb_dict:
                    self.highlight_source_with_termbase(current_row, segment.source, tb_dict)
                else:
                    # No cached matches – do a fresh (cheap) termbase-only lookup
                    fresh_tb = self.find_termbase_matches_in_source(segment.source)
                    if fresh_tb:
                        self.highlight_source_with_termbase(current_row, segment.source, fresh_tb)

            # --- TermLens pane update ---
            if self.current_project and (
                (hasattr(self, 'termlens_widget') and self.termlens_widget) or
                (hasattr(self, 'termlens_widget_match') and self.termlens_widget_match)
            ):
                termbase_matches = []
                with self.translation_matches_cache_lock:
                    tv_cached = self.translation_matches_cache.get(segment_id)
                if tv_cached:
                    termbase_matches = [
                        {
                            'source_term': match.source,
                            'target_term': match.target,
                            'termbase_name': match.metadata.get('termbase_name', '') if match.metadata else '',
                            'ranking': match.metadata.get('ranking', 0) if match.metadata else 0,
                            'is_project_termbase': match.metadata.get('is_project_termbase', False) if match.metadata else False,
                            'term_id': match.metadata.get('term_id') if match.metadata else None,
                            'termbase_id': match.metadata.get('termbase_id') if match.metadata else None,
                            'notes': match.metadata.get('notes', '') if match.metadata else ''
                        }
                        for match in tv_cached.get("Termbases", [])
                    ]

                nt_matches = self.find_nt_matches_in_source(segment.source)
                status_hint = self._get_termbase_status_hint()
                self._update_both_termlens(segment.source, termbase_matches, nt_matches, status_hint)
        except Exception as e:
            if self.debug_mode_enabled:
                self.log(f"Error in glossary-only cell selection: {e}")

    def _pcs(self, label: str):
        """Context manager that logs elapsed time for a named block during
        cell-selection. Always active – the timer itself is cheap, and we
        only call self.log() when a block exceeds 50 ms, so normal fast
        clicks produce no log output. Used to pinpoint which lookups in
        `_on_cell_selected_full` are responsible for the multi-second UI
        freezes that some users hit after clicking a segment.
        """
        from contextlib import contextmanager
        import time as _t

        @contextmanager
        def _timer():
            t0 = _t.perf_counter()
            try:
                yield
            finally:
                elapsed_ms = (_t.perf_counter() - t0) * 1000.0
                if elapsed_ms > 50.0:
                    self.log(f"⏱️ [cell-select] {label}: {elapsed_ms:.1f} ms")

        return _timer()

    def _on_cell_selected_full(self, current_row, current_col, previous_row, previous_col):
        """Full cell selection handler with lookups and highlighting"""
        # Top-level stopwatch – any total over ~250 ms is logged so the
        # multi-second freezes that some users hit show up in the log
        # without needing debug mode enabled. Fine-grained `self._pcs("…")`
        # blocks below show which step ate the time.
        import time as _profile_time
        _profile_t0 = _profile_time.perf_counter()

        # Clear text selections in previous row's source and target cells
        if previous_row >= 0 and previous_row < self.table.rowCount():
            # Clear source cell selection (column 2)
            source_widget = self.table.cellWidget(previous_row, 2)
            if source_widget and hasattr(source_widget, 'textCursor'):
                cursor = source_widget.textCursor()
                cursor.clearSelection()
                source_widget.setTextCursor(cursor)
            
            # Clear target cell selection (column 3)
            target_widget = self.table.cellWidget(previous_row, 3)
            if target_widget and hasattr(target_widget, 'textCursor'):
                cursor = target_widget.textCursor()
                cursor.clearSelection()
                target_widget.setTextCursor(cursor)
        
        # DEBUG: Also log all connected signals for this table (only in debug mode)
        if self.debug_mode_enabled:
            self.log(f"🔗 Table currentCellChanged signal connected: {self.table.currentCellChanged}")
            self.log(f"🔗 Table itemClicked signal connected: {self.table.itemClicked}")
            self.log(f"🔗 Table itemSelectionChanged signal connected: {self.table.itemSelectionChanged}")
        try:
            # Update segment number highlighting (orange = active)
            if previous_row >= 0 and previous_row < self.table.rowCount():
                prev_id_item = self.table.item(previous_row, 0)
                if prev_id_item:
                    prev_id_item.setBackground(QBrush())
                    theme = self.theme_manager.current_theme
                    segment_num_color = "black" if theme.name in ["Light (Default)", "Soft Gray", "Warm Cream", "Sepia", "High Contrast"] else theme.text
                    prev_id_item.setForeground(QBrush(QColor(segment_num_color)))

            if current_row >= 0 and current_row < self.table.rowCount():
                current_id_item = self.table.item(current_row, 0)
                if current_id_item:
                    current_id_item.setBackground(QColor("#FFA500"))
                    current_id_item.setForeground(QColor("white"))
                
                if getattr(self, 'auto_center_active_segment', False) and not getattr(self, 'filtering_active', False):
                    self._center_row_in_viewport(current_row)
            
            if not self.current_project or current_row < 0:
                return
            
            if current_row < len(self.current_project.segments):
                # CRITICAL: Get segment by ID from the grid, not by row index!
                # The row index might not match the segment's position in the list
                id_item = self.table.item(current_row, 0)
                if not id_item:
                    self.log(f"⚠️ No ID item found at row {current_row}")
                    return
                
                # Get segment ID from the grid cell
                try:
                    segment_id = int(id_item.text())
                except (ValueError, AttributeError):
                    self.log(f"⚠️ Could not parse segment ID from cell at row {current_row}")
                    return
                
                # Find the segment by ID in the project's segment list
                segment = next((seg for seg in self.current_project.segments if seg.id == segment_id), None)
                if not segment:
                    self.log(f"⚠️ Could not find segment with ID {segment_id} in project")
                    return
                
                # If segment has a batch TM match, display it in the Match Panel immediately
                batch_match = getattr(segment, '_batch_tm_match', None)
                if batch_match:
                    search_source = segment.source
                    if self.hide_outer_wrapping_tags:
                        search_source, _ = strip_outer_wrapping_tags(search_source)
                    tm_matches = [{
                        'source': batch_match.get('source', search_source),
                        'target': batch_match.get('target', ''),
                        'tm_name': batch_match.get('tm_name', 'TM'),
                        'tm_id': batch_match.get('tm_id', ''),
                        'match_pct': batch_match.get('match_pct', 100),
                        # v1.10.50: surface reverse-match info so the Match
                        # Panel can show a "⇄ reversed" chip.
                        'reverse_match': batch_match.get('reverse_match', False),
                    }]
                    self.set_compare_panel_matches(segment.id, search_source, tm_matches, [])

                # Update Preview panel - scroll to and highlight this segment
                self._scroll_preview_to_segment(segment_id)

                # Update Translation Results panel header with segment info
                if hasattr(self, 'results_panels'):
                    for panel in self.results_panels:
                        try:
                            panel.set_segment_info(segment.id, segment.source)
                        except Exception as e:
                            self.log(f"Error updating Translation Results panel header: {e}")
                
                # Update toolbar segment info and status
                if hasattr(self, 'tab_seg_info'):
                    try:
                        self.tab_seg_info.setText(f"Segment {segment.id}")
                        
                        # Update status combo if it exists
                        if hasattr(self, 'tab_status_combo'):
                            from modules.statuses import STATUSES
                            idx = -1
                            for i in range(self.tab_status_combo.count()):
                                if self.tab_status_combo.itemData(i) == segment.status:
                                    idx = i
                                    break
                            if idx >= 0:
                                self.tab_status_combo.blockSignals(True)
                                self.tab_status_combo.setCurrentIndex(idx)
                                self.tab_status_combo.blockSignals(False)
                    except Exception as e:
                        self.log(f"Error updating toolbar: {e}")
                
                # Update Translation Results panel notes
                if hasattr(self, 'translation_results_panel') and self.translation_results_panel:
                    try:
                        notes_text = segment.notes if segment.notes else ""
                        self.translation_results_panel.notes_edit.blockSignals(True)
                        self.translation_results_panel.notes_edit.setPlainText(notes_text)
                        self.translation_results_panel.notes_edit.blockSignals(False)
                    except Exception as e:
                        self.log(f"Error updating notes in Translation Results panel: {e}")
                
                # Update bottom Notes tab with segment notes
                self._update_bottom_notes_for_segment(segment)
                # Update Proofreading note tab
                self._update_proofreading_notes_for_segment(segment)

                # Update legacy tabbed panels (if they exist for other views)
                if hasattr(self, 'update_tab_segment_editor'):
                    self.update_tab_segment_editor(
                        segment_id=segment.id,
                        source_text=segment.source,
                        target_text=segment.target,
                        status=segment.status,
                        notes=segment.notes
                    )
                
                # ⚡ PERFORMANCE: Skip heavy lookups if Preview tab is open
                # User is likely just reading/reviewing, not actively translating
                if self._is_preview_tab_active():
                    if self.debug_mode_enabled:
                        self.log(f"⏭️ Preview tab active - skipping TM/Termbase lookups for segment {segment.id}")
                    return
                
                # Get termbase matches (from cache or search on-demand) - ONLY if enabled
                matches_dict = None  # Initialize at the top level
                cached_matches = None  # Initialize for cache skip path

                # 🧪 EXPERIMENTAL: Skip ALL cache checks if cache kill switch is enabled
                if not getattr(self, 'disable_all_caches', False):
                    # 🚀 CHECK PREFETCH CACHE FIRST for instant display (like memoQ)
                    segment_id = segment.id
                    with self.translation_matches_cache_lock:
                        if segment_id in self.translation_matches_cache:
                            cached_matches = self.translation_matches_cache[segment_id]
                            
                            # Count matches in each category
                            tm_count = len(cached_matches.get("TM", []))
                            tb_count = len(cached_matches.get("Termbases", []))
                            mt_count = len(cached_matches.get("MT", []))
                            llm_count = len(cached_matches.get("LLM", []))
                            
                            self.log(f"⚡ CACHE HIT for segment {segment_id}: TM={tm_count}, TB={tb_count}, MT={mt_count}, LLM={llm_count}")
                else:
                    if self.debug_mode_enabled:
                        self.log(f"🧪 Cache DISABLED - forcing fresh lookup for segment {segment.id}")
                
                # Process cached matches if we have them
                if cached_matches is not None:
                    # Display cached matches immediately
                    if hasattr(self, 'results_panels'):
                        for panel in self.results_panels:
                            try:
                                panel.clear()
                                panel.set_matches(cached_matches)
                            except Exception as e:
                                self.log(f"Error displaying cached matches: {e}")
                    
                    # 🔄 Update TermLens with cached termbase matches (always update, even if empty)
                    if self.current_project and ((hasattr(self, 'termlens_widget') and self.termlens_widget) or (hasattr(self, 'termlens_widget_match') and self.termlens_widget_match)):
                        try:
                            # Convert TranslationMatch objects to dict format for termlens
                            termbase_matches = [
                                {
                                    'source_term': match.source,
                                    'target_term': match.target,
                                    'termbase_name': match.metadata.get('termbase_name', '') if match.metadata else '',
                                    'ranking': match.metadata.get('ranking', 0) if match.metadata else 0,
                                    'is_project_termbase': match.metadata.get('is_project_termbase', False) if match.metadata else False,
                                    'term_id': match.metadata.get('term_id') if match.metadata else None,
                                    'termbase_id': match.metadata.get('termbase_id') if match.metadata else None,
                                    'notes': match.metadata.get('notes', '') if match.metadata else ''
                                }
                                for match in cached_matches.get("Termbases", [])
                            ]
                            # Also get NT matches (fresh, not cached - they may have changed)
                            with self._pcs("find_nt_matches_in_source (cache-hit)"):
                                nt_matches = self.find_nt_matches_in_source(segment.source)

                            # Get status hint for termbase activation
                            with self._pcs("_get_termbase_status_hint (cache-hit)"):
                                status_hint = self._get_termbase_status_hint()

                            # Update both TermLens widgets (left and right)
                            with self._pcs("_update_both_termlens (cache-hit)"):
                                self._update_both_termlens(segment.source, termbase_matches, nt_matches, status_hint)
                        except Exception as e:
                            self.log(f"Error updating termlens from cache: {e}")
                    
                    # 🎯 AUTO-INSERT 100% TM MATCH from cache (if enabled in settings)
                    tm_count = len(cached_matches.get("TM", []))
                    if self.auto_insert_100_percent_matches and tm_count > 0:
                        # Check if segment target is empty (don't overwrite existing translations)
                        target_empty = not segment.target or len(segment.target.strip()) == 0
                        
                        if target_empty:
                            # Find first 100% match in cached TM results
                            best_match = None
                            for tm_match in cached_matches.get("TM", []):
                                # Use >= 99.5 to handle potential floating point issues
                                if float(tm_match.relevance) >= 99.5:
                                    best_match = tm_match
                                    break
                            
                            if best_match:
                                self.log(f"✨ Auto-inserting 100% TM match into segment {segment.id}")
                                self._auto_insert_tm_match(segment, best_match.target, current_row)
                                # Play 100% TM match alert sound
                                self._play_sound_effect('tm_100_percent_match')
                    
                    # 🔊 Play fuzzy match sound if fuzzy matches found from cache (but not 100%)
                    if tm_count > 0:
                        tm_matches = cached_matches.get("TM", [])
                        has_100_match = any(float(tm.relevance) >= 99.5 for tm in tm_matches)
                        has_fuzzy_match = any(float(tm.relevance) < 99.5 and float(tm.relevance) >= 50 for tm in tm_matches)
                        if has_fuzzy_match and not has_100_match:
                            self._play_sound_effect('tm_fuzzy_match')
                    
                    # Highlight termbase matches in source cell (from termbase_cache, dict format)
                    if self.enable_termbase_grid_highlighting:
                        with self.termbase_cache_lock:
                            tb_dict = self.termbase_cache.get(segment_id, {})
                        if not tb_dict:
                            # termbase_cache may be empty if prefetch ran before batch worker,
                            # or after termbase_cache was cleared. Fall back to the TB matches
                            # already in translation_matches_cache (cached_matches["Termbases"]).
                            cached_tb_matches = cached_matches.get("Termbases", [])
                            if cached_tb_matches:
                                tb_dict = {}
                                for match in cached_tb_matches:
                                    term_id = match.metadata.get('term_id') if match.metadata else None
                                    key = term_id if term_id is not None else match.source
                                    tb_dict[key] = {
                                        'source': match.source,
                                        'translation': match.target,
                                        'ranking': match.metadata.get('ranking', 0) if match.metadata else 0,
                                        'is_project_termbase': match.metadata.get('is_project_termbase', False) if match.metadata else False,
                                        'forbidden': match.metadata.get('forbidden', False) if match.metadata else False,
                                        'termbase_name': match.metadata.get('termbase_name', '') if match.metadata else '',
                                        'notes': match.metadata.get('notes', '') if match.metadata else '',
                                        'term_id': term_id,
                                        'termbase_id': match.metadata.get('termbase_id') if match.metadata else None,
                                    }
                                # Backfill termbase_cache so future navigations don't need this fallback
                                if tb_dict:
                                    with self.termbase_cache_lock:
                                        self.termbase_cache[segment_id] = tb_dict
                        if tb_dict:
                            with self._pcs("highlight_source_with_termbase (cache-hit)"):
                                self.highlight_source_with_termbase(current_row, segment.source, tb_dict)

                    # Skip the slow TERMBASE lookup below, we already have termbase matches cached
                    # But TM lookup was skipped in prefetch (not thread-safe), so schedule it now
                    matches_dict = cached_matches  # Set for later use

                    # v1.9.182: Schedule TM lookup even on cache hit (prefetch skips TM - not thread-safe)
                    # v1.9.261: Skip if segment already has batch TM match data from pre-translation
                    tm_count = len(cached_matches.get("TM", []))
                    has_batch_match = getattr(segment, '_batch_tm_match', None)

                    # v1.9.273: Update Match Panel from cached TM matches (fixes #164)
                    # On revisit, tm_count > 0 so _schedule_mt_and_llm_matches is skipped,
                    # but the Match Panel still needs to be updated with cached TM results.
                    if tm_count > 0:
                        tm_matches_for_panel = []
                        for tm in cached_matches.get("TM", []):
                            tm_name = tm.metadata.get('tm_name', 'TM') if tm.metadata else 'TM'
                            tm_id = tm.metadata.get('tm_id', '') if tm.metadata else ''
                            # v1.10.51: read reverse_match from the
                            # TranslationMatch's metadata so the chip
                            # survives the cache-hit re-render path too.
                            rev = bool(tm.metadata.get('reverse_match', False)) if tm.metadata else False
                            tm_matches_for_panel.append({
                                'source': tm.compare_source or tm.source,
                                'target': tm.target,
                                'tm_name': tm_name,
                                'tm_id': tm_id,
                                'match_pct': int(tm.relevance),
                                'reverse_match': rev,
                            })
                        self.set_compare_panel_matches(
                            segment_id,
                            segment.source,
                            tm_matches=tm_matches_for_panel,
                            mt_matches=getattr(self, '_compare_panel_mt_matches', [])
                        )

                    if tm_count == 0 and self.enable_tm_matching and not has_batch_match:
                        find_replace_active = getattr(self, 'find_replace_active', False)
                        if not find_replace_active:
                            # Get termbase matches for the lookup
                            termbase_matches_for_tm = [
                                {
                                    'source_term': match.source,
                                    'target_term': match.target,
                                    'termbase_name': match.metadata.get('termbase_name', '') if match.metadata else '',
                                }
                                for match in cached_matches.get("Termbases", [])
                            ]
                            self._schedule_mt_and_llm_matches(segment, termbase_matches_for_tm)
                
                # Check if TM/Termbase matching is enabled
                if not matches_dict and (not self.enable_tm_matching and not self.enable_termbase_matching):
                    self.log("⏭️ TM/Termbase matching disabled - skipping all lookups")
                elif not matches_dict:  # Only do slow lookup if cache missed
                    try:
                        source_widget = self.table.cellWidget(current_row, 2)  # Source column is column 2

                        # Termbase lookup (if enabled)
                        stored_matches = {}
                        if self.enable_termbase_matching:
                            # 🧪 EXPERIMENTAL: Skip termbase cache if cache kill switch is enabled
                            cache_checked = False
                            if not getattr(self, 'disable_all_caches', False):
                                # Check cache first (thread-safe) - uses `in` check to properly handle empty caches
                                with self.termbase_cache_lock:
                                    if segment_id in self.termbase_cache:
                                        stored_matches = self.termbase_cache[segment_id]
                                        cache_checked = True
                            
                            if not cache_checked and source_widget:
                                with self._pcs("find_termbase_matches_in_source"):
                                    stored_matches = self.find_termbase_matches_in_source(segment.source)

                                # Store in cache for future access (thread-safe) - EVEN IF EMPTY
                                # BUT skip cache storage if cache kill switch is enabled
                                if not getattr(self, 'disable_all_caches', False):
                                    with self.termbase_cache_lock:
                                        self.termbase_cache[segment_id] = stored_matches
                            
                            # CRITICAL FIX: Always update TermLens (even with empty results) - show "No matches" state
                            if self.current_project and ((hasattr(self, 'termlens_widget') and self.termlens_widget) or (hasattr(self, 'termlens_widget_match') and self.termlens_widget_match)):
                                try:
                                    # Convert dict format to list format
                                    termbase_matches = [
                                        {
                                            'source_term': match_data.get('source', ''),
                                            'target_term': match_data.get('translation', ''),
                                            'termbase_name': match_data.get('termbase_name', ''),
                                            'ranking': match_data.get('ranking', 0),
                                            'is_project_termbase': match_data.get('is_project_termbase', False),
                                            'term_id': match_data.get('term_id'),
                                            'termbase_id': match_data.get('termbase_id'),
                                            'notes': match_data.get('notes', '')
                                        }
                                        for match_data in stored_matches.values()
                                    ] if stored_matches else []
                                    # Also get NT matches
                                    with self._pcs("find_nt_matches_in_source (miss)"):
                                        nt_matches = self.find_nt_matches_in_source(segment.source)

                                    # Get status hint for termbase activation
                                    with self._pcs("_get_termbase_status_hint (miss)"):
                                        status_hint = self._get_termbase_status_hint()

                                    # Update both TermLens widgets (left and right)
                                    with self._pcs("_update_both_termlens (miss)"):
                                        self._update_both_termlens(segment.source, termbase_matches, nt_matches, status_hint)
                                except Exception as e:
                                    self.log(f"Error refreshing termlens: {e}")

                            # Store in widget for backwards compatibility
                            if source_widget and hasattr(source_widget, 'termbase_matches'):
                                source_widget.termbase_matches = stored_matches
                            
                            # Highlight termbase matches and NT matches in source cell (if enabled)
                            if self.enable_termbase_grid_highlighting:
                                with self._pcs("highlight_source_with_termbase (miss)"):
                                    self.highlight_source_with_termbase(current_row, segment.source, stored_matches)
                        else:
                            self.log("⏭️ Termbase matching disabled - skipping termbase lookup")

                        if stored_matches:
                            # Convert stored matches to TranslationMatch objects
                            from modules.translation_results_panel import TranslationMatch
                            matches_dict = {
                                "LLM": [],
                                "NT": [],
                                "MT": [],
                                "TM": [],
                                "Termbases": [],
                                "NonTrans": []  # Non-translatables
                            }
                            
                            # Add non-translatable matches (now sourced from
                            # termbase entries flagged is_nontranslatable=1)
                            nt_matches = self.find_nt_matches_in_source(segment.source)
                            if nt_matches:
                                for nt_match in nt_matches:
                                    nt_obj = TranslationMatch(
                                        source=nt_match.get('text', ''),
                                        target=nt_match.get('text', ''),  # Same as source (not translated)
                                        relevance=100,  # Always 100% match
                                        metadata={
                                            'list_name': nt_match.get('list_name', 'Non-Translatables'),
                                            'is_non_translatable': True
                                        },
                                        match_type='NonTrans',
                                        compare_source=nt_match.get('text', ''),
                                        provider_code='NT'
                                    )
                                    matches_dict["NonTrans"].append(nt_obj)

                            for term_id_key, match_info in stored_matches.items():
                                # Extract all fields from match_info (including source term)
                                if isinstance(match_info, dict):
                                    source_term = match_info.get('source', '')
                                    target_term = match_info.get('translation', '')
                                    ranking = match_info.get('ranking', None)
                                    forbidden = match_info.get('forbidden', False)
                                    is_project_termbase = match_info.get('is_project_termbase', False)
                                    term_id = match_info.get('term_id')
                                    termbase_id = match_info.get('termbase_id')
                                    termbase_name = match_info.get('termbase_name', 'Unknown')
                                    domain = match_info.get('domain', '')
                                    notes = match_info.get('notes', '')
                                    project = match_info.get('project', '')
                                    client = match_info.get('client', '')
                                else:
                                    # Backward compatibility: if just string (shouldn't happen with new code)
                                    source_term = str(term_id_key)
                                    target_term = match_info
                                    ranking = None
                                    forbidden = False
                                    is_project_termbase = False
                                    term_id = None
                                    termbase_id = None
                                    termbase_name = 'Unknown'
                                    domain = ''
                                    notes = ''
                                    project = ''
                                    client = ''
                                
                                # Get target synonyms from match_info
                                target_synonyms = match_info.get('target_synonyms', []) if isinstance(match_info, dict) else []
                                
                                match_obj = TranslationMatch(
                                    source=source_term,
                                    target=target_term,
                                    relevance=95,  # High relevance for termbase matches
                                    metadata={
                                        'termbase_name': termbase_name,
                                        'ranking': ranking,
                                        'is_project_termbase': is_project_termbase,
                                        'domain': domain,
                                        'notes': notes,
                                        'project': project,
                                        'client': client,
                                        'forbidden': forbidden,
                                        'term_id': term_id,
                                        'termbase_id': termbase_id,
                                        'target_synonyms': target_synonyms
                                    },
                                    match_type='Termbase',
                                    compare_source=source_term,
                                    provider_code='TB'
                                )
                                matches_dict["Termbases"].append(match_obj)

                            # Get current project languages for all translation services
                            source_lang = getattr(self.current_project, 'source_lang', None) if self.current_project else None
                            target_lang = getattr(self.current_project, 'target_lang', None) if self.current_project else None

                            # Convert language names to codes if needed
                            if source_lang:
                                source_lang_code = self._convert_language_to_code(source_lang)
                            if target_lang:
                                target_lang_code = self._convert_language_to_code(target_lang)

                            # Clear panels first, then show termbase matches immediately
                            if hasattr(self, 'results_panels'):
                                for panel in self.results_panels:
                                    try:
                                        panel.clear()  # Clear old matches
                                        panel.set_matches(matches_dict)  # Add termbase matches immediately
                                    except Exception as e:
                                        self.log(f"Error updating results panel: {e}")
                        else:
                            # No termbase matches - but still check for NT matches
                            matches_dict = {
                                "LLM": [],
                                "NT": [],
                                "MT": [],
                                "TM": [],
                                "Termbases": [],
                                "NonTrans": []  # Non-translatables
                            }
                            
                            # Add non-translatable matches even without termbase matches
                            from modules.translation_results_panel import TranslationMatch
                            nt_matches = self.find_nt_matches_in_source(segment.source)
                            if nt_matches:
                                for nt_match in nt_matches:
                                    nt_obj = TranslationMatch(
                                        source=nt_match.get('text', ''),
                                        target=nt_match.get('text', ''),  # Same as source (not translated)
                                        relevance=100,  # Always 100% match
                                        metadata={
                                            'list_name': nt_match.get('list_name', 'Non-Translatables'),
                                            'is_non_translatable': True
                                        },
                                        match_type='NonTrans',
                                        compare_source=nt_match.get('text', ''),
                                        provider_code='NT'
                                    )
                                    matches_dict["NonTrans"].append(nt_obj)
                                
                                if matches_dict["NonTrans"]:
                                    self.log(f"📋 Found {len(matches_dict['NonTrans'])} NT matches")
                            
                            if hasattr(self, 'results_panels'):
                                for panel in self.results_panels:
                                    try:
                                        panel.clear()
                                        if matches_dict["NonTrans"]:
                                            panel.set_matches(matches_dict)
                                    except Exception as e:
                                        self.log(f"Error clearing results panel: {e}")
                    except Exception as e:
                        self.log(f"Error retrieving stored termbase matches: {e}")

                    # Schedule expensive searches (TM, MT, LLM) with debouncing to prevent UI blocking
                    # ONLY schedule if:
                    # 1. Cache miss OR cache hit with no TM matches (prefetch doesn't include TM - not thread-safe)
                    # 2. TM matching is enabled
                    # 3. Find/Replace is not active (to avoid slowdowns during navigation)
                    needs_tm_lookup = True
                    with self.translation_matches_cache_lock:
                        if segment_id in self.translation_matches_cache:
                            cached = self.translation_matches_cache[segment_id]
                            # v1.9.182: Check if TM matches exist - prefetch worker skips TM lookups
                            needs_tm_lookup = len(cached.get("TM", [])) == 0

                    # v1.9.261: Skip background TM lookup if segment has batch match data from pre-translation
                    has_batch_match = getattr(segment, '_batch_tm_match', None)
                    find_replace_active = getattr(self, 'find_replace_active', False)

                    if needs_tm_lookup and not has_batch_match and self.enable_tm_matching and not find_replace_active:
                        # Get termbase matches if they exist (could be None or empty)
                        termbase_matches = matches_dict.get('Termbases', []) if matches_dict else []
                        self._schedule_mt_and_llm_matches(segment, termbase_matches)
                
                # Trigger prefetch for next 20 segments (adaptive background caching)
                # Also trigger PROACTIVE HIGHLIGHTING for already-cached segments
                if self.current_project and current_row >= 0:
                    import json
                    next_segment_ids = []
                    start_idx = current_row + 1
                    end_idx = min(start_idx + 20, len(self.current_project.segments))

                    for seg in self.current_project.segments[start_idx:end_idx]:
                        # Check if already cached
                        with self.translation_matches_cache_lock:
                            is_cached = seg.id in self.translation_matches_cache
                        
                        if not is_cached:
                            next_segment_ids.append(seg.id)
                        else:
                            # PROACTIVE HIGHLIGHTING: Apply highlighting for cached segments
                            # that haven't been highlighted yet
                            try:
                                with self.termbase_cache_lock:
                                    termbase_raw = self.termbase_cache.get(seg.id, {})
                                if termbase_raw:
                                    termbase_json = json.dumps(termbase_raw)
                                    self._apply_proactive_highlighting(seg.id, termbase_json)
                            except Exception:
                                pass  # Silent failure for proactive highlighting

                    if next_segment_ids:
                        self._start_prefetch_worker(next_segment_ids)

        except Exception as e:
            self.log(f"Critical error in on_cell_selected: {e}")
        finally:
            _total_ms = (_profile_time.perf_counter() - _profile_t0) * 1000.0
            if _total_ms > 250.0:
                self.log(f"⏱️ [cell-select] TOTAL: {_total_ms:.1f} ms")

    def on_selection_changed(self):
        """Handle selection change for row-based selection mode"""
        try:
            # Get currently selected row
            current_row = self.table.currentRow()
            current_col = self.table.currentColumn()
            
            # ⚡ FAST PATH: Skip if this is arrow key navigation (already handled by on_cell_selected)
            if getattr(self, '_arrow_key_navigation', False):
                return  # Let on_cell_selected handle it
            
            # 🚫 GUARD: Skip if we're on the same row (prevents double-processing)
            if hasattr(self, '_last_selection_row') and self._last_selection_row == current_row:
                return
            self._last_selection_row = current_row
            
            # If we have a valid row selection, trigger the same logic as on_cell_selected
            if current_row >= 0:
                # Call on_cell_selected with appropriate parameters
                self.on_cell_selected(current_row, current_col, -1, -1)
        except Exception as e:
            self.log(f"Error in on_selection_changed: {e}")
    
    def test_cell_selection(self):
        """Test method to manually trigger cell selection for debugging"""
        self.log("🧪 TEST: Manually triggering cell selection for row 0")
        if self.table.rowCount() > 0:
            # Try to programmatically select first row
            self.table.selectRow(0)
            self.table.setCurrentCell(0, 2)  # Select source column
            self.on_cell_selected(0, 2, -1, -1)  # Manually trigger
        else:
            self.log("🧪 TEST: No rows available for testing")
    
    def get_selected_segments_from_grid(self):
        """Get list of selected segments from grid view"""
        if not self.current_project or not hasattr(self, 'table'):
            return []
        
        selected_rows = set()
        for item in self.table.selectedItems():
            selected_rows.add(item.row())
        
        segments = []
        for row in sorted(selected_rows):
            if 0 <= row < len(self.current_project.segments):
                segments.append(self.current_project.segments[row])
        
        return segments

    def _get_selected_or_filtered_segments(self, operation_name: str) -> list:
        """Get segments for bulk operation: selected rows first, then filtered rows as fallback.

        Args:
            operation_name: Human-readable name for the confirmation dialog (e.g. "Confirm Segments")

        Returns:
            List of Segment objects, or empty list if user cancels or nothing available.
        """
        selected = self.get_selected_segments_from_grid()
        if selected:
            return selected

        # No selection – check for filtered (visible) rows
        visible_rows = [row for row in range(self.table.rowCount())
                        if not self.table.isRowHidden(row)]
        total_rows = self.table.rowCount()

        if len(visible_rows) < total_rows and len(visible_rows) > 0:
            reply = QMessageBox.question(
                self, operation_name,
                f"No segments selected.\n\n"
                f"Apply '{operation_name}' to all {len(visible_rows)} filtered (visible) segments?",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No)
            if reply == QMessageBox.StandardButton.Yes:
                return [self.current_project.segments[row] for row in visible_rows
                        if row < len(self.current_project.segments)]
            return []

        QMessageBox.information(self, "No Selection",
            "Please select one or more segments, or apply a filter first.")
        return []

    def _preview_combined_prompt_from_grid(self):
        """Preview combined prompt with the currently selected segment from grid"""
        from PyQt6.QtWidgets import QDialog, QVBoxLayout, QTextEdit, QPushButton, QHBoxLayout, QMessageBox
        
        # Check if project is loaded
        if not self.current_project:
            QMessageBox.warning(
                self,
                "No Project",
                "Please load a project first to preview prompts."
            )
            return
        
        # Check if prompt_manager_qt exists
        if not hasattr(self, 'prompt_manager_qt'):
            QMessageBox.warning(
                self,
                "Feature Not Available",
                "AI features are not available."
            )
            return
        
        # Get current segment from grid
        current_segment = None
        current_segment_id = "Preview"
        
        if hasattr(self, 'table') and self.table:
            current_row = self.table.currentRow()
            if current_row >= 0:
                # Map display row to actual segment index (for pagination)
                actual_index = current_row
                if hasattr(self, 'grid_row_to_segment_index') and self.grid_row_to_segment_index:
                    if current_row in self.grid_row_to_segment_index:
                        actual_index = self.grid_row_to_segment_index[current_row]
                
                # Get segment
                if actual_index < len(self.current_project.segments):
                    current_segment = self.current_project.segments[actual_index]
                    current_segment_id = f"Segment {current_segment.id}"
        
        # Fallback to first segment if none selected
        if not current_segment:
            if len(self.current_project.segments) > 0:
                current_segment = self.current_project.segments[0]
                current_segment_id = f"Example: Segment {current_segment.id}"
                QMessageBox.information(
                    self,
                    "No Segment Selected",
                    "No segment is currently selected. Using the first segment as an example.\n\n"
                    "To preview with a specific segment, please select a row in the grid first."
                )
            else:
                QMessageBox.warning(
                    self,
                    "No Segments",
                    "This project has no segments to preview."
                )
                return
        
        # Get languages
        source_lang = getattr(self.current_project, 'source_lang', 'Source Language')
        target_lang = getattr(self.current_project, 'target_lang', 'Target Language')
        
        # Get source and target text
        source_text = current_segment.source
        target_text = current_segment.target or ""

        # Get glossary terms for AI injection
        glossary_terms = self.get_ai_inject_glossary_terms()

        # Build combined prompt
        combined = self.prompt_manager_qt.build_final_prompt(
            source_text, source_lang, target_lang, glossary_terms=glossary_terms,
            target_text=target_text
        )
        
        # Check for figure/image context
        figure_info = ""
        figure_images = []
        if hasattr(self, 'figure_context') and self.figure_context:
            if self.figure_context.has_images():
                # Detect figure references in current segment
                figure_refs = self.figure_context.detect_figure_references(source_text)
                if figure_refs:
                    figure_images = self.figure_context.get_images_for_text(source_text)
                    if figure_images:
                        image_names = [ref for ref, _ in figure_images]
                        figure_info = f"🖼️ {len(figure_images)} image(s) will be sent with this prompt: {', '.join(f'Figure {ref}' for ref in image_names)}"
                    else:
                        figure_info = f"⚠️ Figure references detected ({', '.join(figure_refs)}) but images not found in loaded context"
                else:
                    total_images = len(self.figure_context.figure_context_map)
                    figure_info = f"ℹ️ {total_images} image(s) loaded but no figure references detected in this segment"
        
        # Build composition info
        composition_parts = []
        composition_parts.append(f"📍 {current_segment_id}")
        composition_parts.append(f"🌐 {source_lang} → {target_lang}")
        composition_parts.append(f"📏 Total prompt: {len(combined):,} characters")
        
        if self.prompt_manager_qt.library.active_primary_prompt:
            composition_parts.append(f"✓ Custom prompt attached")
        
        if self.prompt_manager_qt.library.attached_prompts:
            composition_parts.append(f"✓ {len(self.prompt_manager_qt.library.attached_prompts)} additional prompt(s) attached")

        if glossary_terms:
            composition_parts.append(f"📚 {len(glossary_terms)} termbase term(s) injected")

        if figure_info:
            composition_parts.append(figure_info)
        
        composition_text = "\n".join(composition_parts)
        
        # Create dialog
        dialog = QDialog(self)
        dialog.setWindowTitle("🧪 Combined Prompt Preview")
        dialog.resize(900, 700)
        
        layout = QVBoxLayout(dialog)
        
        # Info label
        info_label = QLabel(
            "<b>Complete Assembled Prompt</b><br>"
            "This is what will be sent to the AI (System Prompt + Custom Prompts + segment text)<br><br>" +
            composition_text.replace("\n", "<br>")
        )
        info_label.setTextFormat(Qt.TextFormat.RichText)
        info_label.setWordWrap(True)
        info_label.setStyleSheet("padding: 10px; background-color: #e3f2fd; border-radius: 4px; margin-bottom: 10px;")
        layout.addWidget(info_label)
        
        # Additional image context notice if images are being sent
        if figure_images:
            image_notice = QLabel(
                f"📸 <b>Visual Context:</b> {len(figure_images)} image(s) will be sent alongside this text prompt as binary data<br>"
                f"<small>Images: {', '.join(f'Figure {ref}' for ref, _ in figure_images)}</small>"
            )
            image_notice.setTextFormat(Qt.TextFormat.RichText)
            image_notice.setWordWrap(True)
            image_notice.setStyleSheet("padding: 10px; border-radius: 4px; margin-bottom: 10px; border-left: 4px solid #ff9800;")
            layout.addWidget(image_notice)
        
        # Text editor for preview with syntax highlighting
        text_edit = QTextEdit()
        text_edit.setReadOnly(True)
        text_edit.setLineWrapMode(QTextEdit.LineWrapMode.WidgetWidth)
        text_edit.setStyleSheet("font-family: 'Consolas', 'Courier New', monospace; font-size: 9pt;")

        # Format the prompt with color highlighting
        import html
        import re

        # Escape HTML entities first
        formatted_html = html.escape(combined)

        # Replace newlines with <br> for HTML
        formatted_html = formatted_html.replace('\n', '<br>')

        # Make "# SYSTEM PROMPT" bold and red
        formatted_html = re.sub(
            r'(#\s*SYSTEM\s*PROMPT)',
            r'<span style="color: #d32f2f; font-weight: bold; font-size: 11pt;">\1</span>',
            formatted_html,
            flags=re.IGNORECASE
        )

        # Make "# CUSTOM PROMPT" bold and red
        formatted_html = re.sub(
            r'(#\s*CUSTOM\s*PROMPT)',
            r'<span style="color: #d32f2f; font-weight: bold; font-size: 11pt;">\1</span>',
            formatted_html,
            flags=re.IGNORECASE
        )

        # Make "# TERMBASE" bold and orange
        formatted_html = re.sub(
            r'(#\s*TERMBASE)',
            r'<span style="color: #FF9800; font-weight: bold; font-size: 11pt;">\1</span>',
            formatted_html,
            flags=re.IGNORECASE
        )

        # Make source text section blue (pattern: "XX text:<br>..." until double line break or # header)
        # Match language code + " text:" followed by content until "# " or end
        formatted_html = re.sub(
            r'(\w{2,5}\s+text:)(<br>)(.*?)(<br><br>(?:#|\*\*YOUR TRANSLATION)|$)',
            r'<span style="color: #1565c0; font-weight: bold;">\1</span>\2<span style="color: #1565c0;">\3</span>\4',
            formatted_html,
            flags=re.DOTALL
        )

        # Wrap in pre-like styling div
        formatted_html = f'<div style="font-family: Consolas, Courier New, monospace; white-space: pre-wrap;">{formatted_html}</div>'

        text_edit.setHtml(formatted_html)
        layout.addWidget(text_edit, 1)
        
        # Close button
        button_layout = QHBoxLayout()
        button_layout.addStretch()
        close_btn = QPushButton("Close")
        close_btn.clicked.connect(dialog.accept)
        close_btn.setStyleSheet("padding: 8px 20px; font-weight: bold;")
        button_layout.addWidget(close_btn)
        layout.addLayout(button_layout)
        
        dialog.exec()

    
    def show_grid_context_menu(self, position):
        """Show context menu for grid view with bulk operations"""
        selected_segments = self.get_selected_segments_from_grid()

        if not selected_segments:
            return

        menu = QMenu(self)

        # Confirm selected segments action
        if len(selected_segments) >= 1:
            confirm_action = menu.addAction(f"✅ Confirm {len(selected_segments)} Segment(s)")
            confirm_action.setToolTip(f"Confirm {len(selected_segments)} selected segment(s)")
            confirm_action.triggered.connect(self.confirm_selected_segments)

        # Change Status submenu
        from modules.statuses import get_status
        status_menu = menu.addMenu(f"🏷️ Change Status ({len(selected_segments)})")
        # Common user-settable statuses (excluding TM-specific ones like pm, cm, tm_100, etc.)
        user_statuses = [
            ("not_started", "❌ Not started"),
            ("pretranslated", "🤖 Pre-translated"),
            ("draft", "✏️ Draft"),
            ("confirmed", "✔ Confirmed"),
            ("proofread", "🟪 Proofread"),
            ("approved", "⭐ Approved"),
            ("rejected", "🚫 Rejected"),
        ]
        for status_key, label in user_statuses:
            action = status_menu.addAction(label)
            action.triggered.connect(lambda checked, s=status_key: self.change_status_selected(s))

        # Lock / Unlock toggle
        locked_count = sum(1 for seg in selected_segments if getattr(seg, 'locked', False))
        unlocked_count = len(selected_segments) - locked_count
        if locked_count and unlocked_count:
            # Mixed: offer both
            lock_action = menu.addAction(f"🔒 Lock {unlocked_count} Segment(s)")
            lock_action.triggered.connect(lambda: self._set_locked_on_selected(selected_segments, True))
            unlock_action = menu.addAction(f"🔓 Unlock {locked_count} Segment(s)")
            unlock_action.triggered.connect(lambda: self._set_locked_on_selected(selected_segments, False))
        elif locked_count:
            unlock_action = menu.addAction(f"🔓 Unlock {locked_count} Segment(s)")
            unlock_action.triggered.connect(lambda: self._set_locked_on_selected(selected_segments, False))
        else:
            lock_action = menu.addAction(f"🔒 Lock {len(selected_segments)} Segment(s)")
            lock_action.triggered.connect(lambda: self._set_locked_on_selected(selected_segments, True))

        menu.addSeparator()

        # Clear translations action
        clear_action = menu.addAction("🗑️ Clear Translations")
        clear_action.setToolTip(f"Clear translations for {len(selected_segments)} selected segment(s)")
        clear_action.triggered.connect(lambda: self.clear_selected_translations(selected_segments, 'grid'))

        menu.addSeparator()

        # Select all action
        select_all_action = menu.addAction(f"📋 Select All ({format_shortcut_for_display('Ctrl+A')})")
        select_all_action.triggered.connect(lambda: self.table.selectAll())

        menu.exec(self.table.viewport().mapToGlobal(position))
    
    def _set_locked_on_selected(self, segments, locked: bool):
        """Lock or unlock selected segments."""
        changed = 0
        for seg in segments:
            if getattr(seg, 'locked', False) != locked:
                seg.locked = locked
                changed += 1
        if changed:
            self.project_modified = True
            self.load_segments_to_grid()
            self.update_window_title()
            action = "Locked" if locked else "Unlocked"
            self.log(f"{'🔒' if locked else '🔓'} {action} {changed} segment{'s' if changed != 1 else ''}")

    def clear_selected_translations(self, segments, view_type='grid'):
        """Clear translations for selected segments"""
        if not segments:
            return
        
        count = len(segments)
        cleared_count = 0
        
        for segment in segments:
            if segment.target:  # Only clear if there's something to clear
                segment.target = ""
                if segment.status != 'untranslated':
                    segment.status = 'untranslated'
                cleared_count += 1
        
        if cleared_count > 0:
            self.project_modified = True
            self.update_window_title()
            
            # Refresh the appropriate view
            if view_type == 'grid':
                self.load_segments_to_grid()
            elif view_type == 'list':
                self.refresh_list_view()
            
            self.log(f"✓ Cleared translations for {cleared_count} segment(s)")
        else:
            self.log(f"ℹ No translations to clear for selected segments")
    
    def clear_selected_translations_from_menu(self):
        """Clear translations for selected/filtered segments (called from Edit menu)"""
        # Only available in Grid view
        if self.current_project and hasattr(self, 'table') and self.table:
            segments = self._get_selected_or_filtered_segments("Clear Translations")
            if segments:
                self.clear_selected_translations(segments, 'grid')
        else:
            QMessageBox.information(self, "Not Available", "Please load a project first.")
    
    def copy_source_to_target_bulk(self):
        """Copy source text to target for selected or filtered segments (Edit > Bulk Operations)"""
        if not self.current_project or not hasattr(self, 'table') or not self.table:
            QMessageBox.information(self, "Not Available", "Please load a project first.")
            return

        selected_segments = self._get_selected_or_filtered_segments("Copy Source to Target")
        if not selected_segments:
            return
        
        # Confirm operation
        count = len(selected_segments)
        if count > 1:
            reply = QMessageBox.question(
                self,
                "Confirm Copy",
                f"Copy source to target for {count} segment(s)?\n\nThis will overwrite existing translations.",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
            )
            if reply != QMessageBox.StandardButton.Yes:
                return
        
        # Perform the copy
        copied_count = 0
        for segment in selected_segments:
            row = self._find_row_for_segment(segment.id)
            if row >= 0:
                # v1.9.306: Use segment.source (clean text) instead of source widget's display text
                # which may contain invisible markers (·, →, °, ↵, \u200B)
                source_text = segment.source

                # Update segment object
                segment.target = source_text

                # Update target widget with display-formatted text
                target_widget = self.table.cellWidget(row, 3)
                if target_widget:
                    target_display = self.apply_invisible_replacements(source_text) if hasattr(self, 'apply_invisible_replacements') else source_text
                    target_widget.blockSignals(True)
                    target_widget.setPlainText(target_display)
                    target_widget.blockSignals(False)

                copied_count += 1

        # Auto-resize rows to fit new content
        self.auto_resize_rows()
        self.update_progress_stats()
        
        self.log(f"✓ Copied source to target for {copied_count} segment(s)")
        QMessageBox.information(self, "Copy Complete", f"Copied source to target for {copied_count} segment(s).")

    # --- Non-translatable (number/code) helpers ---
    # Compiled once at class definition time. Matches text that contains ONLY
    # digits, whitespace, and punctuation – no Unicode letters of any script.
    # The character class covers common numeric/code content:
    #   digits, whitespace, hyphen/dash, period, slash, comma, semicolons,
    #   colon, parentheses, plus, equals, asterisk, hash, percent, degree,
    #   currency symbols (€$£¥), ampersand, at-sign, exclamation, question,
    #   square brackets, curly braces, pipe, tilde, caret, underscore, backslash.
    # Future locale-aware conversion belongs in _transform_non_translatable only.
    _NON_TRANSLATABLE_RE = re.compile(
        r'^[\d\s\-\.\/,;:()+=*#%°€$£¥&@!\?\[\]\{\}|~^_\\\'\"]+$'
    )

    @staticmethod
    def _is_non_translatable(source_text: str) -> bool:
        """Return True if source contains only numbers, codes, and punctuation (no letters)."""
        if not source_text or not source_text.strip():
            return False
        return bool(SupervertalerQt._NON_TRANSLATABLE_RE.match(source_text.strip()))

    @staticmethod
    def _transform_non_translatable(source_text: str, source_lang: str = None, target_lang: str = None) -> str:
        """Return the target text for a non-translatable segment.

        Currently returns source verbatim. This is the designed extension point
        for future locale-aware number/date conversion (e.g. decimal comma ↔ period).
        When that feature is added, only this method changes; callers and UI stay the same.
        """
        return source_text

    def copy_source_to_target_non_translatable_bulk(self):
        """Copy source to target for number/code-only segments (Edit > Bulk Operations).

        Segments that contain no alphabetic characters (only digits, punctuation,
        symbols) are considered non-translatable. Their source is copied verbatim
        into an empty target and the status is set to 'draft'.

        Only acts on segments with an empty target to avoid overwriting existing work.
        """
        if not self.current_project or not hasattr(self, 'table') or not self.table:
            QMessageBox.information(self, "Not Available", "Please load a project first.")
            return

        selected_segments = self._get_selected_or_filtered_segments("Copy Source to Target (Non-Translatable)")
        if not selected_segments:
            return

        # Identify qualifying segments: non-translatable source AND empty target
        qualifying = [
            seg for seg in selected_segments
            if self._is_non_translatable(seg.source) and not seg.target.strip()
        ]

        total_selected = len(selected_segments)
        count = len(qualifying)

        if count == 0:
            QMessageBox.information(
                self,
                "No Qualifying Segments",
                f"None of the {total_selected} selected/filtered segment(s) qualify.\n\n"
                "Qualifying segments must contain only numbers, codes, or punctuation "
                "(no letters) and have an empty target.",
            )
            return

        reply = QMessageBox.question(
            self,
            "Confirm Copy",
            f"Found {count} non-translatable segment(s) out of {total_selected} selected/filtered.\n\n"
            "Copy source to target and mark as Draft?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
        )
        if reply != QMessageBox.StandardButton.Yes:
            return

        source_lang = getattr(self.current_project, 'source_language', None)
        target_lang = getattr(self.current_project, 'target_language', None)

        copied_count = 0
        for segment in qualifying:
            row = self._find_row_for_segment(segment.id)
            if row < 0:
                continue

            transformed = self._transform_non_translatable(segment.source, source_lang, target_lang)

            # Update segment data
            segment.target = transformed
            segment.status = 'draft'

            # Update target widget
            target_widget = self.table.cellWidget(row, 3)
            if target_widget:
                target_display = (
                    self.apply_invisible_replacements(transformed)
                    if hasattr(self, 'apply_invisible_replacements')
                    else transformed
                )
                target_widget.blockSignals(True)
                target_widget.setPlainText(target_display)
                target_widget.blockSignals(False)

            # Refresh status icon
            self._refresh_segment_status(segment)

            copied_count += 1

        self.auto_resize_rows()
        self.update_progress_stats()
        if hasattr(self, '_mark_project_modified'):
            self._mark_project_modified()

        self.log(f"✓ Copied source to target (non-translatable) for {copied_count} segment(s)")
        QMessageBox.information(
            self, "Copy Complete",
            f"Copied source to target for {copied_count} non-translatable segment(s)."
        )

    def _copy_source_to_target_selected(self, selected_segments):
        """Copy source to target for the given selected segments (keyboard shortcut path).

        Called from EditableGridTextEditor when Ctrl+Shift+S is pressed with
        multiple segments selected.  Unlike the menu bulk version, this skips
        the confirmation dialog for a snappy keyboard-driven workflow.
        """
        copied_count = 0
        for segment in selected_segments:
            row = self._find_row_for_segment(segment.id)
            if row >= 0:
                # v1.9.306: Use segment.source (clean text) instead of source widget's display text
                # which may contain invisible markers (·, →, °, ↵, \u200B)
                source_text = segment.source

                # Update segment object
                segment.target = source_text

                # Update target widget with display-formatted text
                target_widget = self.table.cellWidget(row, 3)
                if target_widget:
                    target_display = self.apply_invisible_replacements(source_text) if hasattr(self, 'apply_invisible_replacements') else source_text
                    target_widget.blockSignals(True)
                    target_widget.setPlainText(target_display)
                    target_widget.blockSignals(False)

                copied_count += 1

        if copied_count:
            self.auto_resize_rows()
            self.update_progress_stats()
            self.project_modified = True
            self.update_window_title()

        self.log(f"📋 Copied source to target for {copied_count} segment(s)")

    def show_clean_tags_dialog(self):
        """Show dialog to clean formatting tags from project segments"""
        if not self.current_project or not self.current_project.segments:
            QMessageBox.warning(self, "No Project", "Please load a project with segments first.")
            return
        
        # Import dialog class from TMX editor module
        try:
            from modules.tmx_editor_qt import TmxTagCleanerDialog
        except ImportError:
            QMessageBox.warning(self, "Module Error", "Could not load tag cleaner dialog.")
            return
        
        segment_count = len(self.current_project.segments)
        dialog = TmxTagCleanerDialog(self, tu_count=segment_count)
        dialog.setWindowTitle("🧹 Clean Tags from Project")
        
        if dialog.exec() == QDialog.DialogCode.Accepted:
            self.clean_project_tags(dialog)
    
    def clean_project_tags(self, dialog):
        """Clean tags from project segments based on dialog settings"""
        import re
        
        # Get selected tag patterns
        patterns = []
        for name, cb in dialog.tag_checkboxes.items():
            if cb.isChecked():
                patterns.append(cb.tag_pattern)
        
        if not patterns:
            QMessageBox.information(self, "No Tags Selected", "Please select at least one tag type to clean.")
            return
        
        # Get replacement string
        replacement = " " if dialog.replace_space.isChecked() else ""
        
        # Get scope
        clean_source = dialog.scope_both.isChecked() or dialog.scope_source.isChecked()
        clean_target = dialog.scope_both.isChecked() or dialog.scope_target.isChecked()
        
        # Create patterns for both literal and XML-escaped versions
        # Files may store tags as literal <b> or escaped &lt;b&gt;
        expanded_patterns = []
        for p in patterns:
            expanded_patterns.append(p)  # Original pattern for literal tags
            # Create escaped version: < becomes &lt; and > becomes &gt;
            escaped_p = p.replace('<', '&lt;').replace('>', '&gt;')
            if escaped_p != p:
                expanded_patterns.append(escaped_p)
        
        # Compile combined pattern
        combined_pattern = "|".join(f"({p})" for p in expanded_patterns)
        regex = re.compile(combined_pattern)
        
        # Process segments
        modified_count = 0
        tags_removed = 0
        
        progress = QProgressDialog("Cleaning tags...", "Cancel", 0, len(self.current_project.segments), self)
        progress.setWindowModality(Qt.WindowModality.WindowModal)
        progress.setMinimumDuration(0)
        
        for i, segment in enumerate(self.current_project.segments):
            if progress.wasCanceled():
                break
            
            progress.setValue(i)
            QApplication.processEvents()
            
            segment_modified = False
            
            if clean_source and segment.source:
                new_source, count = regex.subn(replacement, segment.source)
                if count > 0:
                    segment.source = new_source.strip() if replacement == "" else new_source
                    tags_removed += count
                    segment_modified = True
            
            if clean_target and segment.target:
                new_target, count = regex.subn(replacement, segment.target)
                if count > 0:
                    segment.target = new_target.strip() if replacement == "" else new_target
                    tags_removed += count
                    segment_modified = True
            
            if segment_modified:
                modified_count += 1
        
        progress.setValue(len(self.current_project.segments))
        
        # Refresh grid
        if modified_count > 0:
            self.project_modified = True
            self.load_segments_to_grid()
            self.update_window_title()
        
        # Show results
        scope_text = "both source and target" if (clean_source and clean_target) else ("source" if clean_source else "target")
        QMessageBox.information(
            self, "Tag Cleaning Complete",
            f"✅ Cleaned {modified_count:,} segment(s)\n"
            f"🏷️ Removed {tags_removed:,} tag(s)\n"
            f"📋 Scope: {scope_text}"
        )
        
        self.log(f"🧹 Tag cleaning: {modified_count} segments modified, {tags_removed} tags removed")
    
