    def _open_folder_in_explorer(self, path: str):
        """Open a folder or file location in the system file explorer"""
        from pathlib import Path

        path_obj = Path(path)

        # If it's a file, open the containing folder
        if path_obj.is_file():
            folder = path_obj.parent
        else:
            folder = path_obj

        # Create folder if it doesn't exist
        folder.mkdir(parents=True, exist_ok=True)

        open_file(str(folder))

    def filter_empty_segments(self):
        """Quick filter to show only segments with empty target"""
        if not self.current_project:
            return
        
        # Safety check: ensure table exists
        if not hasattr(self, 'table') or self.table is None:
            return
        
        # Clear filter boxes first
        source_widget = getattr(self, 'source_filter', None)
        target_widget = getattr(self, 'target_filter', None)
        if self._widget_is_alive(source_widget):
            source_widget.blockSignals(True)
            source_widget.clear()
            source_widget.blockSignals(False)
        if self._widget_is_alive(target_widget):
            target_widget.blockSignals(True)
            target_widget.clear()
            target_widget.blockSignals(False)
        
        # OPTIMIZED: Batch UI updates and don't reload grid
        self.table.setUpdatesEnabled(False)
        try:
            # Clear any yellow text filter highlights (but preserve termbase/tag formatting)
            self._clear_all_filter_highlights()
            
            # Hide rows with non-empty target (empty structural segments always hidden)
            visible_count = 0
            for row, segment in enumerate(self.current_project.segments):
                if row >= self.table.rowCount():
                    break

                has_empty_target = not segment.target or not segment.target.strip()
                show_row = has_empty_target and segment.source.strip()
                self.table.setRowHidden(row, not show_row)

                if show_row:
                    visible_count += 1
        finally:
            self.table.setUpdatesEnabled(True)
        
        self.log(f"🔍 Empty segments filter: showing {visible_count} of {len(self.current_project.segments)} segments")
    
    def _clear_all_filter_highlights(self):
        """Clear yellow filter highlights from all cells without reloading grid"""
        if not hasattr(self, 'table') or self.table is None:
            return
        
        for row in range(self.table.rowCount()):
            # Clear source column (2)
            self._clear_filter_highlights_in_widget(row, 2)
            
            # Clear target column (3)
            self._clear_filter_highlights_in_widget(row, 3)

    def apply_quick_filter(self, filter_type: str):
        """Apply quick filter based on type - integrates with pagination system"""
        if not self.current_project:
            return

        if not hasattr(self, 'table') or self.table is None:
            return

        # Clear filter boxes first
        source_widget = getattr(self, 'source_filter', None)
        target_widget = getattr(self, 'target_filter', None)
        if self._widget_is_alive(source_widget):
            source_widget.blockSignals(True)
            source_widget.clear()
            source_widget.blockSignals(False)
        if self._widget_is_alive(target_widget):
            target_widget.blockSignals(True)
            target_widget.clear()
            target_widget.blockSignals(False)

        # Clear any yellow text filter highlights (but preserve termbase/tag formatting)
        self._clear_all_filter_highlights()

        # Calculate matching rows - collect into a set for pagination integration
        matching_rows = set()
        for row, segment in enumerate(self.current_project.segments):
            show_row = False

            if filter_type == "empty":
                show_row = not segment.target or not segment.target.strip()
            elif filter_type == "not_started":
                show_row = segment.status in ["not_started", "draft"]
            elif filter_type == "confirmed":
                show_row = segment.status == "confirmed"
            elif filter_type == "locked":
                show_row = getattr(segment, 'locked', False)
            elif filter_type == "not_locked":
                show_row = not getattr(segment, 'locked', False)
            elif filter_type == "commented":
                show_row = bool(segment.notes and segment.notes.strip())

            if show_row:
                matching_rows.add(row)

        # Integrate with pagination system - this ensures the filter persists
        # when other UI events trigger pagination updates
        self._active_text_filter_rows = matching_rows
        self.filtering_active = True

        # Apply the filter through the pagination system
        if hasattr(self, '_apply_pagination_to_grid'):
            self._apply_pagination_to_grid()

        filter_names = {
            "empty": "Empty segments",
            "not_started": "Not started",
            "confirmed": "Confirmed",
            "locked": "Locked",
            "not_locked": "Not locked",
            "commented": "Commented"
        }
        self.log(f"🔍 {filter_names.get(filter_type, 'Quick')} filter: showing {len(matching_rows)} of {len(self.current_project.segments)} segments")
    
    def _update_bulk_menu_label(self):
        """Update the Bulk Operations menu label to show filter state."""
        if not hasattr(self, 'bulk_menu') or not self.bulk_menu:
            return
        action = self.bulk_menu.menuAction()
        if not self.current_project or not hasattr(self, 'table') or not self.table:
            action.setText("Bulk &Operations")
            return
        visible = sum(1 for r in range(self.table.rowCount())
                      if not self.table.isRowHidden(r))
        total = self.table.rowCount()
        if visible < total and visible > 0:
            action.setText(f"Bulk &Operations ({visible} filtered)")
        else:
            action.setText("Bulk &Operations")

    def show_advanced_filters_dialog(self):
        """Show advanced filters dialog with detailed filtering options"""
        if not self.current_project:
            QMessageBox.information(self, "No Project", "Please open or create a project first.")
            return
        
        dialog = AdvancedFiltersDialog(self)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            filters = dialog.get_filters()
            self.apply_advanced_filters(filters)
    
    def apply_advanced_filters(self, filters: dict):
        """Apply advanced filters to grid - OPTIMIZED for speed"""
        if not self.current_project or not hasattr(self, 'table') or self.table is None:
            return
        
        # Clear text filter boxes
        source_widget = getattr(self, 'source_filter', None)
        target_widget = getattr(self, 'target_filter', None)
        if self._widget_is_alive(source_widget):
            source_widget.blockSignals(True)
            source_widget.clear()
            source_widget.blockSignals(False)
        if self._widget_is_alive(target_widget):
            target_widget.blockSignals(True)
            target_widget.clear()
            target_widget.blockSignals(False)
        
        # OPTIMIZED: Batch UI updates and don't reload grid
        self.table.setUpdatesEnabled(False)
        try:
            # Clear any yellow text filter highlights (but preserve termbase/tag formatting)
            self._clear_all_filter_highlights()
            
            visible_count = 0
            for row, segment in enumerate(self.current_project.segments):
                if row >= self.table.rowCount():
                    break
                
                show_row = True
                
                # Match rate filter
                if filters.get('match_rate_enabled'):
                    match_percent = getattr(segment, 'match_percent', 0) or 0
                    min_rate = filters.get('match_rate_min', 0)
                    max_rate = filters.get('match_rate_max', 102)
                    if not (min_rate <= match_percent <= max_rate):
                        show_row = False
                
                # Row status filters
                status_filters = filters.get('row_status', [])
                if status_filters:
                    if segment.status not in status_filters:
                        show_row = False
                
                # Locked/unlocked filter
                if filters.get('locked_filter'):
                    locked_value = getattr(segment, 'locked', False)
                    if filters['locked_filter'] == 'locked' and not locked_value:
                        show_row = False
                    elif filters['locked_filter'] == 'unlocked' and locked_value:
                        show_row = False
                
                # Other properties
                if filters.get('has_comments'):
                    if not (segment.notes and segment.notes.strip()):
                        show_row = False
                
                if filters.get('has_proofreading'):
                    if not getattr(segment, 'proofreading_notes', None):
                        show_row = False
                
                if filters.get('repetitions_only'):
                    # TODO: Implement repetition detection
                    pass

                # Empty structural segments are always hidden
                if not segment.source.strip():
                    show_row = False

                self.table.setRowHidden(row, not show_row)

                if show_row:
                    visible_count += 1
        finally:
            self.table.setUpdatesEnabled(True)
        
        self.log(f"🔍 Advanced filters: showing {visible_count} of {len(self.current_project.segments)} segments")

    def apply_sort(self, sort_type: str = None):
        """Sort segments by various criteria (similar to memoQ)"""
        if not self.current_project or not hasattr(self, 'table') or self.table is None:
            return

        if not self.current_project.segments:
            return

        # Show progress dialog during sorting
        from PyQt6.QtWidgets import QProgressDialog
        from PyQt6.QtCore import Qt

        progress = QProgressDialog("Sorting segments, please wait...", None, 0, 0, self)
        progress.setWindowTitle("Sorting")
        progress.setWindowModality(Qt.WindowModality.WindowModal)
        progress.setMinimumDuration(0)  # Show immediately
        progress.show()
        QApplication.processEvents()  # Force UI update

        try:
            # Store original document order if not already stored
            if not hasattr(self, '_original_segment_order'):
                self._original_segment_order = self.current_project.segments.copy()

            # Update current sort state
            self.current_sort = sort_type

            # If sort_type is None, restore document order
            if sort_type is None:
                # Restore document order by sorting by segment ID (original position)
                # This works even if the stored original order is wrong
                self.current_project.segments.sort(key=lambda seg: int(seg.id))

                # Update stored original order to this correct order
                self._original_segment_order = self.current_project.segments.copy()

                # Set pagination to "All" to show all segments
                if hasattr(self, 'page_size_combo') and self._widget_is_alive(self.page_size_combo):
                    self.page_size_combo.blockSignals(True)
                    self.page_size_combo.setCurrentText("All")
                    self.page_size_combo.blockSignals(False)
                    # Update the internal page size variable
                    if hasattr(self, 'grid_page_size'):
                        self.grid_page_size = 999999

                self.load_segments_to_grid()
                self.log("↩️ Restored document order (showing all segments)")
                return

            # Helper function to get text without tags for more accurate sorting
            def strip_tags(text: str) -> str:
                """Remove HTML/XML tags from text for sorting"""
                import re
                return re.sub(r'<[^>]+>', '', text).strip()

            # Calculate frequency maps if needed
            frequency_cache = {}
            if 'freq' in sort_type:
                from collections import Counter
                if 'source' in sort_type:
                    counter = Counter(strip_tags(seg.source).lower() for seg in self.current_project.segments)
                    frequency_cache = {strip_tags(seg.source).lower(): counter[strip_tags(seg.source).lower()]
                                     for seg in self.current_project.segments}
                else:  # target frequency
                    counter = Counter(strip_tags(seg.target).lower() for seg in self.current_project.segments if seg.target)
                    frequency_cache = {strip_tags(seg.target).lower(): counter[strip_tags(seg.target).lower()]
                                     for seg in self.current_project.segments if seg.target}

            # Sort based on selected criterion
            if sort_type == 'source_asc':
                self.current_project.segments.sort(key=lambda s: strip_tags(s.source).lower())
                sort_name = "Source A → Z"
            elif sort_type == 'source_desc':
                self.current_project.segments.sort(key=lambda s: strip_tags(s.source).lower(), reverse=True)
                sort_name = "Source Z → A"
            elif sort_type == 'target_asc':
                self.current_project.segments.sort(key=lambda s: strip_tags(s.target).lower() if s.target else "")
                sort_name = "Target A → Z"
            elif sort_type == 'target_desc':
                self.current_project.segments.sort(key=lambda s: strip_tags(s.target).lower() if s.target else "", reverse=True)
                sort_name = "Target Z → A"
            elif sort_type == 'source_length_asc':
                self.current_project.segments.sort(key=lambda s: len(strip_tags(s.source)))
                sort_name = "Source (shorter first)"
            elif sort_type == 'source_length_desc':
                self.current_project.segments.sort(key=lambda s: len(strip_tags(s.source)), reverse=True)
                sort_name = "Source (longer first)"
            elif sort_type == 'target_length_asc':
                self.current_project.segments.sort(key=lambda s: len(strip_tags(s.target)) if s.target else 0)
                sort_name = "Target (shorter first)"
            elif sort_type == 'target_length_desc':
                self.current_project.segments.sort(key=lambda s: len(strip_tags(s.target)) if s.target else 0, reverse=True)
                sort_name = "Target (longer first)"
            elif sort_type == 'match_asc':
                self.current_project.segments.sort(key=lambda s: getattr(s, 'match_percent', 0) or 0)
                sort_name = "Match Rate (lower first)"
            elif sort_type == 'match_desc':
                self.current_project.segments.sort(key=lambda s: getattr(s, 'match_percent', 0) or 0, reverse=True)
                sort_name = "Match Rate (higher first)"
            elif sort_type == 'source_freq_asc':
                self.current_project.segments.sort(key=lambda s: frequency_cache.get(strip_tags(s.source).lower(), 0))
                sort_name = "Source Frequency (lower first)"
            elif sort_type == 'source_freq_desc':
                self.current_project.segments.sort(key=lambda s: frequency_cache.get(strip_tags(s.source).lower(), 0), reverse=True)
                sort_name = "Source Frequency (higher first)"
            elif sort_type == 'target_freq_asc':
                self.current_project.segments.sort(key=lambda s: frequency_cache.get(strip_tags(s.target).lower(), 0) if s.target else 0)
                sort_name = "Target Frequency (lower first)"
            elif sort_type == 'target_freq_desc':
                self.current_project.segments.sort(key=lambda s: frequency_cache.get(strip_tags(s.target).lower(), 0) if s.target else 0, reverse=True)
                sort_name = "Target Frequency (higher first)"
            elif sort_type == 'modified_asc':
                self.current_project.segments.sort(key=lambda s: s.modified_at if s.modified_at else "")
                sort_name = "Last Changed (oldest first)"
            elif sort_type == 'modified_desc':
                self.current_project.segments.sort(key=lambda s: s.modified_at if s.modified_at else "", reverse=True)
                sort_name = "Last Changed (newest first)"
            elif sort_type == 'status':
                # Sort by status in a logical order: not_started, draft, confirmed
                status_order = {'not_started': 0, 'draft': 1, 'confirmed': 2, 'approved': 3}
                self.current_project.segments.sort(key=lambda s: status_order.get(s.status, 99))
                sort_name = "Row Status"
            else:
                self.log(f"⚠️ Unknown sort type: {sort_type}")
                return

            # Set pagination to "All" to show all sorted segments
            if hasattr(self, 'page_size_combo') and self._widget_is_alive(self.page_size_combo):
                self.page_size_combo.blockSignals(True)
                self.page_size_combo.setCurrentText("All")
                self.page_size_combo.blockSignals(False)
                # Update the internal page size variable
                if hasattr(self, 'grid_page_size'):
                    self.grid_page_size = 999999

            # Reload grid to reflect new order
            self.load_segments_to_grid()
            self.log(f"⇅ Sorted by: {sort_name} (showing all segments)")

        except Exception as e:
            self.log(f"❌ Error sorting segments: {e}")
            import traceback
            traceback.print_exc()
        finally:
            # Close progress dialog
            progress.close()

    # ========================================================================
    # TABBED SEGMENT EDITOR METHODS (for Grid view)
    # ========================================================================
    
    def on_tab_target_change(self):
        """Handle target text change in tab editor - updates all panels"""
        if not hasattr(self, 'tab_current_segment_id') or not self.tab_current_segment_id:
            return
        
        # Get the new text from whichever panel triggered this
        new_text = None
        if hasattr(self, 'tabbed_panels'):
            for panel in self.tabbed_panels:
                try:
                    if hasattr(panel, 'editor_widget') and hasattr(panel.editor_widget, 'target_editor'):
                        new_text = panel.editor_widget.target_editor.toPlainText()
                        break  # Use text from first panel found
                except:
                    continue
        
        if new_text is None:
            return
        
        # Auto-save to current_project data structure
        if self.current_project and hasattr(self.current_project, 'segments'):
            for seg in self.current_project.segments:
                if seg.id == self.tab_current_segment_id:
                    # Check if text actually changed
                    old_target = seg.target
                    old_status = seg.status
                    
                    # IMMEDIATE: Update segment data
                    seg.target = new_text
                    self.project_modified = True
                    
                    # Reset 'confirmed' status to 'draft' when user edits the segment
                    # This prevents auto-saving to TM until user re-confirms the edit
                    if old_status == 'confirmed' and new_text != old_target:
                        seg.status = 'draft'
                        if self.debug_mode_enabled:
                            self.log(f"📝 Tab editor: Status reset confirmed → draft (segment edited)")
                        # Refresh status in all views
                        self._refresh_segment_status(seg)
                    
                    # Update all other panels to keep them in sync
                    if hasattr(self, 'tabbed_panels'):
                        for panel in self.tabbed_panels:
                            try:
                                if hasattr(panel, 'editor_widget') and hasattr(panel.editor_widget, 'target_editor'):
                                    # Temporarily disconnect to avoid infinite loop
                                    panel.editor_widget.target_editor.blockSignals(True)
                                    panel.editor_widget.target_editor.setPlainText(new_text)
                                    panel.editor_widget.target_editor.blockSignals(False)
                            except:
                                pass
                    
                    # DEBOUNCED: Save to TM (expensive operation)
                    # Cancel previous timer
                    if hasattr(self, '_tab_target_debounce_timer'):
                        self._tab_target_debounce_timer.stop()
                    
                    # Schedule TM save after 500ms of inactivity
                    from PyQt6.QtCore import QTimer
                    self._tab_target_debounce_timer = QTimer()
                    self._tab_target_debounce_timer.setSingleShot(True)
                    # CRITICAL: Capture variables by value using default parameters to avoid closure bugs
                    self._tab_target_debounce_timer.timeout.connect(lambda segment=seg, text=new_text: self._save_tab_target_to_tm(segment, text))
                    self._tab_target_debounce_timer.start(500)
                    
                    break
    
    def _save_tab_target_to_tm(self, segment, text):
        """Save tab target text to TM after debounce delay"""
        try:
            # Only save to TM if segment is confirmed (user explicitly approved)
            if segment.status == 'confirmed' and text.strip():
                self.save_segment_to_activated_tms(segment.source, text)
        except Exception as e:
            self.log(f"Warning: Could not save to TM: {e}")
    
    def on_tab_status_combo_changed(self, index: int):
        combo = self.sender()
        if isinstance(combo, QComboBox) and index >= 0:
            status_key = combo.itemData(index)
            if status_key:
                self.on_tab_segment_status_change(status_key)

    def on_tab_segment_status_change(self, status_key: str):
        """Handle status change in tab editor - updates all panels"""
        if not hasattr(self, 'tab_current_segment_id') or not self.tab_current_segment_id:
            return

        status_key = status_key or DEFAULT_STATUS.key
        status_def = get_status(status_key)

        if self.current_project and hasattr(self.current_project, 'segments'):
            for seg in self.current_project.segments:
                if seg.id == self.tab_current_segment_id:
                    seg.status = status_key
                    self.project_modified = True
                    self.log(f"✓ Status changed to: {status_def.label}")

                    # Update all panels to keep them in sync
                    if hasattr(self, 'tabbed_panels'):
                        for panel in self.tabbed_panels:
                            try:
                                if hasattr(panel, 'editor_widget') and hasattr(panel.editor_widget, 'status_combo'):
                                    combo = panel.editor_widget.status_combo
                                    combo.blockSignals(True)
                                    idx = combo.findData(status_key)
                                    if idx >= 0:
                                        combo.setCurrentIndex(idx)
                                    combo.blockSignals(False)
                            except Exception as e:
                                self.log(f"Error syncing status combo: {e}")
                    self._refresh_segment_status(seg)
                    
                    # Save to TM ONLY if status changed to confirmed (user explicitly approved)
                    if status_key == 'confirmed' and seg.target.strip():
                        try:
                            self.save_segment_to_activated_tms(seg.source, seg.target)
                            self.log(f"✓ Saved to TM: {seg.source[:30]}... → {seg.target[:30]}...")
                        except Exception as e:
                            self.log(f"Warning: Could not save to TM: {e}")
                    
                    break
    
    def on_tab_notes_change(self):
        """Handle comments change in tab editor - updates all panels"""
        if not hasattr(self, 'tab_current_segment_id') or not self.tab_current_segment_id:
            return
        
        # Get the new comments from whichever panel triggered this
        new_notes = None
        if hasattr(self, 'tabbed_panels'):
            for panel in self.tabbed_panels:
                try:
                    if hasattr(panel, 'notes_widget') and hasattr(panel.notes_widget, 'notes_editor'):
                        new_notes = panel.notes_widget.notes_editor.toPlainText()
                        break
                except:
                    continue
        
        if new_notes is None:
            return
        
        if self.current_project and hasattr(self.current_project, 'segments'):
            for seg in self.current_project.segments:
                if seg.id == self.tab_current_segment_id:
                    seg.notes = new_notes
                    self.project_modified = True
                    
                    # Update all other panels to keep them in sync
                    if hasattr(self, 'tabbed_panels'):
                        for panel in self.tabbed_panels:
                            try:
                                if hasattr(panel, 'notes_widget') and hasattr(panel.notes_widget, 'notes_editor'):
                                    panel.notes_widget.notes_editor.blockSignals(True)
                                    panel.notes_widget.notes_editor.setPlainText(new_notes)
                                    panel.notes_widget.notes_editor.blockSignals(False)
                            except:
                                pass
                    self._refresh_segment_status(seg)
                    break
    
    def _on_results_panel_notes_changed(self):
        """Handle notes change in Translation Results panel - saves to current segment.
        NOTE: This function is deprecated - Translation Results panel has been removed.
        """
        # Translation Results panel is deprecated - this should never be called
        if not self.translation_results_panel:
            return
        if not self.current_project:
            return
        
        # Get current segment from grid selection
        current_row = self.table.currentRow()
        if current_row < 0:
            return
        
        id_item = self.table.item(current_row, 0)
        if not id_item:
            return
        
        try:
            segment_id = int(id_item.text())
        except (ValueError, AttributeError):
            return
        
        # Find segment and update notes
        for seg in self.current_project.segments:
            if seg.id == segment_id:
                new_notes = self.translation_results_panel.notes_edit.toPlainText()
                seg.notes = new_notes
                self.project_modified = True
                # Sync with bottom notes panel
                if hasattr(self, 'bottom_notes_edit') and self.bottom_notes_edit:
                    self.bottom_notes_edit.blockSignals(True)
                    self.bottom_notes_edit.setPlainText(new_notes)
                    self.bottom_notes_edit.blockSignals(False)
                # Refresh the status cell to update the notes indicator
                self._refresh_segment_status(seg)
                break
    
    # ──────────────────────────────────────────────────────────────
    # Comment-anchor visual indicators in editor cells (v1.10.57 Phase C)
    # ──────────────────────────────────────────────────────────────

    # Amber background for ranges anchored by a Comment. Mirrors the
    # default Word-comment highlight colour so the in-app cell matches
    # what users will see in the exported DOCX (Phase E).
    _COMMENT_ANCHOR_BG_QCOLOR = None  # Lazily built — needs Qt module

    def _comment_anchor_bg_color(self):
        if self._COMMENT_ANCHOR_BG_QCOLOR is None:
            # Use a light amber with full alpha — cell renderers don't
            # always honour transparency, and full-alpha picks up cleanly
            # against the editor's default white background.
            self._COMMENT_ANCHOR_BG_QCOLOR = QColor(254, 240, 138)  # amber-200
        return self._COMMENT_ANCHOR_BG_QCOLOR

    def _apply_comment_anchors_to_cell(self, row: int, segment):
        """Apply a background highlight to every anchored character range
        in this row's source and target cell editors.

        Called from load_segments_to_grid (initial paint), after
        Ctrl+Shift+M creates a comment, and after edit/delete.
        Cheap to call repeatedly — at most one cursor pass per
        anchored comment, and visible cells only.

        Defensive against text-length mismatches: anchor offsets are
        clamped to the actual cell text length. If the user has
        edited the target text since the comment was anchored, the
        highlight may not match the original wording, but at least
        it won't crash or wander into invalid territory.
        """
        if not segment or not getattr(segment, 'comments', None):
            return
        if not hasattr(self, 'table') or not self.table:
            return

        from PyQt6.QtGui import QTextCursor as _QTextCursor, QTextCharFormat as _QTextCharFormat

        bg_color = self._comment_anchor_bg_color()
        fmt = _QTextCharFormat()
        fmt.setBackground(bg_color)
        # Force black text on the amber highlight so it stays readable in dark
        # themes (light theme text on light amber is unreadable). The amber is
        # always light, so black works in every theme.
        fmt.setForeground(QColor('#000000'))

        for col, field_name in [(2, 'source'), (3, 'target')]:
            editor = self.table.cellWidget(row, col)
            if editor is None or not hasattr(editor, 'document'):
                continue
            text_len = len(editor.toPlainText())
            for c in segment.comments:
                if c.anchor_field != field_name or not c.is_anchored:
                    continue
                start = max(0, min(c.anchor_start, text_len))
                end = max(start, min(c.anchor_end, text_len))
                if start == end:
                    continue
                cursor = _QTextCursor(editor.document())
                cursor.setPosition(start)
                cursor.setPosition(end, _QTextCursor.MoveMode.KeepAnchor)
                cursor.mergeCharFormat(fmt)

    def _apply_comment_anchors_to_all_cells(self):
        """Apply anchor highlights to every currently-visible row.

        Called once at the end of load_segments_to_grid so the
        highlights show up immediately after a project load or a
        page-switch (with pagination, only the current page's rows
        actually have cell widgets).
        """
        if (not self.current_project
                or not self.current_project.segments
                or not hasattr(self, 'table')
                or not self.table):
            return

        # Build a quick lookup: segment_id → segment, since cells store id only.
        by_id = {s.id: s for s in self.current_project.segments}

        for row in range(self.table.rowCount()):
            id_item = self.table.item(row, 0)
            if not id_item:
                continue
            try:
                seg_id = int(id_item.text())
            except (ValueError, AttributeError):
                continue
            segment = by_id.get(seg_id)
            if segment is None:
                continue
            self._apply_comment_anchors_to_cell(row, segment)

    def _refresh_cell_text_for_anchors(self, row: int, segment):
        """Reset character formatting on this row's source/target cells.

        Used as a "cheap clear" before re-applying anchor highlights,
        since mergeCharFormat is additive (no per-range undo). Calling
        setPlainText() with the cell's current text strips all rich-text
        char formats (Qt documented behaviour) without changing the text
        content. Signals are blocked so the legacy textChanged handlers
        don't interpret this as a user edit.
        """
        if not hasattr(self, 'table') or not self.table:
            return
        for col in (2, 3):
            editor = self.table.cellWidget(row, col)
            if editor is None or not hasattr(editor, 'setPlainText'):
                continue
            current_text = editor.toPlainText()
            editor.blockSignals(True)
            try:
                editor.setPlainText(current_text)
            finally:
                editor.blockSignals(False)

    def _find_row_for_segment_id(self, segment_id: int) -> int:
        """Return the row index for a segment id in the visible table,
        or -1 if the segment isn't on the current page. Helper for the
        targeted anchor-refresh after a single comment is created/edited."""
        if not hasattr(self, 'table') or not self.table:
            return -1
        for row in range(self.table.rowCount()):
            id_item = self.table.item(row, 0)
            if id_item:
                try:
                    if int(id_item.text()) == segment_id:
                        return row
                except (ValueError, AttributeError):
                    continue
        return -1

    def _refresh_segment_comments_list(self):
        """Rebuild the all-comments list at the top of the Comments → Segment sub-tab.

        v1.10.57 Phase D: iterates ``segment.comments`` (one entry per
        Comment) instead of the legacy single-string ``segment.notes``.
        A segment with three comments shows three entries; each entry
        carries its own anchor snippet (if any), author, timestamp,
        and a right-click context menu for edit / delete.

        Idempotent. Cheap to call on every change — number of comments
        per project is typically small.
        """
        if not hasattr(self, '_segment_comments_list_layout'):
            return  # Sub-tab not built yet (early init)

        from PyQt6.QtWidgets import QFrame as _QFrame

        layout = self._segment_comments_list_layout

        # Map of comment id → its header button, so _open_comment_in_panel()
        # can scroll a specific comment into view and flash it. Rebuilt here
        # since the widgets are recreated on every refresh.
        self._comment_list_header_btns = {}

        # Clear existing children. Walk takeAt(0) until the layout is
        # empty so both widgets AND the trailing stretch get cleaned up.
        while layout.count() > 0:
            item = layout.takeAt(0)
            widget = item.widget()
            if widget is not None:
                widget.deleteLater()

        # Collect (segment, comment) pairs in document order, one row
        # per Comment. Skips comments with empty text just in case.
        entries: list = []  # [(seg_id, segment, comment), ...]
        if self.current_project and self.current_project.segments:
            for seg in self.current_project.segments:
                for c in getattr(seg, 'comments', []) or []:
                    if c.text and c.text.strip():
                        entries.append((seg.id, seg, c))

        if not entries:
            empty = QLabel(
                "(No comments in this project yet. Select text in a source or "
                "target cell and press <b>Ctrl+Shift+M</b> to add an anchored "
                "comment, or use the editor below for a segment-level note.)"
            )
            empty.setTextFormat(Qt.TextFormat.RichText)
            empty.setStyleSheet("color: #999; padding: 8px;")
            empty.setWordWrap(True)
            layout.addWidget(empty)
            layout.addStretch()
            return

        for idx, (seg_id, segment, comment) in enumerate(entries):
            # Divider between entries (not above the first).
            if idx > 0:
                divider = _QFrame()
                divider.setFrameShape(_QFrame.Shape.HLine)
                divider.setStyleSheet("color: #e0e0e0; max-height: 1px;")
                layout.addWidget(divider)

            # ── Header: "Segment #N" + optional anchor tag ──
            header_label = f"Segment #{seg_id}"
            if comment.is_anchored:
                header_label += f"  ⚓ {comment.anchor_field}"
            header_btn = QPushButton(header_label)
            header_btn.setFlat(True)
            header_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            header_btn.setStyleSheet(
                "QPushButton { "
                "  color: #2563eb; "
                "  font-weight: bold; "
                "  font-size: 10pt; "
                "  text-align: left; "
                "  padding: 6px 8px 2px 8px; "
                "  border: none; "
                "  background: transparent; "
                "} "
                "QPushButton:hover { "
                "  background-color: rgba(37, 99, 235, 0.08); "
                "  text-decoration: underline; "
                "}"
            )
            header_btn.clicked.connect(
                lambda _checked, sid=seg_id: self._navigate_to_segment_by_id(sid)
            )
            self._comment_list_header_btns[comment.id] = header_btn
            # Right-click context menu for edit/delete.
            header_btn.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
            header_btn.customContextMenuRequested.connect(
                lambda _pos, seg=segment, cid=comment.id, btn=header_btn:
                    self._comment_context_menu(seg, cid, btn)
            )
            layout.addWidget(header_btn)

            # ── Optional anchored-text snippet ──
            if comment.is_anchored:
                source_text = (segment.source if comment.anchor_field == 'source'
                               else segment.target) or ''
                snippet_raw = source_text[comment.anchor_start:comment.anchor_end]
                snippet = snippet_raw[:140] + ('…' if len(snippet_raw) > 140 else '')
                try:
                    import html as _html
                    snippet_escaped = _html.escape(snippet) if snippet else '(range)'
                except Exception:
                    snippet_escaped = snippet or '(range)'
                anchor_label = QLabel(f'<i>"{snippet_escaped}"</i>')
                anchor_label.setTextFormat(Qt.TextFormat.RichText)
                anchor_label.setWordWrap(True)
                anchor_label.setStyleSheet(
                    "color: #555; padding: 0 12px 4px 12px; font-size: 9pt;"
                )
                layout.addWidget(anchor_label)

            # ── Body ──
            body = QLabel(comment.text)
            body.setWordWrap(True)
            body.setTextInteractionFlags(Qt.TextInteractionFlag.TextSelectableByMouse)
            body.setStyleSheet(
                "padding: 0 12px 4px 12px; "
                "font-size: 10pt; "
                "color: #333;"
            )
            layout.addWidget(body)

            # ── Footer: author + timestamp ──
            footer_parts = []
            if comment.author:
                footer_parts.append(comment.author)
            if comment.created:
                # Show just date + HH:MM, not the full ISO blob.
                try:
                    from datetime import datetime as _dt
                    parsed = _dt.fromisoformat(comment.created)
                    footer_parts.append(parsed.strftime('%Y-%m-%d %H:%M'))
                except Exception:
                    footer_parts.append(comment.created[:16])
            if footer_parts:
                footer = QLabel(' · '.join(footer_parts) + '  (right-click for edit/delete)')
                footer.setStyleSheet(
                    "color: #888; padding: 0 12px 8px 12px; font-size: 8pt; "
                    "font-style: italic;"
                )
                layout.addWidget(footer)

        layout.addStretch()

        # Update bottom-editor lock state — when any segment in the project
        # has multiple comments or any anchored comment, the legacy
        # single-string editor would silently clobber them. Lock it
        # whenever the currently-selected segment is in that state.
        self._update_bottom_notes_editor_lock_state()

    def _comment_context_menu(self, segment: 'Segment', comment_id: str, anchor_widget):
        """Right-click context menu on a comments-list entry. Edit / Delete."""
        from PyQt6.QtWidgets import QMenu, QMessageBox as _QMessageBox
        from PyQt6.QtGui import QAction as _QAction

        comment = segment.get_comment(comment_id)
        if not comment:
            return

        menu = QMenu(anchor_widget)
        edit_action = _QAction("✏️ Edit comment…", menu)
        delete_action = _QAction("🗑️ Delete comment", menu)
        menu.addAction(edit_action)
        menu.addAction(delete_action)

        chosen = menu.exec(anchor_widget.mapToGlobal(anchor_widget.rect().bottomLeft()))
        if chosen is edit_action:
            self._edit_comment_dialog(segment, comment_id)
        elif chosen is delete_action:
            reply = _QMessageBox.question(
                self, "Delete comment",
                f"Delete this comment from segment #{segment.id}?\n\n"
                f"\"{comment.text[:100]}{'…' if len(comment.text) > 100 else ''}\"",
                _QMessageBox.StandardButton.Yes | _QMessageBox.StandardButton.No,
                _QMessageBox.StandardButton.No,
            )
            if reply == _QMessageBox.StandardButton.Yes:
                segment.remove_comment(comment_id)
                self.project_modified = True
                try:
                    self.update_window_title()
                except Exception:
                    pass
                try:
                    self._refresh_segment_status(segment)
                except Exception:
                    pass
                self._refresh_segment_comments_list()
                # Re-apply anchor highlights on the affected row (the
                # removed comment's highlight needs to go; remaining
                # anchored comments stay highlighted).
                affected_row = self._find_row_for_segment_id(segment.id)
                if affected_row >= 0:
                    # We need to clear ALL char-format backgrounds first
                    # since mergeCharFormat is additive and we have no
                    # cheap way to identify "our" old highlight to undo.
                    # Easiest: refresh the cell text, which resets formats.
                    self._refresh_cell_text_for_anchors(affected_row, segment)
                    self._apply_comment_anchors_to_cell(affected_row, segment)
                # Keep the bottom editor in sync if the deleted comment
                # belonged to the currently-selected segment.
                if hasattr(self, '_update_bottom_notes_for_segment'):
                    self._update_bottom_notes_for_segment(segment)

    def _edit_comment_dialog(self, segment: 'Segment', comment_id: str):
        """Open a dialog to edit an existing comment's text. Anchor + author
        are kept as-is; only the body is editable here."""
        from PyQt6.QtWidgets import (QDialog as _QDialog, QDialogButtonBox as _QDialogButtonBox,
                                     QPlainTextEdit as _QPlainTextEdit)

        comment = segment.get_comment(comment_id)
        if not comment:
            return

        dialog = _QDialog(self)
        dialog.setWindowTitle("Edit comment")
        dialog.setMinimumWidth(480)
        layout = QVBoxLayout(dialog)

        header = QLabel(
            f"<b>Segment #{segment.id}</b> &mdash; " +
            (f"anchored to {comment.anchor_field}" if comment.is_anchored else "segment-level")
        )
        header.setTextFormat(Qt.TextFormat.RichText)
        layout.addWidget(header)

        if comment.is_anchored:
            source_text = (segment.source if comment.anchor_field == 'source'
                           else segment.target) or ''
            snippet_raw = source_text[comment.anchor_start:comment.anchor_end]
            snippet = snippet_raw[:140] + ('…' if len(snippet_raw) > 140 else '')
            try:
                import html as _html
                snippet_escaped = _html.escape(snippet)
            except Exception:
                snippet_escaped = snippet
            sl = QLabel(f'Re: <i>"{snippet_escaped}"</i>')
            sl.setTextFormat(Qt.TextFormat.RichText)
            sl.setWordWrap(True)
            sl.setStyleSheet(
                "color: #555; padding: 6px 8px; "
                "background-color: rgba(37, 99, 235, 0.08); "
                "border-radius: 4px; margin: 4px 0;"
            )
            layout.addWidget(sl)

        layout.addWidget(QLabel("Comment:"))
        text_edit = _QPlainTextEdit()
        text_edit.setPlainText(comment.text)
        text_edit.setMinimumHeight(120)
        layout.addWidget(text_edit)

        buttons = _QDialogButtonBox(
            _QDialogButtonBox.StandardButton.Ok
            | _QDialogButtonBox.StandardButton.Cancel
        )
        buttons.accepted.connect(dialog.accept)
        buttons.rejected.connect(dialog.reject)
        layout.addWidget(buttons)

        text_edit.setFocus()
        # Place cursor at end so the user can append immediately.
        cur = text_edit.textCursor()
        cur.movePosition(cur.MoveOperation.End)
        text_edit.setTextCursor(cur)

        if dialog.exec() != _QDialog.DialogCode.Accepted:
            return
        new_text = text_edit.toPlainText().strip()
        if new_text == comment.text:
            return  # No change

        if new_text:
            segment.update_comment(comment_id, new_text)
        else:
            segment.remove_comment(comment_id)
        self.project_modified = True
        try:
            self.update_window_title()
        except Exception:
            pass
        try:
            self._refresh_segment_status(segment)
        except Exception:
            pass
        self._refresh_segment_comments_list()
        # Re-apply anchor highlights on the affected row (text content
        # of the anchor is unchanged but a delete-via-empty-edit may
        # have removed a comment whose highlight needs to go).
        affected_row = self._find_row_for_segment_id(segment.id)
        if affected_row >= 0:
            self._refresh_cell_text_for_anchors(affected_row, segment)
            self._apply_comment_anchors_to_cell(affected_row, segment)
        if hasattr(self, '_update_bottom_notes_for_segment'):
            self._update_bottom_notes_for_segment(segment)

    def _update_bottom_notes_editor_lock_state(self):
        """Disable the legacy bottom comment editor when the current segment
        has multiple comments or any anchored comment.

        The bottom editor is a single QPlainTextEdit that writes to
        ``segment.notes`` (via ``replace_all_comments_with_text``).
        That works for the simple one-segment-level-comment case but
        would silently clobber anchored comments or merge multiple
        comments into one. When the current segment is in that "complex"
        state, the editor goes read-only with a hint that the user
        should use the all-comments list above instead.
        """
        if not hasattr(self, 'bottom_notes_edit') or not self.bottom_notes_edit:
            return
        # Determine the currently-selected segment.
        segment = None
        if (self.current_project and self.current_project.segments
                and hasattr(self, 'table') and self.table):
            current_row = self.table.currentRow()
            if current_row >= 0:
                id_item = self.table.item(current_row, 0)
                if id_item:
                    try:
                        seg_id = int(id_item.text())
                        segment = next(
                            (s for s in self.current_project.segments
                             if s.id == seg_id), None
                        )
                    except (ValueError, AttributeError):
                        pass

        is_complex = False
        if segment:
            comments = getattr(segment, 'comments', []) or []
            if len(comments) > 1:
                is_complex = True
            elif any(c.is_anchored for c in comments):
                is_complex = True

        if is_complex:
            self.bottom_notes_edit.setReadOnly(True)
            self.bottom_notes_edit.setPlaceholderText(
                "This segment has multiple comments or an anchored comment. "
                "Use the list above to edit or delete individual comments "
                "(right-click on a Segment #N header)."
            )
            self.bottom_notes_edit.setStyleSheet(
                "font-size: 10pt; background-color: #f5f5f5; color: #888;"
            )
        else:
            self.bottom_notes_edit.setReadOnly(False)
            self.bottom_notes_edit.setPlaceholderText(
                "Add a comment about this segment — context, "
                "translation concerns, anything worth flagging..."
            )
            self.bottom_notes_edit.setStyleSheet("font-size: 10pt;")

    def _navigate_to_segment_by_id(self, segment_id: int):
        """Navigate to a segment by ID, switching pages first if needed.

        Unlike :py:meth:`_navigate_to_segment_in_grid` (which looks the
        segment up by row index in the *currently visible* table), this
        version finds the segment's index in the full project segment
        list, computes which page it's on, switches to that page if
        we're not already there, and only then selects the row. Works
        correctly across pagination boundaries.
        """
        if not self.current_project or not self.current_project.segments:
            return
        if not hasattr(self, 'table') or not self.table:
            return

        # Locate the target segment in the full project list.
        segments = self.current_project.segments
        target_idx = None
        for i, seg in enumerate(segments):
            if seg.id == segment_id:
                target_idx = i
                break
        if target_idx is None:
            self.log(f"⚠ Segment #{segment_id} not found in project")
            return

        # If pagination is active and the segment is on a different page,
        # switch to that page first. The grid rebuilds synchronously
        # inside go_to_page, so by the time it returns the target row
        # is visible.
        if (hasattr(self, 'page_size_combo')
                and self.page_size_combo.currentText() != "All"):
            try:
                page_size = int(self.page_size_combo.currentText())
                target_page = (target_idx // page_size) + 1
                current_page = getattr(self, 'grid_current_page', 0) + 1
                if current_page != target_page and hasattr(self, 'page_number_input'):
                    self.page_number_input.setText(str(target_page))
                    self.go_to_page()
            except (ValueError, AttributeError):
                pass

        # Switch to the Grid (Editor) tab if we're elsewhere.
        if hasattr(self, 'main_tabs'):
            self.main_tabs.setCurrentIndex(0)

        # Find the row in the (possibly newly-rebuilt) table and select it.
        for row in range(self.table.rowCount()):
            id_item = self.table.item(row, 0)
            if id_item:
                try:
                    if int(id_item.text()) == segment_id:
                        self.table.setCurrentCell(row, 3)  # Column 3 = Target
                        self.table.scrollToItem(
                            self.table.item(row, 0),
                            QTableWidget.ScrollHint.PositionAtCenter,
                        )
                        target_widget = self.table.cellWidget(row, 3)
                        if target_widget:
                            target_widget.setFocus()
                        return
                except (ValueError, AttributeError):
                    continue

        # Reaching here means the page-switch logic didn't put the
        # segment on the current page — shouldn't happen but log it.
        self.log(
            f"⚠ Segment #{segment_id} not on current grid page after "
            f"page-switch attempt (unexpected)"
        )

    def _open_comment_in_panel(self, comment_id: str):
        """Reveal a specific comment in the Comments ▸ Segment sub-tab.

        Invoked by the "💬 Open comment" item on a cell's anchored-comment
        highlight. Switches the right panel to the Comments tab, scrolls the
        all-comments list to the matching entry, and briefly flashes it. Handy
        when the Match Panel (or any other tab) is showing and you want to jump
        straight from a yellow-highlighted range to its comment.
        """
        # Ensure the list (and the comment→button map) is current.
        try:
            self._refresh_segment_comments_list()
        except Exception:
            pass

        # Switch the right panel to Comments → Segment sub-tab. Resolve the
        # Comments tab by its LABEL, not the stored _comments_tab_index — the
        # Chat/AI tab is inserted into the row after build time, shifting the
        # Comments tab down, so the cached index goes stale (it pointed at
        # Preview).
        if hasattr(self, 'right_tabs'):
            target_index = None
            for i in range(self.right_tabs.count()):
                if "Comments" in self.right_tabs.tabText(i):
                    target_index = i
                    break
            if target_index is not None:
                self.right_tabs.setCurrentIndex(target_index)
        if hasattr(self, 'comments_sub_tabs'):
            self.comments_sub_tabs.setCurrentIndex(0)

        btn = getattr(self, '_comment_list_header_btns', {}).get(comment_id)
        if btn is None:
            return
        scroll = getattr(self, '_segment_comments_list_scroll', None)

        def _reveal_and_flash():
            try:
                if scroll is not None and self._widget_is_alive(scroll):
                    scroll.ensureWidgetVisible(btn)
                self._flash_comment_header(btn)
            except Exception:
                pass

        # Defer so the tab switch / layout settles before we scroll.
        QTimer.singleShot(0, _reveal_and_flash)

    def _flash_comment_header(self, btn):
        """Briefly tint a comments-list header button so the eye lands on it."""
        if not self._widget_is_alive(btn):
            return
        original = btn.styleSheet()
        btn.setStyleSheet(
            original +
            "\nQPushButton { background-color: rgba(255, 213, 79, 0.55); "
            "border-radius: 3px; }"
        )

        def _restore():
            if self._widget_is_alive(btn):
                btn.setStyleSheet(original)

        QTimer.singleShot(1400, _restore)

    def _on_bottom_notes_changed(self):
        """Handle notes change in bottom Notes tab - saves to current segment and syncs with Translation Results panel"""
        if not self.current_project:
            return
        
        # Get current segment from grid selection
        current_row = self.table.currentRow()
        if current_row < 0:
            return
        
        id_item = self.table.item(current_row, 0)
        if not id_item:
            return
        
        try:
            segment_id = int(id_item.text())
        except (ValueError, AttributeError):
            return
        
        # Find segment and update notes
        for seg in self.current_project.segments:
            if seg.id == segment_id:
                new_notes = self.bottom_notes_edit.toPlainText()
                # v1.10.57: route the assignment through the legacy
                # bridge helper so segment.comments stays in sync with
                # the legacy segment.notes single-string field. The
                # bridge preserves the existing comment's id when the
                # text is edited in place (no churn), or replaces the
                # comments list with a single new Comment otherwise.
                seg.replace_all_comments_with_text(
                    new_notes,
                    author=self.get_translator_name() if hasattr(self, 'get_translator_name') else '',
                )
                self.project_modified = True
                # Sync with Translation Results panel notes
                if hasattr(self, 'translation_results_panel') and self.translation_results_panel:
                    if hasattr(self.translation_results_panel, 'notes_edit') and self.translation_results_panel.notes_edit:
                        self.translation_results_panel.notes_edit.blockSignals(True)
                        self.translation_results_panel.notes_edit.setPlainText(new_notes)
                        self.translation_results_panel.notes_edit.blockSignals(False)
                # Refresh the status cell to update the notes indicator
                self._refresh_segment_status(seg)
                # v1.10.56: rebuild the all-comments list in the
                # Comments → Segment sub-tab so the new/edited comment
                # appears (or disappears, if cleared) immediately.
                self._refresh_segment_comments_list()
                break
    
    def _on_scratchpad_changed(self):
        """Handle scratchpad change - saves to current project (not segment-level)"""
        if not self.current_project:
            return
        
        new_notes = self.scratchpad_edit.toPlainText()
        self.current_project.scratchpad_notes = new_notes
        self.current_project.modified = datetime.now().isoformat()
        self.project_modified = True
    
    def _update_scratchpad_for_project(self):
        """Update the Scratchpad tab with the current project's scratchpad notes"""
        if not hasattr(self, 'scratchpad_edit') or not self.scratchpad_edit:
            return
        
        self.scratchpad_edit.blockSignals(True)
        if self.current_project and hasattr(self.current_project, 'scratchpad_notes'):
            self.scratchpad_edit.setPlainText(self.current_project.scratchpad_notes or '')
        else:
            self.scratchpad_edit.clear()
        self.scratchpad_edit.blockSignals(False)
    
    def _update_bottom_notes_for_segment(self, segment):
        """Update the bottom Notes tab with the current segment's notes.

        v1.10.57 Phase D: when the segment has multiple comments or any
        anchored comment, the legacy single-string editor would silently
        clobber them on the next textChanged. We detect that case and
        leave the editor empty (it'll be locked read-only by
        _update_bottom_notes_editor_lock_state, which the comments-list
        refresh calls). Otherwise — simple case, one segment-level
        comment (or none) — populate as before.
        """
        if not hasattr(self, 'bottom_notes_edit') or not self.bottom_notes_edit:
            return

        self.bottom_notes_edit.blockSignals(True)
        try:
            if segment and hasattr(segment, 'comments'):
                comments = getattr(segment, 'comments', []) or []
                is_complex = len(comments) > 1 or any(c.is_anchored for c in comments)
                if is_complex:
                    # Leave empty — the read-only state + placeholder
                    # tells the user to use the all-list above.
                    self.bottom_notes_edit.setPlainText('')
                elif comments:
                    # Exactly one unanchored segment-level comment.
                    self.bottom_notes_edit.setPlainText(comments[0].text or '')
                else:
                    self.bottom_notes_edit.setPlainText('')
            elif segment and hasattr(segment, 'notes'):
                # Pre-Phase-A segment (shouldn't happen post-migration,
                # but defensive — old in-memory objects might not have
                # the comments[] field yet).
                self.bottom_notes_edit.setPlainText(segment.notes or '')
            else:
                self.bottom_notes_edit.setPlainText('')
        finally:
            self.bottom_notes_edit.blockSignals(False)
        # Lock/unlock based on the segment's complexity.
        self._update_bottom_notes_editor_lock_state()

    def _update_proofreading_notes_for_segment(self, segment):
        """Update the Proofreading note tab with the current segment's proofreading notes (read-only, keyed by LLM)."""
        if not hasattr(self, 'bottom_proofreading_notes_display') or not self.bottom_proofreading_notes_display:
            return

        import html as html_module

        proofread = getattr(segment, 'proofreading_notes', None) if segment else None
        if not proofread:
            self.bottom_proofreading_notes_display.setHtml(
                '<span style="color: #999; font-style: italic;">No proofreading comments for this segment.</span>'
            )
            return

        # Cycle through a few distinct colours for different LLM entries
        colors = [
            ("#ff9800", "#fff3e0", "#e65100"),  # orange
            ("#2196f3", "#e3f2fd", "#0d47a1"),  # blue
            ("#4caf50", "#e8f5e9", "#1b5e20"),  # green
            ("#9c27b0", "#f3e5f5", "#4a148c"),  # purple
            ("#f44336", "#ffebee", "#b71c1c"),  # red
        ]

        html_parts = []
        for idx, (model_name, issue_text) in enumerate(proofread.items()):
            border_color, bg_color, text_color = colors[idx % len(colors)]
            escaped_model = html_module.escape(model_name)
            escaped_text = html_module.escape(issue_text).replace('\n', '<br/>')
            html_parts.append(
                f'<div style="margin-bottom: 10px; padding: 8px; background: {bg_color}; '
                f'border-left: 3px solid {border_color}; border-radius: 3px;">'
                f'<b style="color: {text_color};">{escaped_model}</b><br/>'
                f'<span style="color: #333;">{escaped_text}</span>'
                f'</div>'
            )

        self.bottom_proofreading_notes_display.setHtml(''.join(html_parts))
    
    def copy_source_to_tab_target(self):
        """Copy source to target in tab editor - works with all panels"""
        if hasattr(self, 'tabbed_panels'):
            for panel in self.tabbed_panels:
                try:
                    if hasattr(panel, 'editor_widget'):
                        source_text = panel.editor_widget.source_editor.toPlainText()
                        panel.editor_widget.target_editor.setPlainText(source_text)
                except:
                    pass
    
    def clear_tab_target(self):
        """Clear target in tab editor - works with all panels"""
        if hasattr(self, 'tabbed_panels'):
            for panel in self.tabbed_panels:
                try:
                    if hasattr(panel, 'editor_widget'):
                        panel.editor_widget.target_editor.clear()
                except:
                    pass

    def _get_voice_release_poller(self):
        """Lazy-create the GetAsyncKeyState-based release poller.

        Single instance per app. Returns ``None`` on platforms where
        polling isn't implemented (currently macOS / Linux). The poller
        installs no keyboard hook – press detection stays on
        RegisterHotKey, this just watches the key state while the chord
        is held.
        """
        existing = getattr(self, '_voice_release_poller', None)
        if existing is not None:
            return existing
        try:
            from modules.voice_release_poller import KeyReleasePoller, IS_WINDOWS
        except Exception as e:
            self.log(f"⚠ Voice release poller unavailable: {e}")
            self._voice_release_poller = None
            return None
        if not IS_WINDOWS:
            self._voice_release_poller = None
            return None
        poller = KeyReleasePoller(parent=self)
        poller.released.connect(self.stop_voice_dictation_if_recording)
        self._voice_release_poller = poller
        return poller

    def _register_voice_pushtotalk_deferred(self, qt_shortcut: str):
        """Install the push-to-talk keyboard listener and bind a shortcut.

        Called via QTimer from SuperlookupTab.register_global_hotkey so
        that pynput's blocking hook-install doesn't delay the rest of the
        global-hotkey registration during Workbench startup. Safe to call
        repeatedly (re-registration after a shortcut change is the main
        non-startup caller).
        """
        listener = self._get_voice_hotkey_listener()
        if listener is None:
            return
        listener.unregister('voice_dictate')
        if listener.register('voice_dictate', qt_shortcut):
            self.log(f"🎤 Push-to-talk armed: {qt_shortcut} (hold to dictate, release to transcribe)")
        else:
            self.log(f"⚠ Could not parse push-to-talk shortcut: {qt_shortcut!r}")

    def _get_voice_hotkey_listener(self):
        """Lazy-create the global push-to-talk hotkey listener.

        Returns the running listener instance, or None if pynput / the
        low-level keyboard hook is unavailable. Single instance per app.
        Signals are wired here (not at __init__) so they reach the
        already-existing dictation infrastructure.
        """
        if self._voice_hotkey_listener is not None:
            return self._voice_hotkey_listener
        try:
            from modules.voice_hotkey_listener import GlobalHotkeyListener
        except Exception as e:
            self.log(f"⚠ Voice hotkey listener unavailable: {e}")
            return None
        listener = GlobalHotkeyListener(self)

        def _on_chord_pressed(binding_id):
            if binding_id == 'voice_dictate':
                self.start_voice_dictation()

        def _on_chord_released(binding_id):
            if binding_id == 'voice_dictate':
                self.stop_voice_dictation_if_recording()

        listener.chord_pressed.connect(_on_chord_pressed)
        listener.chord_released.connect(_on_chord_released)
        if not listener.start():
            self.log("⚠ Voice hotkey listener failed to start – push-to-talk will not work")
            return None
        self._voice_hotkey_listener = listener
        return listener

    def stop_voice_dictation_if_recording(self):
        """Stop an active dictation recording on release (hold-to-talk).

        No-op if:
          - no recording is in progress, or
          - the user has explicitly set ``pushtotalk_mode = 'toggle'``
            (in which case release should not stop the recording – the
            user wants press-to-start / press-to-stop semantics).

        Called from the global keyboard listener on release of the
        voice_dictate chord.
        """
        try:
            mode = self.load_dictation_settings().get('pushtotalk_mode', 'hold')
        except Exception:
            mode = 'hold'
        if mode == 'toggle':
            return

        thread = getattr(self, 'dictation_thread', None)
        if thread is None:
            return
        try:
            if thread.isRunning() and getattr(thread, 'is_recording', False):
                thread.stop_recording()
                self.log("⏹️ Hold-to-talk: hotkey released, transcribing…")
                # Dismiss the listening toast immediately on user-initiated
                # stop; on_dictation_finished will also try to dismiss but
                # the visual feedback should disappear right now.
                try:
                    toast = getattr(self, '_dictation_toast', None)
                    if toast is not None:
                        toast.dismiss()
                        self._dictation_toast = None
                except Exception:
                    pass
        except Exception:
            pass

    def start_voice_dictation(self):
        """Start or stop voice dictation (toggle behavior).

        Old behaviour (pre-Vosk): if always-on was active, the dictation
        hotkey would toggle it OFF instead of dictating, because both
        paths used Whisper and shared the mic exclusively.

        New behaviour (Vosk + faster-whisper coexisting): always-on uses
        Vosk for command recognition, push-to-talk uses faster-whisper
        for running-text dictation. They're different engines and SHOULD
        coexist – we just need to mute the always-on listener for the
        duration of the dictation so the dictated text isn't half-
        interpreted as a command. The mic is handed back to Vosk via
        ``_resume_alwayson_after_dictation`` once the dictation thread
        signals ``finished``.
        """
        # Debounce: the in-editor QShortcut and the global keyboard listener
        # can both fire start_voice_dictation for the same physical press
        # (the listener fires on the OS hook ~1 ms before Qt routes the
        # event to the QShortcut). Without this guard the second call sees
        # is_recording=True and aborts the recording milliseconds after it
        # started. 200 ms window comfortably covers the worst-case Qt
        # dispatch lag without affecting genuinely re-issued presses.
        import time as _time
        now_ms = int(_time.monotonic() * 1000)
        if now_ms - self._voice_dictate_last_press_ms < 200:
            return
        self._voice_dictate_last_press_ms = now_ms

        # If always-on is currently running, pause it (don't kill it) so
        # push-to-talk can use the mic alone, then resume after.
        alwayson_was_running = bool(
            self.voice_listener and self.voice_listener.is_listening)
        if alwayson_was_running:
            try:
                self.voice_listener.pause()
                self.log("⏸️ Always-on paused for push-to-talk dictation")
            except Exception:
                pass
        # Stash the flag so the dictation-finished callback knows whether
        # to resume always-on or leave it stopped.
        self._alwayson_was_running_before_dictation = alwayson_was_running

        # Debug: Check thread state
        has_thread = hasattr(self, 'dictation_thread')
        thread_exists = has_thread and self.dictation_thread is not None
        thread_running = thread_exists and self.dictation_thread.isRunning()
        is_recording = thread_exists and getattr(self.dictation_thread, 'is_recording', False)

        self.log(f"🔍 DEBUG: has_thread={has_thread}, thread_exists={thread_exists}, thread_running={thread_running}, is_recording={is_recording}")

        # Check if already recording - if so, stop it
        if thread_running:
            if is_recording:
                # Stop recording early
                self.dictation_thread.stop_recording()
                self.log("⏹️ Stopping recording early...")
                # Dismiss the "🎤 Listening…" toast immediately on the
                # user-initiated stop. on_dictation_finished will also
                # call dismiss() once the thread actually finishes
                # transcribing, but that can be a couple of seconds
                # later – the user pressed the shortcut to STOP, so the
                # visual feedback should disappear right away.
                try:
                    toast = getattr(self, '_dictation_toast', None)
                    if toast is not None:
                        toast.dismiss()
                        self._dictation_toast = None
                except Exception:
                    pass
                return
            else:
                # Thread is running but not recording (probably transcribing/loading model)
                self.log("⚠️ Thread is running but not recording - waiting for it to finish...")
                return

        try:
            # Load dictation settings
            dictation_settings = self.load_dictation_settings()
            model_name = dictation_settings.get('model', 'base')
            max_duration = dictation_settings.get('max_duration', 10)
            lang_setting = dictation_settings.get('language', 'Auto (use project target language)')

            # Push-to-talk dictation engine. Three sources, in order:
            #
            #   1. User's explicit ``pushtotalk_engine`` setting (added
            #      in v1.9.441 as a separate dropdown in the Voice tab)
            #   2. ``'auto'`` → mirror the Always-On engine
            #   3. Always-On engine (with Vosk → faster-whisper since Vosk
            #      is commands-only and push-to-talk needs running text)
            #
            # Legacy ``recognition_engine='local'`` also maps to faster-whisper.
            ptt_engine = dictation_settings.get('pushtotalk_engine', 'auto')
            if ptt_engine == 'auto':
                always_on_engine = dictation_settings.get('recognition_engine', 'vosk')
                if always_on_engine in ('vosk', 'local'):
                    ptt_engine = 'faster_whisper'
                elif always_on_engine == 'api':
                    ptt_engine = 'api'
                else:
                    ptt_engine = 'faster_whisper'
            elif ptt_engine == 'local':  # very old legacy alias
                ptt_engine = 'faster_whisper'
            use_api = ptt_engine == 'api'
            api_key = None
            if use_api:
                api_keys = self.load_api_keys()
                api_key = api_keys.get('openai') or api_keys.get('openai_api_key')
                if not api_key:
                    QMessageBox.warning(
                        self, "OpenAI API Key Required",
                        "To use OpenAI Whisper API, please set your OpenAI API key in:\n\n"
                        "Settings → AI Settings → OpenAI API Key"
                    )
                    return

            # Determine language. Two flavours of "Auto":
            #   - "Auto-detect (Whisper picks per utterance)" – pass
            #     language=None to Whisper so it detects per utterance.
            #     Right for mixed-language workflows.
            #   - "Auto (use project target language)" – read the
            #     Workbench project's target language and pin Whisper
            #     to it. Right for single-language workflows.
            if lang_setting.startswith('Auto-detect'):
                # Sentinel value 'auto' is converted to None by
                # QuickDictationThread before being passed to Whisper.
                target_lang = '__autodetect__'
            elif lang_setting == 'Auto (use project target language)':
                target_lang = getattr(self, 'target_language', 'English')
            else:
                # Use override language from settings
                target_lang = lang_setting

            # Map language names to Whisper codes
            lang_map = {
                'English': 'en',
                'Dutch': 'nl',
                'German': 'de',
                'French': 'fr',
                'Spanish': 'es',
                'Italian': 'it',
                'Portuguese': 'pt',
                'Polish': 'pl',
                'Russian': 'ru',
                'Chinese': 'zh',
                'Japanese': 'ja',
                'Korean': 'ko'
            }
            if target_lang == '__autodetect__':
                # 'auto' is the sentinel that QuickDictationThread maps
                # to language=None at transcribe time, triggering
                # Whisper's per-utterance language detection.
                lang_code = 'auto'
            else:
                lang_code = lang_map.get(target_lang, 'auto')

            # Create dictation thread with user settings. mic_device is
            # the saved device *name* from the Voice tab's Microphone
            # dropdown; the thread resolves it to a sounddevice index at
            # record time via modules.mic_devices (None ⇒ OS default).
            # initial_prompt + replacements bias the Whisper decoder
            # toward known vocabulary (defaults + custom + optional
            # active termbase) – see build_voice_initial_prompt() and
            # modules/voice_vocabulary.py.
            mic_device = dictation_settings.get('mic_device')
            vocab_settings = self.load_voice_vocabulary_settings()
            self.dictation_thread = QuickDictationThread(
                model_name=model_name,
                language=lang_code,
                duration=max_duration,
                use_api=use_api,
                api_key=api_key,
                mic_device=mic_device,
                initial_prompt=self.build_voice_initial_prompt(),
                replacements=vocab_settings.get('replacements', []),
            )

            # Connect signals
            self.dictation_thread.transcription_ready.connect(self.on_dictation_complete)
            self.dictation_thread.status_update.connect(self.on_dictation_status)
            self.dictation_thread.error_occurred.connect(self.on_dictation_error)
            self.dictation_thread.finished.connect(self.on_dictation_finished)
            self.dictation_thread.model_loading_started.connect(self.on_model_loading_started)
            self.dictation_thread.model_loading_finished.connect(self.on_model_loading_finished)

            # Change button appearance
            self._set_dictation_button_recording(True)

            # Start recording
            if use_api:
                self.log(f"▶️ Starting dictation thread (OpenAI Whisper API, language={lang_code}, duration={max_duration}s)...")
            else:
                self.log(f"▶️ Starting dictation thread (local Whisper model={model_name}, language={lang_code}, duration={max_duration}s)...")
            # Visual cue so the user knows the hotkey was received and the
            # mic is now hot. Push-to-talk fires from Ctrl+Shift+Space in any
            # app via the global hotkey; without this there's no feedback
            # that recording started. Replaces the earlier QApplication.beep()
            # which was unreliable (many users mute system sound) and harsh
            # on Windows (the system Ding tone reads as an error).
            try:
                from modules.dictation_toast import show_dictation_toast
                self._dictation_toast = show_dictation_toast(self)
            except Exception as _toast_err:
                print(f"[Dictation toast] Failed to show: {_toast_err}")
                self._dictation_toast = None
            self.dictation_thread.start()

        except Exception as e:
            self._set_dictation_button_recording(False)
            import traceback
            error_details = traceback.format_exc()
            self.log(f"")
            self.log(f"❌ ERROR starting dictation:")
            self.log(f"   {str(e)}")
            self.log(f"")
            self.log(f"Full traceback:")
            self.log(error_details)
            self.log(f"")
            QMessageBox.critical(self, "Dictation Error", f"Failed to start dictation:\n\n{str(e)}\n\nCheck the Log tab for full details.")

    def on_dictation_complete(self, text):
        """Handle completed dictation - check for voice commands first"""
        dictation_settings = self.load_dictation_settings()
        voice_commands_enabled = dictation_settings.get('voice_commands_enabled', True)

        # Voice commands first (if enabled).
        if voice_commands_enabled and hasattr(self, 'voice_command_manager'):
            was_command, result = self.voice_command_manager.process_spoken_text(text)
            if was_command:
                self.log(f"🎤 Voice command: {text} → {result}")
                self.status_bar.showMessage(f"🎤 {result}", 3000)
                return

        # Otherwise route as dictation text – same cross-app path Always-On
        # uses, so push-to-talk works in any app.
        self._insert_dictated_text(text)

    def _insert_dictated_text(self, text: str):
        """Route dictated text to whatever target makes sense.

        Preference order:
        1. Focused Supervertaler grid editor (EditableGridTextEditor) →
           direct insert with cursor handling.
        2. Focused tabbed-panel target editor → direct insert.
        3. Any other focused app → AHK SendText / osascript keystroke /
           pynput type, via CrossPlatformKeySender.type_text.
        4. Last-resort fallback → drop on clipboard so the user can paste
           manually with whatever shortcut their app uses.

        Used by both ``on_dictation_complete`` (F9 push-to-talk and the
        global Voice hotkey) and ``_on_alwayson_dictation``
        (continuous listener) so behaviour is identical across surfaces.
        """
        focused_widget = QApplication.focusWidget()

        if isinstance(focused_widget, EditableGridTextEditor):
            current_text = focused_widget.toPlainText()
            if current_text:
                focused_widget.setPlainText(current_text + " " + text)
            else:
                focused_widget.setPlainText(text)
            cursor = focused_widget.textCursor()
            cursor.movePosition(cursor.MoveOperation.End)
            focused_widget.setTextCursor(cursor)
            self.status_bar.showMessage(f"✅ Dictation: {text[:50]}...", 3000)
            return

        # Tabbed panel editor (legacy list view).
        if hasattr(self, 'tabbed_panels'):
            for panel in self.tabbed_panels:
                try:
                    if hasattr(panel, 'editor_widget') and panel.editor_widget.target_editor.hasFocus():
                        target = panel.editor_widget.target_editor
                        current_text = target.toPlainText()
                        if current_text:
                            target.setPlainText(current_text + " " + text)
                        else:
                            target.setPlainText(text)
                        cursor = target.textCursor()
                        cursor.movePosition(cursor.MoveOperation.End)
                        target.setTextCursor(cursor)
                        self.status_bar.showMessage(
                            f"✅ Dictation: {text[:50]}...", 3000)
                        return
                except Exception:
                    pass

        # Cross-app: type into whatever has keyboard focus.
        try:
            from modules.platform_helpers import CrossPlatformKeySender
            sender = CrossPlatformKeySender()
            if sender.is_available and sender.type_text(text):
                self.log(f"💬 Dictated: {text}")
                self.status_bar.showMessage(
                    f"💬 Dictated: {text[:50]}...", 3000)
                return
        except Exception as e:
            self.log(f"⚠ Dictation type failed: {e}")

        # Last-resort clipboard fallback.
        try:
            QApplication.clipboard().setText(text)
            self.log(
                f"💬 Dictated → clipboard (auto-typing unavailable): {text}")
            self.status_bar.showMessage(
                f"📋 Copied to clipboard: {text[:50]}...", 4000)
        except Exception:
            self.log(f"💬 Dictation (no target): {text}")
            self.status_bar.showMessage(f"💬 {text[:50]}...", 3000)

    def on_dictation_status(self, message):
        """Show dictation status"""
        self.log(message)  # Also log to Log tab
        self.status_bar.showMessage(message, 2000)

    def on_dictation_error(self, error_msg):
        """Handle dictation error"""
        self._set_dictation_button_recording(False)

        # Log the full error to Log tab
        self.log("")
        self.log("❌ SUPERVOICE ERROR:")
        self.log(error_msg)
        self.log("")

        self.status_bar.showMessage(f"❌ Voice dictation error", 3000)

        # Hand the mic back to always-on if we paused it for this dictation.
        self._resume_alwayson_after_dictation()

        # Show detailed error dialog for FFmpeg issues
        if "FFmpeg" in error_msg or "ffmpeg" in error_msg:
            QMessageBox.warning(self, "FFmpeg Required", error_msg)

    def on_dictation_finished(self):
        """Handle dictation thread finishing"""
        self.log("✓ Dictation thread finished")
        self._set_dictation_button_recording(False)
        # Dismiss the "🎤 Listening…" toast if it's still up.
        try:
            toast = getattr(self, '_dictation_toast', None)
            if toast is not None:
                toast.dismiss()
                self._dictation_toast = None
        except Exception:
            pass
        # Hand the mic back to always-on if we paused it for this dictation.
        self._resume_alwayson_after_dictation()

    def _resume_alwayson_after_dictation(self):
        """Re-enable the always-on listener if push-to-talk had paused it.

        Idempotent – safe to call from both the success and error paths.
        Only resumes if (a) we set the flag in ``start_voice_dictation``
        AND (b) the listener is still around AND in a paused state.
        """
        if not getattr(self, '_alwayson_was_running_before_dictation', False):
            return
        self._alwayson_was_running_before_dictation = False
        try:
            if (self.voice_listener
                    and self.voice_listener.is_listening
                    and getattr(self.voice_listener, 'is_paused', False)):
                self.voice_listener.resume()
                self.log("▶️ Always-on resumed")
        except Exception as e:
            self.log(f"⚠ Could not resume always-on listener: {e}")

    def on_model_loading_started(self, model_name):
        """Handle Whisper model loading/download starting"""
        self.is_loading_model = True
        self.loading_model_name = model_name
        model_sizes = {
            'tiny': '75 MB',
            'base': '142 MB',
            'small': '466 MB',
            'medium': '1.5 GB',
            'large': '2.9 GB'
        }
        size = model_sizes.get(model_name, 'unknown size')

        # Check if model exists
        import os
        cache_dir = self._get_whisper_cache_path()
        model_files = [
            f"{model_name}.pt",
            f"{model_name}.en.pt",
            f"{model_name}-v3.pt"
        ]
        model_exists = any(os.path.exists(os.path.join(cache_dir, f)) for f in model_files)

        if model_exists:
            self.status_bar.showMessage(f"🎤 Voice: Loading '{model_name}' model...", 10000)
            self.log(f"⏳ Loading Whisper model '{model_name}' from cache...")
        else:
            self.status_bar.showMessage(f"📥 Voice: Downloading '{model_name}' model ({size})...", 60000)
            self.log(f"")
            self.log(f"📥 DOWNLOADING Whisper model '{model_name}' ({size})...")
            self.log(f"   This is a one-time download. Please be patient!")
            self.log(f"   ⚠️ DO NOT CLOSE SUPERVERTALER until download completes!")
            self.log(f"   Location: {cache_dir}")
            self.log(f"")

    def on_model_loading_finished(self):
        """Handle Whisper model loading/download finishing"""
        model_name = self.loading_model_name  # Save before clearing
        self.is_loading_model = False
        self.loading_model_name = None
        self.status_bar.showMessage(f"🎤 Voice: '{model_name}' model ready", 3000)
        self.log(f"✅ Model '{model_name}' loaded successfully")

    def _dictation_shortcut_label(self) -> str:
        """Return the current voice-dictation shortcut as a display suffix,
        e.g. " (Ctrl+Shift+Space)", or "" when the shortcut is unbound.

        The dictation key is user-configurable (Settings → Keyboard Shortcuts,
        ``voice_dictate``), so the Dictate/Stop buttons read it live rather than
        hardcoding a key that goes stale on rebind. (The old "(F9)" label was
        wrong — the default is Ctrl+Shift+Space.)
        """
        sm = getattr(self, 'shortcut_manager', None)
        if sm is None:
            return ""
        try:
            key = sm.get_shortcut('voice_dictate')
        except Exception:
            return ""
        if not key:
            return ""
        try:
            return f" ({format_shortcut_for_display(key)})"
        except Exception:
            return f" ({key})"

    def _set_dictation_button_recording(self, is_recording):
        """Change dictate button appearance based on recording state"""
        suffix = self._dictation_shortcut_label()
        # Update grid view dictate button
        if hasattr(self, 'tab_dictate_btn'):
            button = self.tab_dictate_btn
            if is_recording:
                button.setText(f"⏹️ Stop{suffix}")
                button.setStyleSheet("background-color: #D32F2F; color: white; font-weight: bold;")
            else:
                button.setText(f"🎤 Dictate{suffix}")
                button.setStyleSheet("background-color: #4CAF50; color: white; font-weight: bold;")

        # Update list view dictate button (legacy, for backwards compatibility)
        if hasattr(self, 'tabbed_panels'):
            for panel in self.tabbed_panels:
                try:
                    # Use stored reference to dictate button
                    if hasattr(panel, 'editor_widget') and hasattr(panel.editor_widget, 'dictate_btn'):
                        button = panel.editor_widget.dictate_btn
                        if is_recording:
                            button.setText(f"⏹️ Stop{suffix}")
                            button.setStyleSheet("background-color: #D32F2F; color: white; font-weight: bold;")
                        else:
                            button.setText(f"🎤 Dictate{suffix}")
                            button.setStyleSheet("background-color: #4CAF50; color: white; font-weight: bold;")
                except:
                    pass

    def save_tab_segment(self):
        """Save current segment in tab editor"""
        if not hasattr(self, 'tab_current_segment_id') or not self.tab_current_segment_id:
            return
        
        # Find segment and save to TM if appropriate
        if self.current_project and hasattr(self.current_project, 'segments'):
            for seg in self.current_project.segments:
                if seg.id == self.tab_current_segment_id:
                    # Save to TM ONLY if status is confirmed (user explicitly approved)
                    if seg.status == 'confirmed' and seg.target.strip():
                        try:
                            self.save_segment_to_activated_tms(seg.source, seg.target)
                            self.log(f"✓ Saved segment {self.tab_current_segment_id} to TM")
                        except Exception as e:
                            self.log(f"✓ Saved segment {self.tab_current_segment_id} (TM save failed: {e})")
                    else:
                        self.log(f"✓ Saved segment {self.tab_current_segment_id}")
                    break
        else:
            self.log(f"✓ Saved segment {self.tab_current_segment_id}")
    
    def save_tab_segment_and_next(self):
        """Save current segment and move to next in tab editor"""
        self.save_tab_segment()
        
        # Move to next segment in grid view
        if hasattr(self, 'table') and self.table:
            current_row = self.table.currentRow()
            if current_row < self.table.rowCount() - 1:
                self.table.setCurrentCell(current_row + 1, self.table.currentColumn())
    
    # ========================================================================
    # GRID-BASED EDITING HANDLERS (for toolbar below grid)
    # ========================================================================
    
    def filter_on_selected_text(self):
        """Filter based on currently selected text in source or target column.
        
        Toggle behavior: If filters are already active, pressing Ctrl+Shift+F 
        will clear the filters. Otherwise, filter on selected text.
        """
        from PyQt6.QtWidgets import QApplication
        
        # Check if filters are currently active FIRST (for toggle behavior)
        source_filter_text = self._get_line_edit_text('source_filter').strip() if hasattr(self, 'source_filter') else ""
        target_filter_text = self._get_line_edit_text('target_filter').strip() if hasattr(self, 'target_filter') else ""
        filters_active = bool(source_filter_text or target_filter_text)
        
        # Toggle: if filters are active, clear them and return
        if filters_active:
            self.clear_filters()
            self.log(f"🔍 Filters cleared ({format_shortcut_for_display('Ctrl+Shift+F')} toggle)")
            return
        
        # No filters active - try to filter on selected text
        focused_widget = QApplication.focusWidget()
        
        selected_text = ""
        is_source = False
        is_target = False
        
        # Check if it's a text editor widget (source or target)
        if focused_widget and isinstance(focused_widget, (EditableGridTextEditor, ReadOnlyGridTextEditor)):
            cursor = focused_widget.textCursor()
            selected_text = cursor.selectedText().strip()
            
            # Determine if it's source or target by checking which column it's in
            if hasattr(self, 'table') and self.table:
                for row in range(self.table.rowCount()):
                    # Check source column (index 2)
                    source_widget = self.table.cellWidget(row, 2)
                    if source_widget == focused_widget:
                        is_source = True
                        break
                    # Check target column (index 3)
                    target_widget = self.table.cellWidget(row, 3)
                    if target_widget == focused_widget:
                        is_target = True
                        break
        
        # Strip invisible character markers so filtering matches clean segment text
        if selected_text and hasattr(self, 'reverse_invisible_replacements'):
            selected_text = self.reverse_invisible_replacements(selected_text)
            selected_text = selected_text.strip()

        if not selected_text:
            self.log("⚠️ No text selected. Select text in source or target column first.")
            return

        # Put selected text in appropriate filter box and apply filter
        if is_source and hasattr(self, 'source_filter') and self.source_filter:
            self.source_filter.setText(selected_text)
            self.apply_filters()
            self.log(f"🔍 Filtering source on: '{selected_text}'")
        elif is_target and hasattr(self, 'target_filter') and self.target_filter:
            self.target_filter.setText(selected_text)
            self.apply_filters()
            self.log(f"🔍 Filtering target on: '{selected_text}'")
    
    def copy_source_to_grid_target(self):
        """Copy source to target in currently selected grid row"""
        if not hasattr(self, 'table') or not self.table:
            return

        current_row = self.table.currentRow()
        if current_row < 0 or not self.current_project or current_row >= len(self.current_project.segments):
            return

        segment = self.current_project.segments[current_row]
        segment.target = segment.source

        # Update grid cell - target is column 3 (ID=0, Status=1, Source=2, Target=3)
        # v1.9.306: Apply invisible markers for display
        target_widget = self.table.cellWidget(current_row, 3)
        if target_widget and isinstance(target_widget, EditableGridTextEditor):
            display_text = self.apply_invisible_replacements(segment.source) if hasattr(self, 'apply_invisible_replacements') else segment.source
            target_widget.setPlainText(display_text)
        
        self.project_modified = True
        self.log(f"📋 Copied source to target in segment {segment.id}")
    
    def clear_grid_target(self):
        """Clear target in currently selected grid row"""
        if not hasattr(self, 'table') or not self.table:
            return
        
        current_row = self.table.currentRow()
        if current_row < 0 or not self.current_project or current_row >= len(self.current_project.segments):
            return
        
        segment = self.current_project.segments[current_row]
        segment.target = ""
        
        # Update grid cell - target is column 3 (ID=0, Status=1, Source=2, Target=3)
        target_widget = self.table.cellWidget(current_row, 3)
        if target_widget and isinstance(target_widget, EditableGridTextEditor):
            target_widget.clear()
        
        self.project_modified = True
        self.log(f"🗑️ Cleared target in segment {segment.id}")
    
    def save_grid_segment(self):
        """Save current segment from grid"""
        if not hasattr(self, 'table') or not self.table:
            return
        
        current_row = self.table.currentRow()
        if current_row < 0 or current_row >= len(self.current_project.segments):
            return
        
        segment = self.current_project.segments[current_row]
        
        # Save to TM ONLY if status is confirmed (user explicitly approved)
        if segment.status == 'confirmed' and segment.target.strip():
            try:
                self.save_segment_to_activated_tms(segment.source, segment.target)
                self.log(f"💾 Saved segment {segment.id} to TM")
            except Exception as e:
                self.log(f"💾 Saved segment {segment.id} (TM save failed: {e})")
        else:
            self.log(f"💾 Saved segment {segment.id}")
    
    def save_grid_segment_and_next(self):
        """Save current segment and move to next in grid"""
        self.save_grid_segment()
        
        if hasattr(self, 'table') and self.table:
            current_row = self.table.currentRow()
            if current_row < self.table.rowCount() - 1:
                next_row = current_row + 1
                
                # ⚡ INSTANT NAVIGATION
                self._ctrl_enter_navigation = True
                
                self.table.setCurrentCell(next_row, 3)  # Column 3 = Target (widget column)
                # Get the target cell widget and set focus to it
                target_widget = self.table.cellWidget(next_row, 3)
                if target_widget:
                    target_widget.setFocus()
                    # Move cursor to end of text
                    target_widget.moveCursor(QTextCursor.MoveOperation.End)
    
    # ========================================================================
    # KEYBOARD NAVIGATION SHORTCUTS
    # ========================================================================
    
    def select_previous_match(self):
        """Cycle to previous match (Ctrl+Up)

        Context-aware behavior:
        - If Compare Panel tab is active: navigate MT/TM list depending on focused box
        - If Translation Results tab is active: delegate to visible results panel
        - Otherwise: do nothing (avoid acting on hidden panels)
        """
        mode = self._get_active_match_shortcut_mode()
        if mode == 'compare':
            self._compare_panel_nav_active_box(-1)
            return
        if mode == 'results':
            for panel in self._iter_visible_results_panels():
                try:
                    if hasattr(panel, 'select_previous_match'):
                        panel.select_previous_match()
                        break
                except Exception as e:
                    self.log(f"Error selecting previous match: {e}")
            return
    
    def select_next_match(self):
        """Cycle to next match (Ctrl+Down)

        Context-aware behavior:
        - If Compare Panel tab is active: navigate MT/TM list depending on focused box
        - If Translation Results tab is active: delegate to visible results panel
        - Otherwise: do nothing (avoid acting on hidden panels)
        """
        mode = self._get_active_match_shortcut_mode()
        if mode == 'compare':
            self._compare_panel_nav_active_box(1)
            return
        if mode == 'results':
            for panel in self._iter_visible_results_panels():
                try:
                    if hasattr(panel, 'select_next_match'):
                        panel.select_next_match()
                        break
                except Exception as e:
                    self.log(f"Error selecting next match: {e}")
            return
    
    def insert_match_by_number(self, match_number: int):
        """Insert match by number (Ctrl+1-9)

        Context-aware behavior:
        - If Compare Panel tab is active: insert from Compare Panel MT/TM list depending on focused box
        - If Translation Results tab is active: delegate to visible results panel
        - Otherwise: do nothing (avoid acting on hidden panels)
        """
        mode = self._get_active_match_shortcut_mode()
        if mode == 'compare':
            try:
                self._insert_compare_panel_match_by_number(match_number)
            except Exception as e:
                self.log(f"Error inserting Compare Panel match #{match_number}: {e}")
            return
        if mode == 'results':
            for panel in self._iter_visible_results_panels():
                try:
                    if hasattr(panel, 'insert_match_by_number'):
                        if panel.insert_match_by_number(match_number):
                            break
                except Exception as e:
                    self.log(f"Error inserting match #{match_number}: {e}")
            return
    
    def _handle_termlens_shortcut(self, key_num: int):
        """Handle TermLens shortcut with double-tap detection for terms 11-20
        
        TermLens numbering starts at 1 (Alt+1..Alt+9). Alt+0 is reserved for the Compare Panel.
        
        Single tap (Alt+N): Insert term N (1-9)
        Double tap (Alt+N,N within 300ms): Undo first insert, then insert term N+10 (11, 22, ..., 99)
        """
        import time

        # Alt+0 is reserved for the Compare Panel.
        if key_num == 0:
            return

        current_time = time.time()
        double_tap_threshold = 0.3  # 300ms window for double-tap
        
        # Check if this is a double-tap (same key within threshold)
        if (hasattr(self, '_termlens_last_key') and 
            self._termlens_last_key == key_num and 
            hasattr(self, '_termlens_last_time') and
            (current_time - self._termlens_last_time) < double_tap_threshold):
            # Double-tap detected! 
            # First, undo the single-tap insertion
            current_widget = self._get_current_target_widget()
            if current_widget and hasattr(current_widget, 'undo'):
                current_widget.undo()
            
            # Now insert term 10-19 (displayed as 00, 11, ..., 99)
            term_index = key_num + 10
            self._termlens_last_key = None  # Reset to prevent triple-tap
            self._termlens_last_time = 0
            self.insert_termlens_term_by_number(term_index)
        else:
            # Single tap - insert term 1-9
            self._termlens_last_key = key_num
            self._termlens_last_time = current_time
            self.insert_termlens_term_by_number(key_num)
    
    def _get_current_target_widget(self):
        """Get the current target cell text widget"""
        if hasattr(self, 'table') and self.table:
            current_row = self.table.currentRow()
            if current_row >= 0:
                return self.table.cellWidget(current_row, 3)  # Column 3 = Target
        return None
    
    def insert_termlens_term_by_number(self, term_number: int):
        """Insert term from TermLens by number (0-19)"""
        if hasattr(self, 'termlens_widget') and self.termlens_widget:
            try:
                if hasattr(self.termlens_widget, 'insert_term_by_number'):
                    self.termlens_widget.insert_term_by_number(term_number)
            except Exception as e:
                self.log(f"Error inserting TermLens term #{term_number}: {e}")
    
    def insert_selected_match(self):
        """Insert currently selected match (Ctrl+Space)

        Context-aware behavior:
        - If Compare Panel tab is active: insert current MT translation or TM target depending on focused box
        - If Translation Results tab is active: delegate to visible results panel
        - Otherwise: do nothing (avoid acting on hidden panels)
        """
        mode = self._get_active_match_shortcut_mode()
        if mode == 'compare':
            try:
                self._insert_compare_panel_current_match()
            except Exception as e:
                self.log(f"Error inserting Compare Panel selected match: {e}")
            return
        if mode == 'results':
            for panel in self._iter_visible_results_panels():
                try:
                    if hasattr(panel, 'insert_selected_match'):
                        if panel.insert_selected_match():
                            break
                except Exception as e:
                    self.log(f"Error inserting selected match: {e}")
            return

    def _get_active_match_shortcut_mode(self) -> str:
        """Return active shortcut context for match shortcuts.

        Returns:
            'match' if Match Panel tab is active,
            'results' if Translation Results tab is active,
            '' otherwise.
        """
        if hasattr(self, 'right_tabs') and self._widget_is_alive(self.right_tabs):
            try:
                current = self.right_tabs.currentWidget()
            except Exception:
                current = None
            if current is not None:
                if hasattr(self, 'match_panel_widget') and self.match_panel_widget and current is self.match_panel_widget:
                    return 'match'
                if hasattr(self, 'translation_results_panel') and self.translation_results_panel and current is self.translation_results_panel:
                    return 'results'
        return ''

    def _iter_visible_results_panels(self):
        """Yield results panels that are visible to the user (tab-selected)."""
        if not hasattr(self, 'results_panels') or not self.results_panels:
            return
        for panel in self.results_panels:
            try:
                if panel and hasattr(panel, 'isVisible') and panel.isVisible():
                    yield panel
            except Exception:
                continue

    def _compare_panel_nav_active_box(self, direction: int):
        """Navigate Compare Panel matches based on which box is focused."""
        if not hasattr(self, 'compare_panel') or not self.compare_panel:
            return
        if not hasattr(self, 'right_tabs') or not self._widget_is_alive(self.right_tabs):
            return
        if self.right_tabs.currentWidget() is not self.compare_panel:
            return

        focus_widget = QApplication.focusWidget()
        if hasattr(self, 'compare_panel_mt') and focus_widget is self.compare_panel_mt:
            self._compare_panel_nav_mt(direction)
            return
        if hasattr(self, 'compare_panel_tm_source') and focus_widget is self.compare_panel_tm_source:
            self._compare_panel_nav_tm(direction)
            return
        if hasattr(self, 'compare_panel_tm_target') and focus_widget is self.compare_panel_tm_target:
            self._compare_panel_nav_tm(direction)
            return

        # Default: TM navigation (more "match-like" than MT)
        self._compare_panel_nav_tm(direction)

    def _insert_compare_panel_current_match(self):
        """Insert currently shown Compare Panel text based on focused box."""
        if not hasattr(self, 'compare_panel') or not self.compare_panel:
            return
        if not hasattr(self, 'right_tabs') or not self._widget_is_alive(self.right_tabs):
            return
        if self.right_tabs.currentWidget() is not self.compare_panel:
            return

        focus_widget = QApplication.focusWidget()
        if hasattr(self, 'compare_panel_mt') and focus_widget is self.compare_panel_mt:
            text = self.compare_panel_mt.toPlainText().strip()
            if text and not text.startswith('('):
                self.on_match_inserted(text)
            return

        # Default to inserting TM target
        if hasattr(self, 'compare_panel_tm_target'):
            text = self.compare_panel_tm_target.toPlainText().strip()
            if text and not text.startswith('('):
                self.on_match_inserted(text)

    def _handle_compare_panel_alt0_shortcut(self):
        """Handle Alt+0 insertion from Match Panel.

        Alt+0 inserts TM Target from Match Panel (works regardless of which right panel tab is selected).
        """
        # Always try to insert TM Target from Match Panel if available
        # (No longer requires Match Panel tab to be selected)
        if hasattr(self, 'match_panel_tm_target'):
            text = self.match_panel_tm_target.toPlainText().strip()
            if text and not text.startswith('('):
                self._replace_current_target_segment_text(text, source_label='TM Target (Match Panel)')
                return

        # Legacy Compare Panel support (not currently used)
        mode = self._get_active_match_shortcut_mode()
        if mode != 'compare':
            return

        import time
        current_time = time.time()
        double_tap_threshold = 0.3  # 300ms window
        key_num = 0

        if (hasattr(self, '_compare_panel_last_key') and
            self._compare_panel_last_key == key_num and
            hasattr(self, '_compare_panel_last_time') and
            (current_time - self._compare_panel_last_time) < double_tap_threshold):
            # Double-tap: undo MT insert, then insert TM Target
            current_widget = self._get_current_target_widget()
            if current_widget and hasattr(current_widget, 'undo'):
                current_widget.undo()
            self._compare_panel_last_key = None
            self._compare_panel_last_time = 0
            if hasattr(self, 'compare_panel_tm_target'):
                text = self.compare_panel_tm_target.toPlainText().strip()
                if text and not text.startswith('('):
                    self._replace_current_target_segment_text(text, source_label='TM Target (Compare Panel)')
            return

        # Single tap: insert MT
        self._compare_panel_last_key = key_num
        self._compare_panel_last_time = current_time
        if hasattr(self, 'compare_panel_mt'):
            text = self.compare_panel_mt.toPlainText().strip()
            if text and not text.startswith('('):
                self._replace_current_target_segment_text(text, source_label='MT (Compare Panel)')

    def _replace_current_target_segment_text(self, new_text: str, source_label: str = ""):
        """Replace the entire current target segment text (single undo step).

        This is used for Compare Panel quick-insert shortcuts like Alt+0 / Alt+0,0,
        where the user expects a full replacement (not insertion at cursor).
        """
        try:
            if not self.current_project or not self.table:
                return

            row = self.table.currentRow()
            if row < 0:
                return

            id_item = self.table.item(row, 0)
            if not id_item:
                self.log(f"⚠️ No segment ID found at row {row}")
                return

            try:
                segment_id = int(id_item.text())
            except (ValueError, AttributeError):
                self.log(f"⚠️ Could not parse segment ID from row {row}")
                return

            segment = next((seg for seg in self.current_project.segments if seg.id == segment_id), None)
            if not segment:
                self.log(f"⚠️ Could not find segment with ID {segment_id}")
                return

            target_widget = self.table.cellWidget(row, 3)
            if target_widget and isinstance(target_widget, QTextEdit):
                from PyQt6.QtGui import QTextCursor

                # Strip outer wrapping tags for display if setting is enabled
                display_text = new_text
                if self.hide_outer_wrapping_tags:
                    display_text, _ = strip_outer_wrapping_tags(display_text)

                cursor = target_widget.textCursor()
                cursor.beginEditBlock()
                cursor.select(QTextCursor.SelectionType.Document)
                cursor.insertText(display_text)
                cursor.endEditBlock()

                # Store full text (with tags) in segment, but use displayed text if tags are hidden
                segment.target = new_text  # Keep full text with tags
                target_widget.setFocus()
                target_widget.moveCursor(QTextCursor.MoveOperation.End)

                label = f" ({source_label})" if source_label else ""
                self.log(f"✓ Replaced target text in segment {segment.id}{label}")
                self._play_sound_effect('match_inserted')
                return

            # Fallback: no editor widget, update data and (if possible) update cell
            segment.target = new_text
            if target_widget and hasattr(target_widget, 'setPlainText'):
                # Strip outer wrapping tags if setting is enabled
                display_text = new_text
                if self.hide_outer_wrapping_tags:
                    display_text, _ = strip_outer_wrapping_tags(display_text)
                target_widget.setPlainText(display_text)
            label = f" ({source_label})" if source_label else ""
            self.log(f"✓ Replaced target text in segment {segment_id}{label}")
            self._play_sound_effect('match_inserted')

        except Exception as e:
            self.log(f"Error replacing target text: {e}")
            import traceback
            traceback.print_exc()

    def _play_sound_effect(self, event: str):
        """Play a minimalist UI sound effect (currently uses OS beep).

        Event is informational for future expansion.
        """
        try:
            # Prefer cached in-memory value if available (avoids repeated file reads)
            enabled = getattr(self, 'enable_sound_effects', None)
            if enabled is None:
                settings = self.load_general_settings() if hasattr(self, 'load_general_settings') else {}
                enabled = settings.get('enable_sound_effects', False)

            if not enabled:
                return

            # Per-event mapping (defaults provided by general settings defaults)
            sound_map = getattr(self, 'sound_effects_map', None)
            if sound_map is None:
                settings = self.load_general_settings() if hasattr(self, 'load_general_settings') else {}
                sound_map = settings.get('sound_effects_map', {}) if isinstance(settings, dict) else {}

            sound_key = None
            if isinstance(sound_map, dict):
                sound_key = sound_map.get(event)

            # Windows: MessageBeep tends to be more audible than QApplication.beep()
            if os.name == 'nt':
                try:
                    import winsound

                    if sound_key == 'none':
                        return

                    wav_key_to_path = {
                        'windows_proximity_wav': r"C:\\Windows\\Media\\Windows Proximity Notification.wav",
                        'windows_restore_wav': r"C:\\Windows\\Media\\Windows Restore.wav",
                        'windows_navigation_start_wav': r"C:\\Windows\\Media\\Windows Navigation Start.wav",
                        'speech_disambiguation_wav': r"C:\\Windows\\Media\\Speech Disambiguation.wav",
                        'windows_startup_wav': r"C:\\Windows\\Media\\Windows Startup.wav",
                    }
                    if sound_key in wav_key_to_path:
                        wav_path = wav_key_to_path.get(sound_key)
                        try:
                            if wav_path and os.path.exists(wav_path):
                                winsound.PlaySound(wav_path, winsound.SND_FILENAME | winsound.SND_ASYNC | winsound.SND_NODEFAULT)
                                return
                        except Exception:
                            # Fall back to a beep below
                            pass

                    sound_to_mb = {
                        None: winsound.MB_OK,
                        'ok': winsound.MB_OK,
                        'asterisk': winsound.MB_ICONASTERISK,
                        'exclamation': winsound.MB_ICONEXCLAMATION,
                        'hand': winsound.MB_ICONHAND,
                        'question': winsound.MB_ICONQUESTION,
                    }
                    winsound.MessageBeep(sound_to_mb.get(sound_key, winsound.MB_OK))
                    return
                except Exception:
                    pass

            QApplication.beep()
        except Exception:
            # Never allow sound effects to break normal workflows
            return

    def _queue_tm_save_log(self, msg: str):
        """Collapse repeated TM-save log messages into a single '(xN)' line.

        This prevents session log spam when confirming many segments.
        Thread-safe: flushes via a background timer and relies on self.log() being thread-safe.
        """
        import threading

        if not hasattr(self, '_tm_save_log_lock'):
            self._tm_save_log_lock = threading.Lock()
            self._tm_save_log_msg = None
            self._tm_save_log_count = 0
            self._tm_save_log_timer = None

        flush_now_msg = None
        flush_now_count = 0

        with self._tm_save_log_lock:
            # If we're switching to a different message, flush the previous one immediately.
            if self._tm_save_log_msg and self._tm_save_log_msg != msg and self._tm_save_log_count:
                flush_now_msg = self._tm_save_log_msg
                flush_now_count = self._tm_save_log_count
                self._tm_save_log_msg = None
                self._tm_save_log_count = 0

            # Accumulate the new message
            if self._tm_save_log_msg == msg:
                self._tm_save_log_count += 1
            else:
                self._tm_save_log_msg = msg
                self._tm_save_log_count = 1

            # Reset flush timer (debounce)
            if self._tm_save_log_timer is not None:
                try:
                    self._tm_save_log_timer.cancel()
                except Exception:
                    pass
                self._tm_save_log_timer = None

            self._tm_save_log_timer = threading.Timer(0.8, self._flush_tm_save_log_threadsafe)
            self._tm_save_log_timer.daemon = True
            self._tm_save_log_timer.start()

        # Flush outside lock
        if flush_now_msg and flush_now_count:
            suffix = f" (x{flush_now_count})" if flush_now_count > 1 else ""
            self.log(f"{flush_now_msg}{suffix}")

    def _flush_tm_save_log_threadsafe(self):
        import threading

        if not hasattr(self, '_tm_save_log_lock'):
            return

        msg = None
        count = 0
        with self._tm_save_log_lock:
            msg = getattr(self, '_tm_save_log_msg', None)
            count = int(getattr(self, '_tm_save_log_count', 0) or 0)
            self._tm_save_log_msg = None
            self._tm_save_log_count = 0
            self._tm_save_log_timer = None

        if msg and count:
            suffix = f" (x{count})" if count > 1 else ""
            self.log(f"{msg}{suffix}")

    def insert_compare_panel_mt(self):
        """Insert the currently shown Compare Panel MT translation (default: Alt+M)."""
        if self._get_active_match_shortcut_mode() != 'compare':
            return
        self._insert_compare_panel_mt_current()

    def insert_compare_panel_tm_target(self):
        """Insert the currently shown Compare Panel TM target (default: Alt+T)."""
        if self._get_active_match_shortcut_mode() != 'compare':
            return
        self._insert_compare_panel_tm_target_current()

    def _insert_compare_panel_mt_current(self):
        if not hasattr(self, 'compare_panel_mt'):
            return
        text = self.compare_panel_mt.toPlainText().strip()
        if text and not text.startswith('('):
            self.on_match_inserted(text)

    def _insert_compare_panel_tm_target_current(self):
        if not hasattr(self, 'compare_panel_tm_target'):
            return
        text = self.compare_panel_tm_target.toPlainText().strip()
        if text and not text.startswith('('):
            self.on_match_inserted(text)

    def _insert_compare_panel_match_by_number(self, match_number: int):
        """Insert Compare Panel content by number (Ctrl+1-9 while Compare Panel is active).

        Only two of these make sense for the Compare Panel:
        - 1 = MT (current)
        - 2 = TM Target (current)
        """
        if match_number not in (1, 2):
            return
        if not hasattr(self, 'compare_panel') or not self.compare_panel:
            return
        if not hasattr(self, 'right_tabs') or not self._widget_is_alive(self.right_tabs):
            return
        if self.right_tabs.currentWidget() is not self.compare_panel:
            return

        if match_number == 1:
            self._insert_compare_panel_mt_current()
            return
        if match_number == 2:
            self._insert_compare_panel_tm_target_current()
            return
    
    def go_to_previous_segment(self, target_column: int = None, to_last_line: bool = False):
        """Navigate to previous segment (Alt+Up)
        
        Args:
            target_column: If provided, position cursor at this column (for arrow key nav)
            to_last_line: If True with target_column, go to last line at that column
        """
        from PyQt6.QtGui import QTextCursor
        
        if hasattr(self, 'table') and self.table:
            current_row = self.table.currentRow()
            if current_row > 0:
                new_row = current_row - 1
                # Skip hidden rows (empty structural segments, filtered rows)
                while new_row > 0 and self.table.isRowHidden(new_row):
                    new_row -= 1
                if self.table.isRowHidden(new_row):
                    return  # No visible row above
                self.table.clearSelection()
                self.table.setCurrentCell(new_row, 3)  # Column 3 = Target (widget column)
                # Get the target cell widget and set focus to it
                target_widget = self.table.cellWidget(new_row, 3)
                if target_widget:
                    target_widget.setFocus()
                    if target_column is not None and to_last_line:
                        # Position at target column on VISUAL last line (for Up arrow navigation)
                        cursor = target_widget.textCursor()
                        doc = target_widget.document()
                        last_block = doc.lastBlock()
                        layout = last_block.layout()

                        if layout and layout.lineCount() > 0:
                            # Get the last VISUAL line within this block
                            last_visual_line = layout.lineAt(layout.lineCount() - 1)
                            line_start_in_block = int(last_visual_line.textStart())
                            line_length = int(last_visual_line.textLength())
                            target_pos_in_line = min(target_column, max(0, line_length - 1))
                            absolute_pos = last_block.position() + line_start_in_block + target_pos_in_line
                            cursor.setPosition(absolute_pos)
                        else:
                            # Fallback: position at target column from block start
                            cursor.setPosition(last_block.position())
                            line_length = last_block.length() - 1
                            target_pos = min(target_column, max(0, line_length))
                            cursor.movePosition(QTextCursor.MoveOperation.Right, QTextCursor.MoveMode.MoveAnchor, target_pos)

                        target_widget.setTextCursor(cursor)
                    else:
                        # Default: move cursor to end of text
                        target_widget.moveCursor(QTextCursor.MoveOperation.End)

    def go_to_next_segment(self, target_column: int = None, to_first_line: bool = False):
        """Navigate to next segment (Alt+Down)

        Args:
            target_column: If provided, position cursor at this column (for arrow key nav)
            to_first_line: If True with target_column, go to first line at that column
        """
        from PyQt6.QtGui import QTextCursor

        if hasattr(self, 'table') and self.table:
            current_row = self.table.currentRow()
            if current_row < self.table.rowCount() - 1:
                new_row = current_row + 1
                # Skip hidden rows (empty structural segments, filtered rows)
                while new_row < self.table.rowCount() - 1 and self.table.isRowHidden(new_row):
                    new_row += 1
                if self.table.isRowHidden(new_row):
                    return  # No visible row below
                self.table.clearSelection()
                self.table.setCurrentCell(new_row, 3)  # Column 3 = Target (widget column)
                # Get the target cell widget and set focus to it
                target_widget = self.table.cellWidget(new_row, 3)
                if target_widget:
                    target_widget.setFocus()
                    if target_column is not None and to_first_line:
                        # Position at target column on VISUAL first line (for Down arrow navigation)
                        cursor = target_widget.textCursor()
                        doc = target_widget.document()
                        first_block = doc.firstBlock()
                        layout = first_block.layout()
                        
                        if layout and layout.lineCount() > 0:
                            # Get the first VISUAL line within this block
                            first_visual_line = layout.lineAt(0)
                            line_length = int(first_visual_line.textLength())
                            target_pos_in_line = min(target_column, max(0, line_length - 1))
                            absolute_pos = first_block.position() + target_pos_in_line
                            cursor.setPosition(absolute_pos)
                        else:
                            # Fallback: position at target column from block start
                            cursor.setPosition(first_block.position())
                            line_length = first_block.length() - 1
                            target_pos = min(target_column, max(0, line_length))
                            cursor.movePosition(QTextCursor.MoveOperation.Right, QTextCursor.MoveMode.MoveAnchor, target_pos)
                        
                        target_widget.setTextCursor(cursor)
                    else:
                        # Default: move cursor to end of text
                        target_widget.moveCursor(QTextCursor.MoveOperation.End)
    
    def go_to_first_segment(self):
        """Navigate to first segment (Ctrl+Home).

        Pagination/filters may hide row 0, so switch to the first page and then
        move to the first visible row.
        """
        if not hasattr(self, 'table') or not self.table or self.table.rowCount() <= 0:
            return

        # If pagination is enabled, ensure we're on the first page so row 0 is visible.
        if hasattr(self, 'go_to_first_page'):
            self.go_to_first_page()

        target_row = 0
        if self.table.isRowHidden(target_row):
            # Filters can also hide rows; pick the first visible row.
            target_row = next((r for r in range(self.table.rowCount()) if not self.table.isRowHidden(r)), 0)

        self.table.setCurrentCell(target_row, 3)  # Column 3 = Target (widget column)
        id_item = self.table.item(target_row, 0)
        if id_item is not None:
            self.table.scrollToItem(id_item)
        self.log("⏫ Moved to first segment")

        target_widget = self.table.cellWidget(target_row, 3)
        if target_widget:
            target_widget.setFocus()
            target_widget.moveCursor(QTextCursor.MoveOperation.Start)
    
    def go_to_last_segment(self):
        """Navigate to last segment (Ctrl+End).

        Pagination/filters may hide the last row, so switch to the last page and then
        move to the last visible row.
        """
        if not hasattr(self, 'table') or not self.table or self.table.rowCount() <= 0:
            return

        # If pagination is enabled, ensure we're on the last page so the last row is visible.
        if hasattr(self, 'go_to_last_page'):
            self.go_to_last_page()

        target_row = self.table.rowCount() - 1
        if self.table.isRowHidden(target_row):
            target_row = next((r for r in range(self.table.rowCount() - 1, -1, -1) if not self.table.isRowHidden(r)), target_row)

        self.table.setCurrentCell(target_row, 3)  # Column 3 = Target (widget column)
        id_item = self.table.item(target_row, 0)
        if id_item is not None:
            self.table.scrollToItem(id_item)
        self.log(f"⏬ Moved to last segment ({target_row + 1})")

        target_widget = self.table.cellWidget(target_row, 3)
        if target_widget:
            target_widget.setFocus()
            target_widget.moveCursor(QTextCursor.MoveOperation.End)
    
    def confirm_and_next_unconfirmed(self):
        """Set current segment to confirmed and move to next unconfirmed segment (Ctrl+Enter)."""
        if not hasattr(self, 'table') or not self.table or not self.current_project:
            self.log(f"⚠️ {format_shortcut_for_display('Ctrl+Enter')}: Missing table or project")
            return
        
        current_row = self.table.currentRow()
        if current_row < 0:
            self.log(f"⚠️ {format_shortcut_for_display('Ctrl+Enter')}: No row selected")
            return

        # If text filters are active, Ctrl+Enter should advance through the filtered/visible rows,
        # not "next unconfirmed". This avoids selecting hidden rows and prevents pagination from
        # accidentally unhiding rows.
        if self._is_text_filter_active():
            self._confirm_current_row_segment()
            # Re-apply filters in case the target text changed and affects matching
            self.apply_filters()
            self._move_to_next_visible_row(current_row)
            return
        
        # CRITICAL: Ensure the target widget has focus before reading from it
        # This fixes the issue where Ctrl+Enter doesn't work without mouse interaction
        target_widget_current = self.table.cellWidget(current_row, 3)
        if target_widget_current and not target_widget_current.hasFocus():
            target_widget_current.setFocus()
            # Give Qt event loop time to process the focus change
            QApplication.processEvents()
        
        # Confirm current row (shared implementation)
        self._confirm_current_row_segment()
        
        # Find next unconfirmed segment
        for row in range(current_row + 1, self.table.rowCount()):
            if row < len(self.current_project.segments):
                seg = self.current_project.segments[row]
                if seg.status not in ['confirmed', 'approved']:
                    # Check if row is hidden due to pagination
                    if self.table.isRowHidden(row):
                        # Calculate which page this row is on and switch to it
                        if hasattr(self, 'grid_page_size') and hasattr(self, 'grid_current_page'):
                            target_page = row // self.grid_page_size
                            if target_page != self.grid_current_page:
                                self.grid_current_page = target_page
                                self._update_pagination_ui()
                                self._apply_pagination_to_grid()
                    
                    # ⚡ INSTANT NAVIGATION: Set flag so on_cell_selected uses fast path
                    # This makes Ctrl+Enter feel instant - cursor moves first, lookups happen after
                    self._ctrl_enter_navigation = True
                    
                    self.table.clearSelection()
                    self.table.setCurrentCell(row, 3)  # Column 3 = Target (widget column)
                    self.table.selectRow(row)  # v1.9.182: Ensure row is visually selected
                    # Ensure the row is visible by scrolling to it
                    self.table.scrollToItem(self.table.item(row, 0), QTableWidget.ScrollHint.PositionAtCenter)
                    self.log(f"⏭️ Moved to next unconfirmed segment {seg.id}")

                    # v1.9.182: Explicitly update termlens (don't rely on deferred signal)
                    self._update_termlens_for_segment(seg)

                    # v1.9.182: Explicitly schedule TM lookup (don't rely on deferred signal)
                    if self.enable_tm_matching:
                        find_replace_active = getattr(self, 'find_replace_active', False)
                        if not find_replace_active:
                            self._schedule_mt_and_llm_matches(seg, [])

                    # Get the target cell widget and set focus to it IMMEDIATELY
                    # (moved BEFORE auto-confirm check for instant responsiveness)
                    target_widget = self.table.cellWidget(row, 3)
                    if target_widget:
                        target_widget.setFocus()
                        # Move cursor to end of text
                        target_widget.moveCursor(QTextCursor.MoveOperation.End)

                    # v1.9.182: Defer auto-confirm check to not block navigation
                    # The TM lookup is slow - do it asynchronously after navigation completes
                    if self.auto_confirm_100_percent_matches:
                        QTimer.singleShot(50, lambda r=row, s=seg: self._check_auto_confirm_100_percent(r, s))
                    return
        
        # No more unconfirmed segments, just go to next
        if current_row < self.table.rowCount() - 1:
            next_row = current_row + 1
            
            # Check if row is hidden due to pagination
            if self.table.isRowHidden(next_row):
                # Calculate which page this row is on and switch to it
                if hasattr(self, 'grid_page_size') and hasattr(self, 'grid_current_page'):
                    target_page = next_row // self.grid_page_size
                    if target_page != self.grid_current_page:
                        self.grid_current_page = target_page
                        self._update_pagination_ui()
                        self._apply_pagination_to_grid()
            
            # ⚡ INSTANT NAVIGATION
            self._ctrl_enter_navigation = True
            
            self.table.clearSelection()
            self.table.setCurrentCell(next_row, 3)  # Column 3 = Target (widget column)
            self.table.selectRow(next_row)  # v1.9.182: Ensure row is visually selected
            # Ensure the row is visible by scrolling to it
            self.table.scrollToItem(self.table.item(next_row, 0), QTableWidget.ScrollHint.PositionAtCenter)
            self.log(f"⏭️ Moved to next segment (all remaining confirmed)")

            # v1.9.182: Explicitly update termlens (don't rely on deferred signal)
            if next_row < len(self.current_project.segments):
                next_seg = self.current_project.segments[next_row]
                self._update_termlens_for_segment(next_seg)

                # v1.9.182: Explicitly schedule TM lookup (don't rely on deferred signal)
                if self.enable_tm_matching:
                    find_replace_active = getattr(self, 'find_replace_active', False)
                    if not find_replace_active:
                        self._schedule_mt_and_llm_matches(next_seg, [])

            # Get the target cell widget and set focus to it
            target_widget = self.table.cellWidget(next_row, 3)
            if target_widget:
                target_widget.setFocus()
                # Move cursor to end of text
                target_widget.moveCursor(QTextCursor.MoveOperation.End)

    def _check_auto_confirm_100_percent(self, row: int, seg):
        """
        v1.9.182: Deferred auto-confirm check for 100% TM matches.

        This is called asynchronously after Ctrl+Enter navigation to avoid blocking
        the UI thread with slow TM database queries.
        """
        try:
            # Verify we're still on the same segment (user may have navigated away)
            current_row = self.table.currentRow() if hasattr(self, 'table') and self.table else -1
            if current_row != row:
                return  # User has moved - don't auto-confirm wrong segment

            if not self.enable_tm_matching or not hasattr(self, 'db_manager') or not self.db_manager:
                return

            # Get activated TM IDs from project settings
            activated_tm_ids = []
            if hasattr(self.current_project, 'tm_settings') and self.current_project.tm_settings:
                activated_tm_ids = self.current_project.tm_settings.get('activated_tm_ids', [])

            if not activated_tm_ids:
                return

            # Use get_exact_match for 100% matches
            source_lang = self.current_project.source_lang if hasattr(self.current_project, 'source_lang') else None
            target_lang = self.current_project.target_lang if hasattr(self.current_project, 'target_lang') else None
            exact_match = self.db_manager.get_exact_match(
                seg.source,
                tm_ids=activated_tm_ids,
                source_lang=source_lang,
                target_lang=target_lang
            )

            if not exact_match:
                return

            # Check if there's a 100% match and (target is empty OR overwrite is enabled)
            target_is_empty = not seg.target.strip()
            can_auto_confirm = target_is_empty or self.auto_confirm_overwrite_existing

            if not can_auto_confirm:
                return

            # Verify AGAIN that we're still on the same segment (TM query may have taken time)
            current_row = self.table.currentRow() if hasattr(self, 'table') and self.table else -1
            if current_row != row:
                return  # User has moved during TM lookup

            match_target = exact_match.get('target_text', '')
            if not match_target:
                return

            overwrite_note = " (overwriting existing)" if not target_is_empty else " (empty target)"
            self.log(f"🎯 Auto-confirm: Found 100% TM match for segment {seg.id}{overwrite_note}")

            # Insert the match into the target cell
            target_widget = self.table.cellWidget(row, 3)
            if target_widget:
                target_widget.setPlainText(match_target)
                seg.target = match_target
                seg.status = 'confirmed'
                self.update_status_icon(row, 'confirmed')
                self.project_modified = True

                # Save to TM
                try:
                    self.save_segment_to_activated_tms(seg.source, seg.target)
                    self.log(f"💾 Auto-confirmed and saved segment {seg.id} to TM")
                except Exception as e:
                    self.log(f"⚠️ Error saving auto-confirmed segment to TM: {e}")

                # Continue to the NEXT unconfirmed segment (skip this one)
                self.confirm_and_next_unconfirmed()
        except Exception as e:
            self.log(f"⚠️ Error in auto-confirm check: {e}")

    def confirm_selected_or_next(self):
        """Smart confirm: if multiple segments selected, confirm all; otherwise confirm and go to next.
        
        This is the handler for Ctrl+Enter:
        - Multiple segments selected: confirm all selected segments
        - Single segment: confirm current and go to next unconfirmed
        """
        selected_segments = self.get_selected_segments_from_grid()
        
        if len(selected_segments) > 1:
            # Multiple segments selected - confirm all
            self.confirm_selected_segments()
        else:
            # Single segment - if text filters are active, advance through the filtered rows
            # (handled inside confirm_and_next_unconfirmed for centralization).
            self.confirm_and_next_unconfirmed()

    def _is_text_filter_active(self) -> bool:
        """Return True if the Filter Source/Target boxes currently contain text."""
        source_text = self._get_line_edit_text('source_filter').strip()
        target_text = self._get_line_edit_text('target_filter').strip()
        return bool(source_text or target_text)

    def _confirm_current_row_segment(self) -> Optional[int]:
        """Confirm the current row's segment and sync target text from the grid.

        Returns the confirmed segment ID on success, else None.
        """
        if not hasattr(self, 'table') or not self.table or not self.current_project:
            return None

        current_row = self.table.currentRow()
        if current_row < 0:
            return None

        # Ensure the target widget has focus before reading from it
        target_widget_current = self.table.cellWidget(current_row, 3)
        if target_widget_current and not target_widget_current.hasFocus():
            target_widget_current.setFocus()
            QApplication.processEvents()

        id_item = self.table.item(current_row, 0)
        if not id_item:
            self.log(f"⚠️ Ctrl+Enter: No ID item at row {current_row}")
            return None

        try:
            segment_id = int(id_item.text())
        except (ValueError, AttributeError):
            self.log(f"⚠️ Ctrl+Enter: Could not parse segment ID from row {current_row}")
            return None

        segment = next((seg for seg in self.current_project.segments if seg.id == segment_id), None)
        if not segment:
            self.log(f"⚠️ Ctrl+Enter: Could not find segment with ID {segment_id}")
            return None

        self.log(f"🔍 Ctrl+Enter: Row {current_row}, Segment ID {segment.id}")

        old_target = segment.target
        old_status = segment.status

        target_widget = self.table.cellWidget(current_row, 3)
        if target_widget:
            current_text = target_widget.toPlainText().strip()
            segment.target = current_text

        segment.status = 'confirmed'

        # Record undo state for Ctrl+Enter confirmation
        self.record_undo_state(segment_id, old_target, segment.target, old_status, 'confirmed')
        self.update_status_icon(current_row, 'confirmed')
        self.project_modified = True
        self.log(f"✅ Segment {segment.id} confirmed")

        self.update_progress_stats()

        # Play sound effect for segment confirmation
        self._play_sound_effect('segment_confirmed')

        if segment.target and segment.target.strip():
            try:
                self.save_segment_to_activated_tms(segment.source, segment.target)
                self.log(f"💾 Saved segment {segment.id} to TM: '{segment.target[:50]}...'")
            except Exception as e:
                self.log(f"⚠️ Error saving to TM: {e}")

        return segment_id

    def _move_to_next_visible_row(self, current_row: int) -> None:
        """Move focus to the next visible row after current_row (respects filters + pagination)."""
        if not hasattr(self, 'table') or not self.table or not self.current_project:
            return

        row_count = self.table.rowCount()
        if row_count <= 0:
            return

        page_size = getattr(self, 'grid_page_size', 50)
        has_pagination = isinstance(page_size, int) and page_size < 999999 and page_size > 0

        last_page_applied = getattr(self, 'grid_current_page', 0)

        for row in range(current_row + 1, row_count):
            if has_pagination:
                target_page = row // page_size
                if target_page != last_page_applied:
                    self.grid_current_page = target_page
                    last_page_applied = target_page
                    self._apply_pagination_to_grid()

            if not self.table.isRowHidden(row):
                self.table.clearSelection()
                self.table.setCurrentCell(row, 3)
                id_item = self.table.item(row, 0)
                if id_item is not None:
                    self.table.scrollToItem(id_item)

                target_widget = self.table.cellWidget(row, 3)
                if target_widget:
                    target_widget.setFocus()
                    target_widget.moveCursor(QTextCursor.MoveOperation.End)
                return

        # No more visible rows
        self.log("✅ No more filtered segments")
    
    def confirm_selected_segments(self, segments=None):
        """Confirm all selected segments in the grid.

        Sets status to 'confirmed' for all selected/provided segments and saves them to TM.

        Args:
            segments: Optional list of segments to confirm. If None, uses grid selection.
        """
        if not self.current_project:
            self.log("⚠️ No project loaded")
            return

        selected_segments = segments or self.get_selected_segments_from_grid()

        if not selected_segments:
            self.log("⚠️ No segments selected")
            return
        
        # Sync all target text from grid widgets first
        self._sync_grid_targets_to_segments(selected_segments)
        
        confirmed_count = 0
        tm_saved_count = 0
        
        for segment in selected_segments:
            # Skip already confirmed segments
            if segment.status == 'confirmed':
                continue
            
            old_status = segment.status
            segment.status = 'confirmed'
            confirmed_count += 1
            
            # Update grid status icon
            row = self._find_row_for_segment(segment.id)
            if row >= 0:
                self.update_status_icon(row, 'confirmed')
            
            # Save to TM if target has content
            if segment.target and segment.target.strip():
                try:
                    self.save_segment_to_activated_tms(segment.source, segment.target)
                    tm_saved_count += 1
                except Exception as e:
                    self.log(f"⚠️ Error saving segment {segment.id} to TM: {e}")
        
        if confirmed_count > 0:
            self.project_modified = True
            self.update_window_title()
            self.log(f"✅ Confirmed {confirmed_count} segment(s), saved {tm_saved_count} to TM")
            # Update status bar progress stats
            self.update_progress_stats()
        else:
            self.log(f"ℹ️ All {len(selected_segments)} selected segment(s) were already confirmed")
    
    def confirm_selected_segments_from_menu(self):
        """Confirm selected/filtered segments (called from Edit > Bulk Operations menu)"""
        if not self.current_project:
            QMessageBox.information(self, "Not Available", "Please load a project first.")
            return

        if not hasattr(self, 'table') or not self.table:
            QMessageBox.information(self, "Not Available", "Grid view is not available.")
            return

        segments = self._get_selected_or_filtered_segments("Confirm Segments")
        if segments:
            self.confirm_selected_segments(segments)

    def change_status_selected(self, new_status: str, from_menu: bool = False):
        """Change status of all selected/filtered segments to the specified status.

        Args:
            new_status: The status key to set (e.g., 'draft', 'pretranslated')
            from_menu: If True, show message boxes for errors (called from menu)
        """
        if not self.current_project:
            if from_menu:
                QMessageBox.information(self, "Not Available", "Please load a project first.")
            else:
                self.log("⚠️ No project loaded")
            return

        if not hasattr(self, 'table') or not self.table:
            if from_menu:
                QMessageBox.information(self, "Not Available", "Grid view is not available.")
            return

        # Get status definition for dialog label
        from modules.statuses import get_status
        status_def = get_status(new_status)

        if from_menu:
            selected_segments = self._get_selected_or_filtered_segments(f"Change Status to '{status_def.label}'")
        else:
            selected_segments = self.get_selected_segments_from_grid()

        if not selected_segments:
            if not from_menu:
                self.log("⚠️ No segments selected")
            return

        # Sync all target text from grid widgets first
        self._sync_grid_targets_to_segments(selected_segments)

        changed_count = 0
        for segment in selected_segments:
            # Skip if already has this status
            if segment.status == new_status:
                continue

            segment.status = new_status
            changed_count += 1

            # Update grid status icon
            row = self._find_row_for_segment(segment.id)
            if row >= 0:
                self.update_status_icon(row, new_status)

        if changed_count > 0:
            self.project_modified = True
            self.update_window_title()
            self.log(f"✅ Changed {changed_count} segment(s) to '{status_def.label}'")
            # Update status bar progress stats
            self.update_progress_stats()
        else:
            self.log(f"ℹ️ All {len(selected_segments)} selected segment(s) already have status '{status_def.label}'")

    def _sync_grid_targets_to_segments(self, segments):
        """Sync target text from grid widgets to segment objects.

        This ensures any edits in the grid are captured before confirming.
        Reverses invisible character display replacements and restores
        stripped outer wrapping tags to get clean text for export.
        """
        for segment in segments:
            row = self._find_row_for_segment(segment.id)
            if row >= 0:
                target_widget = self.table.cellWidget(row, 3)
                if target_widget:
                    text = target_widget.toPlainText().strip()
                    # Reverse invisible character display replacements (·→space, →→tab, etc.)
                    text = self.reverse_invisible_replacements(text)
                    # Re-add stripped outer wrapping tag if applicable
                    stripped_tag = getattr(target_widget, '_stripped_outer_tag', None)
                    if stripped_tag and self.hide_outer_wrapping_tags:
                        if text and not text.strip().startswith(f'<{stripped_tag}'):
                            text = f'<{stripped_tag}>{text}</{stripped_tag}>'
                    segment.target = text
    
    def _find_row_for_segment(self, segment_id: int) -> int:
        """Find the grid row index for a segment by ID."""
        if not hasattr(self, 'table') or not self.table:
            return -1
        
        for row in range(self.table.rowCount()):
            id_item = self.table.item(row, 0)
            if id_item:
                try:
                    if int(id_item.text()) == segment_id:
                        return row
                except (ValueError, AttributeError):
                    continue
        return -1

    def insert_termlens_text(self, text: str):
        """Insert text from TermLens into the currently active target field"""
        try:
            # Find the active target editor
            current_row = self.table.currentRow()
            if current_row >= 0:
                target_widget = self.table.cellWidget(current_row, 3)
                if target_widget and hasattr(target_widget, 'textCursor'):
                    # Insert at current cursor position
                    cursor = target_widget.textCursor()
                    cursor.insertText(text)
                    target_widget.setFocus()
                    self.log(f"✓ Inserted term: {text}")
                    return
            
            # Fallback: try tab editor panels
            if hasattr(self, 'tabbed_panels'):
                for panel in self.tabbed_panels:
                    if hasattr(panel, 'editor_widget'):
                        editor = panel.editor_widget
                        if editor.target_editor.hasFocus() or True:  # Insert into first available
                            cursor = editor.target_editor.textCursor()
                            cursor.insertText(text)
                            editor.target_editor.setFocus()
                            self.log(f"✓ Inserted term: {text}")
                            return
            
            self.log("⚠️ No active target field found for insertion")
        except Exception as e:
            self.log(f"✗ Error inserting termlens text: {e}")
    
    def _on_termlens_font_size_changed(self, new_size: int):
        """Persist new TermLens font size and sync the other TermLens panel.

        Triggered by the inline A-/A+ buttons on either TermLens widget.
        """
        try:
            settings = self.load_general_settings()
            if settings.get('termlens_font_size') == new_size:
                # The widget that fired the signal is already at new_size; sync the other.
                pass
            else:
                settings['termlens_font_size'] = new_size
                self.save_general_settings(settings)

            family = settings.get('termlens_font_family', 'Segoe UI')
            bold = settings.get('termlens_font_bold', False)

            # Sync both TermLens widgets without re-emitting the signal.
            sender = self.sender()
            for widget in (getattr(self, 'termlens_widget', None),
                           getattr(self, 'termlens_widget_match', None)):
                if widget is None or widget is sender:
                    continue
                if widget.current_font_size == new_size:
                    continue
                widget.current_font_size = new_size
                if getattr(widget, 'current_source', '') and hasattr(widget, '_last_termbase_matches'):
                    widget.update_with_matches(
                        widget.current_source,
                        widget._last_termbase_matches or [],
                        getattr(widget, '_last_nt_matches', None),
                        getattr(widget, '_status_hint', None),
                    )
                else:
                    widget.set_font_settings(family, new_size, bold)
        except Exception as e:
            self.log(f"⚠ Could not save TermLens font size: {e}")

    def _on_termlens_edit_entry(self, term_id: int, termbase_id: int):
        """Handle edit glossary entry request from TermLens"""
        try:
            # v1.10.67 diagnostic: record what TermLens actually
            # emitted so an open user report (dialog opens with empty
            # fields or with project-direction captions when the
            # termbase declares the reverse direction) can be checked
            # against the dialog's LOAD line. If termbase_id here
            # disagrees with the real termbases.id for this term, the
            # bug is in the TermLens display pipeline upstream — the
            # dialog itself self-corrects via the term_id JOIN in
            # TermbaseEntryEditor.setup_ui (v1.10.67).
            self.log(
                f"[edit-from-termlens] received term_id={term_id!r} "
                f"termbase_id={termbase_id!r} (types: "
                f"{type(term_id).__name__}, {type(termbase_id).__name__})"
            )

            from modules.termbase_entry_editor import TermbaseEntryEditor

            dialog = TermbaseEntryEditor(
                parent=self,
                db_manager=self.db_manager,
                termbase_id=termbase_id,
                term_id=term_id
            )
            
            if dialog.exec():
                # Entry was edited (or deleted via the dialog's red
                # Delete button — both paths call self.accept()).
                # v1.10.64: use the full post-delete refresh helper
                # so the in-memory termbase_index is rebuilt too.
                # That's necessary for the delete-via-dialog path; it's
                # harmless overhead for the edit-via-dialog path (index
                # rebuild is sub-second on typical term counts).
                self.log(f"✓ Termbase entry {term_id} updated/deleted via dialog")
                self._post_termbase_delete_refresh()
        except Exception as e:
            self.log(f"✗ Error editing termbase entry: {e}")
    
    def _on_termlens_refresh_requested(self):
        """Handle the TermLens 🔄 refresh button (v1.10.68).

        v1.10.72: collapsed into the same handler as F5
        (``force_refresh_matches``). The button is now just a
        discoverable visual entry point for the F5 shortcut — useful
        for users who don't know about F5 but find the button by
        hovering. Behaviour is identical to pressing F5:

         - Snapshot-check whether the termbase tables actually
           changed since the last index rebuild; if yes, rebuild
           the in-memory index from disk (catches cross-process
           edits from the Trados plugin or external tools); if no,
           skip the rebuild (keeps the common case fast).
         - Clear per-segment caches.
         - Re-search termbases / TMs / NT lists.
         - Redraw TermLens widgets + the Translation Results panel.

        Before v1.10.72 this called a separate
        ``_post_termbase_delete_refresh`` that always rebuilt the
        index. Having two near-identical refresh paths confused
        users and caused the v1.10.71 "F5 fixes what the 🔄 button
        leaves under-refreshed" symptom; the merge fixes both.
        """
        try:
            self.force_refresh_matches()
        except Exception as e:
            self.log(f"✗ TermLens refresh failed: {e}")

    def _on_termlens_delete_entry(self, term_id: int, termbase_id: int, source_term: str, target_term: str):
        """Handle delete glossary entry request from TermLens"""
        from PyQt6.QtWidgets import QMessageBox
        
        try:
            # Confirm deletion
            reply = QMessageBox.question(
                self,
                "Confirm Deletion",
                f"Delete termbase entry?\n\nSource: {source_term}\nTarget: {target_term}\n\nThis action cannot be undone.",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No
            )
            
            if reply == QMessageBox.StandardButton.Yes:
                if self.termbase_mgr:
                    try:
                        if self.termbase_mgr.delete_term(term_id):
                            self.log(f"✓ Deleted termbase entry: {source_term} → {target_term}")

                            # v1.10.64: previously this only called
                            # _refresh_current_segment_matches, which
                            # clears the per-segment cache and re-runs
                            # find_termbase_matches_in_source. But that
                            # search reads from the in-memory
                            # termbase_index, which still contained the
                            # just-deleted entry → the term kept showing
                            # in TermLens after delete. The post-delete
                            # helper additionally rebuilds the index.
                            self._post_termbase_delete_refresh()
                        else:
                            self.log(f"✗ Failed to delete termbase entry")
                    except Exception as e:
                        self.log(f"✗ Error deleting termbase entry from database: {e}")
        except Exception as e:
            self.log(f"✗ Error deleting termbase entry: {e}")
    
    def _refresh_current_segment_matches(self):
        """Refresh termbase matches for the current segment (after edit/delete)"""
        try:
            # Use the targeted refresh method that doesn't trigger TM search
            self._refresh_termbase_display_for_current_segment()
        except Exception as e:
            self.log(f"✗ Error refreshing segment matches: {e}")
    
    def save_tab_notes(self):
        """Save comments in tab editor"""
        if not hasattr(self, 'tab_current_segment_id') or not self.tab_current_segment_id:
            return
        self.log(f"✓ Saved comments for segment {self.tab_current_segment_id}")

    def toggle_tm_from_editor(self, checked: bool, button: QPushButton):
        """Toggle TM/Termbase lookups from segment editor button"""
        # Call the existing toggle method
        self.toggle_tm_termbase_matching(checked)

        # Update button text and style
        if checked:
            button.setText("🔍 TM/Termbase ON")
            self.log("✓ TM/Termbase lookups ENABLED from segment editor")
        else:
            button.setText("🚫 TM/Termbase OFF")
            self.log("⚠️ TM/Termbase lookups DISABLED from segment editor (faster editing)")

    def _toggle_tag_view_via_shortcut(self):
        """Toggle tag view using keyboard shortcut (Ctrl+Shift+H) – cycles: tags → compact → wysiwyg"""
        mode = getattr(self, 'tag_view_mode', 'tags')
        cycle = {'tags': 'compact', 'compact': 'wysiwyg', 'wysiwyg': 'tags'}
        self._set_tag_view_mode(cycle.get(mode, 'tags'))

    def _enable_tag_view_after_import(self):
        """Auto-enable Tag View after importing a document with formatting tags"""
        if hasattr(self, 'tags_btn'):
            self._set_tag_view_mode('tags')
            self.log("🏷️ Tag View auto-enabled (formatting tags detected in import)")

    def _set_tag_view_mode(self, mode: str):
        """Set the tag view mode: 'tags', 'compact', or 'wysiwyg'"""
        self.tag_view_mode = mode
        self.show_tags = (mode == 'tags' or mode == 'compact')

        # Update segmented control buttons
        if hasattr(self, 'wysiwyg_btn'):
            self.wysiwyg_btn.setChecked(mode == 'wysiwyg')
        if hasattr(self, 'compact_btn'):
            self.compact_btn.setChecked(mode == 'compact')
        if hasattr(self, 'tags_btn'):
            self.tags_btn.setChecked(mode == 'tags')

        labels = {'tags': '🏷️ Tag View – showing raw tags',
                  'compact': '📦 Compact View – verbose tags shortened',
                  'wysiwyg': '✨ WYSIWYG View – showing formatted text'}
        self.log(labels.get(mode, mode))

        if hasattr(self, 'table') and self.current_project:
            self._refresh_grid_display_mode()

    def toggle_tag_view(self, checked: bool, button: QPushButton = None):
        """Legacy toggle – routes to _set_tag_view_mode for backward compatibility"""
        self._set_tag_view_mode('tags' if checked else 'wysiwyg')

    def _refresh_grid_display_mode(self):
        """Refresh all visible cells to reflect current tag view mode"""
        if not hasattr(self, 'table') or not self.current_project:
            return

        mode = getattr(self, 'tag_view_mode', 'tags')

        # Suppress target change handlers during refresh to prevent data corruption
        # (switching display modes changes widget content which could trigger textChanged)
        self._suppress_target_change_handlers = True

        # Get current visible rows
        for row in range(self.table.rowCount()):
            # Get segment for this row
            if row >= len(self.current_project.segments):
                continue

            segment = self.current_project.segments[row]

            # Apply tag stripping if enabled
            source_for_display = segment.source
            target_for_display = segment.target

            if self.hide_outer_wrapping_tags:
                stripped_source, _ = strip_outer_wrapping_tags(segment.source)
                source_for_display = stripped_source
                stripped_target, _ = strip_outer_wrapping_tags(segment.target)
                target_for_display = stripped_target

            # Compact mode: build tag map from source, apply to both columns.
            # The map is stored on the target widget so edits can be reversed.
            if mode == 'compact':
                tag_map = {}
                source_for_display = compact_tags(source_for_display, tag_map)
                target_for_display = compact_tags(target_for_display, tag_map)
            else:
                tag_map = None

            # Apply invisible character replacements (e.g. ↵ for line breaks)
            source_for_display = self.apply_invisible_replacements(source_for_display)
            target_for_display = self.apply_invisible_replacements(target_for_display)

            # For compact mode, use show_tags=True so TagHighlighter can color the placeholders
            show_tags_for_cell = (mode in ('tags', 'compact'))

            # Update source cell (column 2)
            source_widget = self.table.cellWidget(row, 2)
            if source_widget and hasattr(source_widget, 'update_display_mode'):
                source_widget.update_display_mode(source_for_display, show_tags_for_cell)

            # Update target cell (column 3)
            target_widget = self.table.cellWidget(row, 3)
            if target_widget and hasattr(target_widget, 'update_display_mode'):
                target_widget.update_display_mode(target_for_display, show_tags_for_cell)
                # Store tag map for reverse-expanding on save
                target_widget._compact_tag_map = tag_map

        # Re-enable target change handlers
        self._suppress_target_change_handlers = False

        # Auto-resize rows since tag length changes affect row heights
        self.auto_resize_rows()

    def update_tab_segment_editor(self, segment_id: int, source_text: str, target_text: str,
                                   status: str = "untranslated", notes: str = ""):
        """Update the tab segment editor with current segment data"""
        # CRITICAL FIX: Update segment ID BEFORE setting text to prevent cross-contamination
        # When setPlainText() triggers textChanged, it needs to update the CORRECT segment
        self.tab_current_segment_id = segment_id
        
        # Update ALL tabbed panels (grid view and list view)
        if hasattr(self, 'tabbed_panels'):
            for panel in self.tabbed_panels:
                try:
                    # Update segment editor tab
                    if hasattr(panel, 'editor_widget'):
                        editor = panel.editor_widget
                        editor.seg_info_label.setText(f"Segment {segment_id}")
                        editor.source_editor.setPlainText(source_text)
                        editor.target_editor.setPlainText(target_text)
                        idx = editor.status_combo.findData(status)
                        if idx >= 0:
                            editor.status_combo.blockSignals(True)
                            editor.status_combo.setCurrentIndex(idx)
                            editor.status_combo.blockSignals(False)
                    
                    # Update notes tab
                    if hasattr(panel, 'notes_widget'):
                        panel.notes_widget.notes_editor.setPlainText(notes)
                except Exception as e:
                    self.log(f"Error updating tabbed panel: {e}")
        
        # NOTE: TermLens is updated AFTER termbase search completes in _on_cell_selected_full
        # Do NOT update TermLens here - the cache may not be populated yet
    
    # ========================================================================
    # UTILITY
    # ========================================================================
    
    def update_window_title(self):
        """Update window title with project name and modified state"""
        title = f"Supervertaler Workbench v{__version__}"
        if ENABLE_PRIVATE_FEATURES:
            title += " [🛠️ DEV MODE]"
        if self.current_project:
            title += f" - {self.current_project.name}"
            if self.project_modified:
                title += " *"
        self.setWindowTitle(title)
    
    def log(self, message: str):
        """Log message to status bar and session log (thread-safe)"""
        # Always safe to print to console
        print(f"[LOG] {message}")
        
        # Check if we're in the main thread - Qt widgets can only be modified from main thread
        import threading
        
        is_main_thread = threading.current_thread() == threading.main_thread()
        
        if not is_main_thread:
            # If we're in a background thread, emit signal which will be handled on main thread
            # pyqtSignal with default connection is thread-safe and queues to main event loop
            try:
                self._log_signal.emit(message)
            except Exception:
                pass  # Silently fail if signal emission fails
            return
        
        # Main thread - safe to access widgets directly
        self._log_to_ui(message)
    
    def _log_to_ui(self, message: str):
        """Internal method to log to UI widgets - must be called from main thread only"""
        if hasattr(self, 'status_bar'):
            self.status_bar.showMessage(message)
        
        # Add to debug buffer if debug mode is enabled
        if hasattr(self, 'debug_mode_enabled') and self.debug_mode_enabled:
            if not hasattr(self, 'debug_log_buffer'):
                self.debug_log_buffer = []
            from datetime import datetime
            timestamp = datetime.now().strftime("%H:%M:%S")
            self.debug_log_buffer.append(f"[{timestamp}] {message}")
            # Keep buffer size reasonable (max 10,000 entries)
            if len(self.debug_log_buffer) > 10000:
                self.debug_log_buffer = self.debug_log_buffer[-10000:]

        # Also append to session log tab if it exists
        if hasattr(self, 'session_log_text') and self.session_log_text:
            from datetime import datetime
            from PyQt6.QtGui import QTextCursor
            timestamp = datetime.now().strftime("%H:%M:%S")
            formatted_message = f"[{timestamp}] {message}"
            try:
                # Append without newline (appendPlainText adds it automatically)
                self.session_log_text.appendPlainText(formatted_message)
                # Force scroll to bottom by moving cursor to end
                self.session_log_text.moveCursor(QTextCursor.MoveOperation.End)
                self.session_log_text.ensureCursorVisible()
            except Exception:
                pass  # Silently fail if widget not ready

        # Also append to Settings tab session log if it exists (separate widget)
        if hasattr(self, 'session_log') and self.session_log:
            from datetime import datetime
            from PyQt6.QtGui import QTextCursor
            timestamp = datetime.now().strftime("%H:%M:%S")
            formatted_message = f"[{timestamp}] {message}"
            try:
                self.session_log.appendPlainText(formatted_message)
                self.session_log.moveCursor(QTextCursor.MoveOperation.End)
                self.session_log.ensureCursorVisible()
            except Exception:
                pass  # Silently fail if widget not ready

        # Also send to detached log windows
        if hasattr(self, 'detached_log_windows'):
            from datetime import datetime
            from PyQt6.QtGui import QTextCursor
            timestamp = datetime.now().strftime("%H:%M:%S")
            formatted_message = f"[{timestamp}] {message}"
            for window in self.detached_log_windows[:]:  # Copy list to avoid modification during iteration
                try:
                    if window and not window.isHidden():
                        window.log_display.appendPlainText(formatted_message)
                        # Force scroll to bottom by moving cursor to end
                        window.log_display.moveCursor(QTextCursor.MoveOperation.End)
                        window.log_display.ensureCursorVisible()
                    else:
                        # Remove closed windows
                        self.detached_log_windows.remove(window)
                except:
                    # Remove invalid windows
                    try:
                        self.detached_log_windows.remove(window)
                    except:
                        pass
    
    def show_options_dialog(self):
        """Show application options dialog - DEPRECATED: Redirects to Settings tab for backwards compatibility"""
        # Redirect to Settings tab instead of showing dialog
        self._go_to_settings_tab()
    
    def _go_to_settings_tab(self, subtab_name: str = None):
        """Navigate to Settings tab (from menu), optionally to a specific sub-tab
        
        Args:
            subtab_name: Name of the sub-tab to navigate to (e.g., "AI Settings")
        """
        if hasattr(self, 'main_tabs'):
            # Main tabs (post-v1.9.467): Grid=0, TMs=1, Termbases=2, AI=3, Settings=4
            self.main_tabs.setCurrentIndex(4)

            # Navigate to specific sub-tab if requested
            if subtab_name and hasattr(self, 'settings_tabs'):
                for i in range(self.settings_tabs.count()):
                    if subtab_name.lower() in self.settings_tabs.tabText(i).lower():
                        self.settings_tabs.setCurrentIndex(i)
                        
                        # If navigating to AI Settings, scroll to bottom (API keys section)
                        if "ai settings" in subtab_name.lower() and hasattr(self, 'ai_settings_scroll'):
                            # Use QTimer to ensure the tab is fully rendered before scrolling
                            from PyQt6.QtCore import QTimer
                            QTimer.singleShot(100, lambda: self.ai_settings_scroll.verticalScrollBar().setValue(
                                self.ai_settings_scroll.verticalScrollBar().maximum()
                            ))
                        break
    
    def _go_to_superlookup(self, query=None, source_lang=None, target_lang=None,
                           switch_to_vertical=True):
        """Open SuperLookup with an optional pre-filled query.

        Pre-v1.10.4 this routed through Sidekick (the floating
        assistant). Sidekick was retired in v1.10.4 and SuperLookup
        now lives as a Workbench top tab; v1.10.10 finished the
        rewire so this method targets the in-Workbench widget
        directly.
        """
        if hasattr(self, 'open_workbench_to_superlookup'):
            # Bring the SuperLookup tab forward without seeding text
            # via the usual hotkey path (which auto-fires the search);
            # we want to seed using search_with_query so we can pass
            # the language pair too.
            self.open_workbench_to_superlookup("")
        else:
            self.log("⚠ SuperLookup tab not available")
            return

        widget = getattr(self, '_superlookup_top_widget', None)
        if widget is not None and query and hasattr(widget, 'search_with_query'):
            widget.search_with_query(
                query,
                switch_to_vertical=switch_to_vertical,
                source_lang=source_lang,
                target_lang=target_lang,
            )
    
    def load_llm_settings(self) -> Dict[str, str]:
        """Load LLM settings from user preferences"""
        defaults = {
            'provider': 'openai',
            'openai_model': 'gpt-5.5',
            'claude_model': 'claude-sonnet-4-6',
            'gemini_model': 'gemini-3.1-flash-lite',
            'ollama_model': 'translategemma:12b',
            'custom_openai_model': '',
            'custom_openai_endpoint': '',
            'custom_openai_profiles': [],
            'custom_openai_active_profile': '',
            # Custom MT endpoint(s): a dedicated, separate set of OpenAI-compatible
            # endpoints used as MT engines (e.g. a local MT proxy), independent of
            # the AI custom endpoint above so MT and AI can point at different
            # services at the same time.
            'custom_mt_profiles': [],
            'custom_mt_active_profile': ''
        }

        try:
            prefs = self._load_settings_section("ui")
            saved = prefs.get('llm_settings', defaults)
            # Ensure new keys exist for older configs
            for k, v in defaults.items():
                saved.setdefault(k, v)
            # Auto-migrate: old single-field config → profiles
            if not saved.get('custom_openai_profiles') and saved.get('custom_openai_endpoint'):
                api_keys = self.load_api_keys() if hasattr(self, 'load_api_keys') else {}
                saved['custom_openai_profiles'] = [{
                    'name': 'Custom Endpoint',
                    'endpoint': saved['custom_openai_endpoint'],
                    'model': saved.get('custom_openai_model', ''),
                    'api_key': api_keys.get('custom_openai', '')
                }]
                saved['custom_openai_active_profile'] = 'Custom Endpoint'
            return saved
        except:
            return defaults
    
    def save_llm_settings(self, settings: Dict[str, str]):
        """Save LLM settings to user preferences"""
        try:
            all_settings = self._load_unified_settings()
            all_settings.setdefault("ui", {})['llm_settings'] = settings
            self._save_unified_settings(all_settings)
        except Exception as e:
            self.log(f"⚠ Could not save LLM settings: {str(e)}")

