    def get_language_filters(self):
        """Get the current language filter settings.
        
        Returns:
            tuple: (from_lang, to_lang) - None means 'Any'
        """
        from_lang = None
        to_lang = None
        
        if hasattr(self, 'lang_from_combo'):
            from_lang = self.lang_from_combo.currentData()
